// --- מערכת למידת ספרות (עם DB) ---

const getLearnedDigits = async (crewMemberId?: number): Promise<{ digit: string; imageData: string }[]> => {
  try {
    const url = crewMemberId ? `${API_URL}/digits?crew_member_id=${crewMemberId}` : `${API_URL}/digits`;
    const res = await fetch(url);
    if (!res.ok) return [];
    return await res.json();
  } catch {
    return [];
  }
};

const saveLearnedDigit = async (digit: string, imageData: string, crewMemberId?: number) => {
  try {
    await fetch(`${API_URL}/digits`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ digit, imageData, crew_member_id: crewMemberId })
    });
  } catch (err) {
    console.error('Failed to save digit:', err);
  }
};

const clearLearnedDigits = async (crewMemberId?: number) => {
  try {
    const url = crewMemberId ? `${API_URL}/digits?crew_member_id=${crewMemberId}` : `${API_URL}/digits`;
    await fetch(url, { method: 'DELETE' });
  } catch (err) {
    console.error('Failed to clear digits:', err);
  }
};

const getDigitsCount = async (crewMemberId?: number): Promise<number> => {
  try {
    const url = crewMemberId ? `${API_URL}/digits/count?crew_member_id=${crewMemberId}` : `${API_URL}/digits/count`;
    const res = await fetch(url);
    if (!res.ok) return 0;
    const data = await res.json();
    return data.count || 0;
  } catch {
    return 0;
  }
};

const compareImages = (img1Data: ImageData, img2Data: ImageData): number => {
  const data1 = img1Data.data;
  const data2 = img2Data.data;
  let matches = 0;
  let total = 0;
  
  for (let i = 0; i < data1.length; i += 4) {
    const isDark1 = data1[i] < 128;
    const isDark2 = data2[i] < 128;
    if (isDark1 || isDark2) {
      total++;
      if (isDark1 === isDark2) matches++;
    }
  }
  
  return total > 0 ? matches / total : 0;
};

// --- עורך אזורי מפה ---
const ZONE_COLORS = ['#3b82f6','#ef4444','#22c55e','#f59e0b','#a855f7','#06b6d4','#f97316','#ec4899'];

const MapZoneEditor = ({ mapId, mapSrc, onClose, mapData: initialMapData }: { mapId: number; mapSrc: string; onClose: () => void; mapData?: any }) => {
  const [zones, setZones] = useState<MapZone[]>([]);
  const [draftPoints, setDraftPoints] = useState<{x: number; y: number}[]>([]);
  const [draftName, setDraftName] = useState('');
  const [draftColor, setDraftColor] = useState(ZONE_COLORS[0]);
  const [editingZone, setEditingZone] = useState<MapZone | null>(null);
  const [saving, setSaving] = useState(false);
  const [altRanges, setAltRanges] = useState<ZoneAltRange[]>([]);
  const [altRangesLoading, setAltRangesLoading] = useState(false);
  const [newAltRange, setNewAltRange] = useState({ name: '', alt_min: '', alt_max: '' });
  const containerRef = useRef<HTMLDivElement>(null);
  const imgEditorRef = useRef<HTMLImageElement>(null);
  const [imgEditorBounds, setImgEditorBounds] = useState<{left:number;top:number;width:number;height:number}|null>(null);
  const [localMapData, setLocalMapData] = useState<any>(initialMapData ?? null);
  const [anchorMode, setAnchorMode] = useState(false);
  const [anchorStep, setAnchorStep] = useState<1|2>(1);
  const [pendingAnchor1, setPendingAnchor1] = useState<{x:number;y:number}|null>(null);
  const [pendingLat1, setPendingLat1] = useState('');
  const [pendingLon1, setPendingLon1] = useState('');
  const [pendingAnchor2, setPendingAnchor2] = useState<{x:number;y:number}|null>(null);
  const [pendingLat2, setPendingLat2] = useState('');
  const [pendingLon2, setPendingLon2] = useState('');
  const [savingAnchors, setSavingAnchors] = useState(false);
  const currentAnchor = getAnchorFromMapData(localMapData);
  const isCalibrated = currentAnchor !== null;

  const [dragOffset, setDragOffset] = useState<{zoneId: number; dx: number; dy: number} | null>(null);
  const dragRef = useRef<{zoneId: number; startX: number; startY: number; origPoly: {x:number;y:number}[]; moved: boolean} | null>(null);

  const [autoMode, setAutoMode] = useState(false);
  const [autoRunning, setAutoRunning] = useState(false);
  const [autoTolerance, setAutoTolerance] = useState(30);
  const [autoTargetColor, setAutoTargetColor] = useState('#3b82f6');
  const [autoResults, setAutoResults] = useState<{
    id: string; polygon: {x:number;y:number}[]; name: string;
    color: string; altRanges: {name:string;alt_min:string;alt_max:string}[];
    saving: boolean; saved: boolean;
  }[]>([]);
  const [autoSelectedId, setAutoSelectedId] = useState<string|null>(null);

  const computeEditorImgBounds = () => {
    const img = imgEditorRef.current;
    if (!img || !img.naturalWidth) { setImgEditorBounds(null); return; }
    const c = img.parentElement; if (!c) return;
    const cw = c.clientWidth, ch = c.clientHeight;
    const nw = img.naturalWidth, nh = img.naturalHeight;
    const scale = Math.min(cw / nw, ch / nh);
    const w = nw * scale, h = nh * scale;
    setImgEditorBounds({ left: (cw - w) / 2, top: (ch - h) / 2, width: w, height: h });
  };

  const getImageRelativePoint = (e: React.MouseEvent): {x:number;y:number}|null => {
    const container = containerRef.current;
    if (!container) return null;
    const rect = container.getBoundingClientRect();
    const img = imgEditorRef.current;
    if (!img || !img.naturalWidth) return null;
    const nw = img.naturalWidth, nh = img.naturalHeight;
    const cw = rect.width, ch = rect.height;
    const scale = Math.min(cw / nw, ch / nh);
    const dispW = nw * scale, dispH = nh * scale;
    const ox = (cw - dispW) / 2, oy = (ch - dispH) / 2;
    const cx = e.clientX - rect.left, cy = e.clientY - rect.top;
    if (cx < ox || cx > ox + dispW || cy < oy || cy > oy + dispH) return null;
    return { x: ((cx - ox) / dispW) * 100, y: ((cy - oy) / dispH) * 100 };
  };

  const saveAnchors = async () => {
    if (!pendingAnchor1 || !pendingAnchor2) return;
    const lat1 = parseFloat(pendingLat1), lon1 = parseFloat(pendingLon1);
    const lat2 = parseFloat(pendingLat2), lon2 = parseFloat(pendingLon2);
    if (isNaN(lat1) || isNaN(lon1) || isNaN(lat2) || isNaN(lon2)) { alert('יש להזין נ"צ תקינים'); return; }
    setSavingAnchors(true);
    try {
      const res = await fetch(`${API_URL}/maps/${mapId}/anchors`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ anchor1_x_img: pendingAnchor1.x, anchor1_y_img: pendingAnchor1.y, anchor1_lat: lat1, anchor1_lon: lon1, anchor2_x_img: pendingAnchor2.x, anchor2_y_img: pendingAnchor2.y, anchor2_lat: lat2, anchor2_lon: lon2 })
      });
      if (res.ok) {
        const updated = await res.json();
        setLocalMapData((prev: any) => ({ ...prev, ...updated }));
        setAnchorMode(false);
        setPendingAnchor1(null); setPendingAnchor2(null);
        setPendingLat1(''); setPendingLon1(''); setPendingLat2(''); setPendingLon2('');
      }
    } catch {}
    setSavingAnchors(false);
  };

  const loadAltRanges = async (zoneId: number) => {
    setAltRangesLoading(true);
    try {
      const res = await fetch(`${API_URL}/zone-altitude-ranges?zone_id=${zoneId}`);
      if (res.ok) setAltRanges(await res.json());
    } catch {} finally { setAltRangesLoading(false); }
  };

  const loadZones = async () => {
    try {
      const res = await fetch(`${API_URL}/map-zones?map_id=${mapId}`);
      if (res.ok) {
        const data = await res.json();
        setZones(data.map((z: any) => ({ ...z, polygon: typeof z.polygon === 'string' ? JSON.parse(z.polygon) : z.polygon, polygon_geo: typeof z.polygon_geo === 'string' ? JSON.parse(z.polygon_geo) : (z.polygon_geo ?? []) })));
      }
    } catch {}
  };

  useEffect(() => { loadZones(); }, [mapId]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    const ro = new ResizeObserver(() => computeEditorImgBounds());
    ro.observe(container);
    return () => ro.disconnect();
  }, []);

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key !== 'Escape') return;
      if (anchorMode) {
        setAnchorMode(false);
        setPendingAnchor1(null);
        setPendingAnchor2(null);
        setAnchorStep(1);
      }
      if (dragRef.current) {
        dragRef.current = null;
        setDragOffset(null);
      }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [anchorMode]);

  const getRelativePoint = (e: React.MouseEvent<SVGSVGElement>) => {
    const container = containerRef.current;
    if (!container) return { x: 0, y: 0 };
    const rect = container.getBoundingClientRect();
    return { x: ((e.clientX - rect.left) / rect.width) * 100, y: ((e.clientY - rect.top) / rect.height) * 100 };
  };

  const handleSvgClick = (e: React.MouseEvent<SVGSVGElement>) => {
    if (anchorMode) {
      const pt = getImageRelativePoint(e);
      if (!pt) return;
      if (anchorStep === 1) { setPendingAnchor1(pt); setAnchorStep(2); }
      else { setPendingAnchor2(pt); }
      return;
    }
    if (editingZone) return;
    const pt = isCalibrated ? getImageRelativePoint(e) : getRelativePoint(e);
    if (!pt) return;
    if (draftPoints.length >= 2) {
      const first = draftPoints[0];
      const dist = Math.hypot(pt.x - first.x, pt.y - first.y);
      if (dist < 3) { return; }
    }
    setDraftPoints(prev => [...prev, pt]);
  };

  const handleSvgDblClick = (e: React.MouseEvent<SVGSVGElement>) => {
    e.preventDefault();
    if (draftPoints.length >= 3) closeDraft();
  };

  const closeDraft = () => {
    if (draftPoints.length < 3) { alert('יש לסמן לפחות 3 נקודות'); return; }
    if (!draftName.trim()) { alert('יש להזין שם לאזור'); return; }
  };

  const computePolygonGeo = (pts: {x:number;y:number}[]): {lat:number;lon:number}[] => {
    if (!currentAnchor || pts.length === 0) return [];
    return pts.map(p => imagePctToGeo(p.x, p.y, currentAnchor));
  };

  const saveDraft = async (pts: {x:number;y:number}[]) => {
    if (pts.length < 3 || !draftName.trim()) return;
    setSaving(true);
    try {
      const polygon_geo = computePolygonGeo(pts);
      const res = await fetch(`${API_URL}/map-zones`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ map_id: mapId, name: draftName.trim(), color: draftColor, polygon: pts, polygon_geo })
      });
      if (res.ok) { await loadZones(); setDraftPoints([]); setDraftName(''); }
    } catch {}
    setSaving(false);
  };

  const saveEdit = async () => {
    if (!editingZone) return;
    setSaving(true);
    try {
      const polygon_geo = computePolygonGeo(editingZone.polygon);
      const res = await fetch(`${API_URL}/map-zones/${editingZone.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: editingZone.name, color: editingZone.color, polygon: editingZone.polygon, polygon_geo })
      });
      if (res.ok) { await loadZones(); setEditingZone(null); }
    } catch {}
    setSaving(false);
  };

  const deleteZone = async (id: number) => {
    if (!await customConfirm('למחוק אזור זה?')) return;
    try {
      await fetch(`${API_URL}/map-zones/${id}`, { method: 'DELETE' });
      await loadZones();
    } catch {}
  };

  // --- זיהוי אזורים אוטומטי ---
  const dpDist = (p:{x:number;y:number}, a:{x:number;y:number}, b:{x:number;y:number}) => {
    const dx = b.x-a.x, dy = b.y-a.y;
    if (!dx && !dy) return Math.hypot(p.x-a.x, p.y-a.y);
    const t = ((p.x-a.x)*dx+(p.y-a.y)*dy)/(dx*dx+dy*dy);
    return Math.hypot(p.x-(a.x+t*dx), p.y-(a.y+t*dy));
  };
  const douglasPeucker = (pts:{x:number;y:number}[], eps:number):{x:number;y:number}[] => {
    if (pts.length < 3) return pts;
    let maxD = 0, maxI = 0;
    for (let i = 1; i < pts.length-1; i++) { const d = dpDist(pts[i],pts[0],pts[pts.length-1]); if (d>maxD){maxD=d;maxI=i;} }
    if (maxD > eps) { const l=douglasPeucker(pts.slice(0,maxI+1),eps); const r=douglasPeucker(pts.slice(maxI),eps); return [...l.slice(0,-1),...r]; }
    return [pts[0],pts[pts.length-1]];
  };

  const detectAllZones = async () => {
    const img = imgEditorRef.current;
    if (!img || !img.naturalWidth) return;
    setAutoRunning(true);
    setAutoResults([]);
    setAutoSelectedId(null);
    try {
      const MAX_DIM = 600;
      const nw = img.naturalWidth, nh = img.naturalHeight;
      const sc = Math.min(1, MAX_DIM / Math.max(nw, nh));
      const cw = Math.round(nw * sc), ch = Math.round(nh * sc);
      const canvas = document.createElement('canvas');
      canvas.width = cw; canvas.height = ch;
      const ctx = canvas.getContext('2d')!;
      ctx.drawImage(img, 0, 0, cw, ch);
      const { data: pixels } = ctx.getImageData(0, 0, cw, ch);

      const tR = parseInt(autoTargetColor.slice(1,3), 16);
      const tG = parseInt(autoTargetColor.slice(3,5), 16);
      const tB = parseInt(autoTargetColor.slice(5,7), 16);
      const tol = autoTolerance * 3;

      // Mark all pixels within tolerance
      const marked = new Uint8Array(cw * ch);
      for (let i = 0; i < cw * ch; i++) {
        const p = i * 4;
        if (Math.abs(pixels[p]-tR) + Math.abs(pixels[p+1]-tG) + Math.abs(pixels[p+2]-tB) <= tol) marked[i] = 1;
      }

      // DFS connected components
      const componentOf = new Int32Array(cw * ch).fill(-1);
      const comps: { pixels: number[]; rS:number; gS:number; bS:number }[] = [];
      for (let start = 0; start < cw * ch; start++) {
        if (!marked[start] || componentOf[start] >= 0) continue;
        const ci = comps.length;
        const comp = { pixels: [] as number[], rS: 0, gS: 0, bS: 0 };
        const stk: number[] = [start];
        while (stk.length) {
          const pos = stk.pop()!;
          if (componentOf[pos] >= 0) continue;
          componentOf[pos] = ci;
          comp.pixels.push(pos);
          comp.rS += pixels[pos*4]; comp.gS += pixels[pos*4+1]; comp.bS += pixels[pos*4+2];
          const x = pos % cw, y = Math.floor(pos / cw);
          if (x > 0 && marked[pos-1] && componentOf[pos-1] < 0) stk.push(pos-1);
          if (x < cw-1 && marked[pos+1] && componentOf[pos+1] < 0) stk.push(pos+1);
          if (y > 0 && marked[pos-cw] && componentOf[pos-cw] < 0) stk.push(pos-cw);
          if (y < ch-1 && marked[pos+cw] && componentOf[pos+cw] < 0) stk.push(pos+cw);
        }
        comps.push(comp);
      }

      const minPx = cw * ch * 0.003;
      const large = comps.filter(c => c.pixels.length >= minPx)
        .sort((a,b) => b.pixels.length - a.pixels.length)
        .slice(0, 12);

      // Build initial results (polygons, no OCR yet)
      const initial = large.map(comp => {
        const mask = new Uint8Array(cw * ch);
        for (const pos of comp.pixels) mask[pos] = 1;
        const leftPts:{x:number;y:number}[] = [], rightPts:{x:number;y:number}[] = [];
        for (let y = 0; y < ch; y++) {
          let minX = cw, maxX = -1;
          for (let x = 0; x < cw; x++) { if (mask[y*cw+x]) { if (x < minX) minX = x; if (x > maxX) maxX = x; } }
          if (maxX >= 0) { leftPts.push({x:(minX/cw)*100, y:(y/ch)*100}); rightPts.push({x:(maxX/cw)*100, y:(y/ch)*100}); }
        }
        const polygon = leftPts.length ? douglasPeucker([...leftPts, ...rightPts.reverse()], 0.7) : [];
        const cnt = comp.pixels.length;
        const avgColor = '#' + [comp.rS/cnt, comp.gS/cnt, comp.bS/cnt].map(v => Math.round(v).toString(16).padStart(2,'0')).join('');
        return { id: Math.random().toString(36).slice(2), polygon, name: '', color: avgColor, altRanges: [] as {name:string;alt_min:string;alt_max:string}[], saving: false, saved: false };
      }).filter(r => r.polygon.length >= 3);

      setAutoResults(initial);
      if (initial.length > 0) setAutoSelectedId(initial[0].id);

      // OCR each zone sequentially, updating results progressively
      for (let i = 0; i < initial.length; i++) {
        const r = initial[i];
        try {
          const allX = r.polygon.map(p=>p.x), allY = r.polygon.map(p=>p.y);
          const bx = Math.max(0, Math.min(...allX)/100*nw - 10);
          const by = Math.max(0, Math.min(...allY)/100*nh - 10);
          const bw = Math.min(nw - bx, (Math.max(...allX) - Math.min(...allX))/100*nw + 20);
          const bh = Math.min(nh - by, (Math.max(...allY) - Math.min(...allY))/100*nh + 20);
          if (bw < 5 || bh < 5) continue;
          const cc = document.createElement('canvas');
          cc.width = Math.round(bw); cc.height = Math.round(bh);
          cc.getContext('2d')!.drawImage(img, bx, by, bw, bh, 0, 0, bw, bh);
          const { data: { text } } = await Tesseract.recognize(cc, 'heb+eng', { logger: ()=>{} });
          const altRanges: {name:string;alt_min:string;alt_max:string}[] = [];
          const flRange = /FL\s*(\d+)\s*[-–]\s*FL?\s*(\d+)/gi;
          let m: RegExpExecArray|null;
          while ((m = flRange.exec(text)) !== null) altRanges.push({name:`FL${m[1]}-FL${m[2]}`, alt_min:m[1], alt_max:m[2]});
          if (!altRanges.length) {
            const flS = /FL\s*(\d+)/gi; const ss:string[] = [];
            while ((m = flS.exec(text)) !== null) ss.push(m[1]);
            for (let j = 0; j+1 < ss.length; j+=2) altRanges.push({name:`FL${ss[j]}-FL${ss[j+1]}`, alt_min:ss[j], alt_max:ss[j+1]});
          }
          const cleaned = text.replace(/FL\s*\d+/gi,'').replace(/\d+/g,'').replace(/[^\u05D0-\u05EA ]/g,' ').trim();
          const lines = cleaned.split(/\s{2,}|\n/).map((l:string)=>l.trim()).filter((l:string)=>l.length>1);
          const name = lines[0] || '';
          setAutoResults(prev => prev.map((x,j) => j===i ? {...x, name, altRanges} : x));
        } catch(e) { console.warn('OCR fail zone', i, e); }
      }
    } catch(e) { console.error('detectAllZones error', e); }
    setAutoRunning(false);
  };

  const saveAutoResult = async (idx: number) => {
    const r = autoResults[idx];
    if (!r || r.saved || r.saving) return;
    setAutoResults(prev => prev.map((x,i) => i===idx ? {...x, saving:true} : x));
    try {
      const polygon_geo = computePolygonGeo(r.polygon);
      const res = await fetch(`${API_URL}/map-zones`, {
        method: 'POST', headers: {'Content-Type':'application/json'},
        body: JSON.stringify({ map_id: mapId, name: r.name || 'אזור חדש', color: r.color, polygon: r.polygon, polygon_geo })
      });
      if (res.ok) {
        const newZone = await res.json();
        for (const ar of r.altRanges) {
          if (!ar.name.trim()) continue;
          await fetch(`${API_URL}/zone-altitude-ranges`, {
            method: 'POST', headers: {'Content-Type':'application/json'},
            body: JSON.stringify({ zone_id: newZone.id, name: ar.name, alt_min: ar.alt_min ? Number(ar.alt_min) : null, alt_max: ar.alt_max ? Number(ar.alt_max) : null, sort_order: 0 })
          });
        }
        await loadZones();
        setAutoResults(prev => prev.map((x,i) => i===idx ? {...x, saving:false, saved:true} : x));
      } else { setAutoResults(prev => prev.map((x,i) => i===idx ? {...x, saving:false} : x)); }
    } catch(e) { setAutoResults(prev => prev.map((x,i) => i===idx ? {...x, saving:false} : x)); }
  };

  const polygonToSvgPoints = (pts: {x:number;y:number}[]) =>
    pts.map(p => `${p.x},${p.y}`).join(' ');

  const activeZone = editingZone;
  const activePoly = activeZone ? activeZone.polygon : draftPoints;

  const svgRef = useRef<SVGSVGElement>(null);

  const getSvgRelativePoint = (e: React.MouseEvent): {x:number;y:number}|null => {
    const svg = svgRef.current;
    if (!svg) return null;
    const rect = svg.getBoundingClientRect();
    return { x: ((e.clientX - rect.left) / rect.width) * 100, y: ((e.clientY - rect.top) / rect.height) * 100 };
  };

  const handleZoneMouseDown = (e: React.MouseEvent, zone: MapZone) => {
    if (anchorMode || draftPoints.length > 0) return;
    e.stopPropagation();
    e.preventDefault();
    const pt = getSvgRelativePoint(e);
    if (!pt) return;
    dragRef.current = { zoneId: zone.id, startX: pt.x, startY: pt.y, origPoly: zone.polygon.map(p => ({...p})), moved: false };
    setDragOffset({ zoneId: zone.id, dx: 0, dy: 0 });
  };

  const handleSvgMouseMove = (e: React.MouseEvent<SVGSVGElement>) => {
    if (!dragRef.current) return;
    const pt = getSvgRelativePoint(e);
    if (!pt) return;
    const dx = pt.x - dragRef.current.startX;
    const dy = pt.y - dragRef.current.startY;
    if (Math.hypot(dx, dy) > 0.3) dragRef.current.moved = true;
    setDragOffset({ zoneId: dragRef.current.zoneId, dx, dy });
  };

  const handleSvgMouseUp = async (e: React.MouseEvent<SVGSVGElement>) => {
    const drag = dragRef.current;
    if (!drag) return;
    dragRef.current = null;
    setDragOffset(null);
    if (!drag.moved) {
      const zone = zones.find(z => z.id === drag.zoneId);
      if (zone) { setEditingZone(zone); setDraftPoints([]); setAltRanges([]); loadAltRanges(zone.id); }
      return;
    }
    const pt = getSvgRelativePoint(e);
    if (!pt) return;
    const dx = pt.x - drag.startX;
    const dy = pt.y - drag.startY;
    const newPoly = drag.origPoly.map(p => ({ x: Math.max(0, Math.min(100, p.x + dx)), y: Math.max(0, Math.min(100, p.y + dy)) }));
    const zone = zones.find(z => z.id === drag.zoneId);
    if (!zone) return;
    const polygon_geo = computePolygonGeo(newPoly);
    setZones(prev => prev.map(z => z.id === drag.zoneId ? { ...z, polygon: newPoly } : z));
    try {
      await fetch(`${API_URL}/map-zones/${drag.zoneId}`, {
        method: 'PUT', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: zone.name, color: zone.color, polygon: newPoly, polygon_geo })
      });
    } catch {}
  };

  const handleSvgClickFixed = (e: React.MouseEvent<SVGSVGElement>) => {
    if (dragRef.current?.moved) return;
    if (anchorMode) {
      const pt = getSvgRelativePoint(e);
      if (!pt) return;
      if (anchorStep === 1) { setPendingAnchor1(pt); setAnchorStep(2); }
      else { setPendingAnchor2(pt); }
      return;
    }
    if (autoMode) return;
    if (editingZone) return;
    const pt = getSvgRelativePoint(e);
    if (!pt) return;
    if (draftPoints.length >= 2) {
      const first = draftPoints[0];
      const dist = Math.hypot(pt.x - first.x, pt.y - first.y);
      if (dist < 2) { return; }
    }
    setDraftPoints(prev => [...prev, pt]);
  };

  return (
    <div style={{ position: 'fixed', inset: 0, zIndex: 9999, background: 'rgba(0,0,0,0.88)', display: 'flex', alignItems: 'center', justifyContent: 'center', direction: 'rtl' }}>
      <div style={{ width: '96vw', height: '93vh', background: '#0f172a', borderRadius: '14px', display: 'flex', flexDirection: 'column', overflow: 'hidden', border: '1px solid #334155', boxShadow: '0 24px 64px rgba(0,0,0,0.7)' }}>

        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '12px 18px', borderBottom: '1px solid #1e293b', flexShrink: 0, background: '#0f172a' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <span style={{ color: '#e2e8f0', fontWeight: 'bold', fontSize: '16px' }}>🗺 עריכת אזורי מפה</span>
            <span style={{ color: isCalibrated ? '#22c55e' : '#f59e0b', fontSize: '12px', fontWeight: 'bold', background: isCalibrated ? 'rgba(34,197,94,0.1)' : 'rgba(245,158,11,0.1)', padding: '2px 8px', borderRadius: '10px' }}>
              {isCalibrated ? '✅ מכוילת' : '⚠️ לא מכוילת'}
            </span>
            {anchorMode && (
              <span style={{ color: 'white', fontSize: '12px', fontWeight: 'bold', background: anchorStep === 1 ? '#ef4444' : '#3b82f6', padding: '3px 10px', borderRadius: '10px', animation: 'elemBlink 1s infinite' }}>
                📍 {anchorStep === 1 ? 'לחץ על המפה לסימון עוגן 1' : 'לחץ על המפה לסימון עוגן 2'}
              </span>
            )}
            {autoMode && !anchorMode && (
              <span style={{ color: 'white', fontSize: '12px', fontWeight: 'bold', background: '#7c3aed', padding: '3px 10px', borderRadius: '10px', animation: autoRunning ? 'elemBlink 0.7s infinite' : 'none' }}>
                {autoRunning ? `⏳ מזהה... OCR רץ` : autoResults.length > 0 ? `🤖 נמצאו ${autoResults.length} אזורים` : '🤖 מצב זיהוי אוטומטי'}
              </span>
            )}
          </div>
          <button onClick={onClose} style={{ background: '#334155', border: 'none', color: '#94a3b8', cursor: 'pointer', fontSize: '20px', lineHeight: 1, borderRadius: '6px', width: '32px', height: '32px' }}>×</button>
        </div>

        {/* Body: map + side panel */}
        <div style={{ display: 'flex', flex: 1, overflow: 'hidden' }}>

          {/* Map area — takes most of the space, SVG positioned directly over image */}
          <div ref={containerRef} style={{ flex: 1, position: 'relative', background: '#1e293b', overflow: 'hidden' }}>
            <img
              ref={imgEditorRef}
              src={mapSrc}
              onLoad={computeEditorImgBounds}
              style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', objectFit: 'contain', pointerEvents: 'none' }}
            />
            {/* SVG always covers the exact image-rendered area for accurate coordinate mapping */}
            {imgEditorBounds ? (
              <svg
                ref={svgRef}
                viewBox="0 0 100 100"
                preserveAspectRatio="none"
                style={{
                  position: 'absolute',
                  left: imgEditorBounds.left,
                  top: imgEditorBounds.top,
                  width: imgEditorBounds.width,
                  height: imgEditorBounds.height,
                  cursor: anchorMode || autoMode ? 'crosshair' : (dragRef.current ? 'grabbing' : (editingZone ? 'default' : 'crosshair')),
                  userSelect: 'none',
                }}
                onClick={handleSvgClickFixed}
                onDoubleClick={handleSvgDblClick}
                onMouseMove={handleSvgMouseMove}
                onMouseUp={handleSvgMouseUp}
                onMouseLeave={() => { if (dragRef.current) { dragRef.current = null; setDragOffset(null); } }}
              >
                {zones.map(z => {
                  const isDragging = dragOffset?.zoneId === z.id;
                  const poly = isDragging
                    ? z.polygon.map(p => ({ x: Math.max(0, Math.min(100, p.x + dragOffset!.dx)), y: Math.max(0, Math.min(100, p.y + dragOffset!.dy)) }))
                    : z.polygon;
                  const cx = poly.reduce((s, p) => s + p.x, 0) / poly.length;
                  const cy = poly.reduce((s, p) => s + p.y, 0) / poly.length;
                  return (
                  <g key={z.id} style={{ cursor: anchorMode || draftPoints.length > 0 ? 'crosshair' : 'grab' }}>
                    <polygon points={polygonToSvgPoints(poly)} fill={z.color + (isDragging ? '55' : '33')} stroke={z.color} strokeWidth={isDragging ? "1" : "0.5"}
                      onMouseDown={(e) => handleZoneMouseDown(e, z)} />
                    {poly.length > 0 && (
                      <text x={cx} y={cy} textAnchor="middle" dominantBaseline="middle" fill={z.color} fontSize="3" fontWeight="bold"
                        style={{ pointerEvents: 'none', userSelect: 'none' }}>{z.name}</text>
                    )}
                  </g>
                  );
                })}
                {activePoly.length >= 2 && (
                  <polyline points={polygonToSvgPoints(activePoly)} fill="none" stroke={editingZone ? editingZone.color : draftColor} strokeWidth="0.5" strokeDasharray="2,1" />
                )}
                {activePoly.length >= 3 && (
                  <polygon points={polygonToSvgPoints(activePoly)} fill={(editingZone ? editingZone.color : draftColor) + '33'} stroke={editingZone ? editingZone.color : draftColor} strokeWidth="0.5" />
                )}
                {activePoly.map((p, i) => (
                  <circle key={i} cx={p.x} cy={p.y} r={i === 0 ? 1.8 : 1.2} fill={editingZone ? editingZone.color : draftColor} style={{ pointerEvents: 'none' }} />
                ))}
                {currentAnchor && (<>
                  <circle cx={currentAnchor.x1} cy={currentAnchor.y1} r="2" fill="#f59e0b" stroke="white" strokeWidth="0.5" style={{ pointerEvents: 'none' }} />
                  <text x={currentAnchor.x1 + 2.5} y={currentAnchor.y1} fill="#f59e0b" fontSize="3" fontWeight="bold" style={{ pointerEvents: 'none' }}>A1</text>
                  <circle cx={currentAnchor.x2} cy={currentAnchor.y2} r="2" fill="#f59e0b" stroke="white" strokeWidth="0.5" style={{ pointerEvents: 'none' }} />
                  <text x={currentAnchor.x2 + 2.5} y={currentAnchor.y2} fill="#f59e0b" fontSize="3" fontWeight="bold" style={{ pointerEvents: 'none' }}>A2</text>
                </>)}
                {anchorMode && pendingAnchor1 && (
                  <circle cx={pendingAnchor1.x} cy={pendingAnchor1.y} r="2.5" fill="#ef4444" stroke="white" strokeWidth="0.6" style={{ pointerEvents: 'none' }} />
                )}
                {anchorMode && pendingAnchor2 && (
                  <circle cx={pendingAnchor2.x} cy={pendingAnchor2.y} r="2.5" fill="#3b82f6" stroke="white" strokeWidth="0.6" style={{ pointerEvents: 'none' }} />
                )}
                {autoResults.map(r => (
                  <g key={r.id} style={{ pointerEvents: 'none' }}>
                    <polygon points={polygonToSvgPoints(r.polygon)}
                      fill={r.saved ? r.color + '22' : r.id === autoSelectedId ? r.color + '55' : r.color + '33'}
                      stroke={r.saved ? r.color + '88' : r.color}
                      strokeWidth={r.id === autoSelectedId ? '1.2' : '0.7'}
                      strokeDasharray={r.saved ? 'none' : '3,2'} />
                  </g>
                ))}
              </svg>
            ) : (
              <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#475569', fontSize: '13px' }}>טוען מפה...</div>
            )}
          </div>

          {/* Controls panel — right side */}
          <div style={{ width: '320px', overflowY: 'auto', background: '#0f172a', borderRight: '1px solid #1e293b', display: 'flex', flexDirection: 'column', gap: '0' }}>

            {/* Anchor / Calibration */}
            <div style={{ padding: '14px', borderBottom: '1px solid #1e293b' }}>
              <div style={{ color: '#7dd3fc', fontSize: '12px', fontWeight: 'bold', marginBottom: '8px' }}>📐 כיול גיאוגרפי</div>
              {!anchorMode ? (
                <button onClick={() => { setAnchorMode(true); setAnchorStep(1); setPendingAnchor1(null); setPendingAnchor2(null); setPendingLat1(localMapData?.anchor1_lat ? String(localMapData.anchor1_lat) : ''); setPendingLon1(localMapData?.anchor1_lon ? String(localMapData.anchor1_lon) : ''); setPendingLat2(localMapData?.anchor2_lat ? String(localMapData.anchor2_lat) : ''); setPendingLon2(localMapData?.anchor2_lon ? String(localMapData.anchor2_lon) : ''); }}
                  style={{ background: '#1d4ed8', color: 'white', border: 'none', borderRadius: '6px', padding: '7px 14px', cursor: 'pointer', fontSize: '12px', width: '100%' }}>
                  {isCalibrated ? '🔧 עדכן עיגון' : '📐 הגדר עיגון גיאו'}
                </button>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                  <div style={{ color: '#94a3b8', fontSize: '11px' }}>עוגן {anchorStep === 1 ? '1 (A1) — לחץ על המפה' : '2 (A2) — לחץ על המפה'}:</div>
                  <div style={{ display: 'flex', gap: '6px' }}>
                    <input value={anchorStep === 1 ? pendingLat1 : pendingLat2} onChange={e => anchorStep === 1 ? setPendingLat1(e.target.value) : setPendingLat2(e.target.value)}
                      placeholder="קו רוחב" style={{ flex: 1, padding: '5px 8px', borderRadius: '4px', border: '1px solid #475569', background: '#1e293b', color: 'white', fontSize: '12px' }} />
                    <input value={anchorStep === 1 ? pendingLon1 : pendingLon2} onChange={e => anchorStep === 1 ? setPendingLon1(e.target.value) : setPendingLon2(e.target.value)}
                      placeholder="קו אורך" style={{ flex: 1, padding: '5px 8px', borderRadius: '4px', border: '1px solid #475569', background: '#1e293b', color: 'white', fontSize: '12px' }} />
                  </div>
                  <div style={{ display: 'flex', gap: '6px' }}>
                    {anchorStep === 1 && pendingAnchor1 && (
                      <button onClick={() => setAnchorStep(2)} style={{ flex: 1, background: '#059669', color: 'white', border: 'none', borderRadius: '4px', padding: '5px', cursor: 'pointer', fontSize: '12px' }}>הבא ▶</button>
                    )}
                    {anchorStep === 2 && pendingAnchor1 && pendingAnchor2 && (
                      <button onClick={saveAnchors} disabled={savingAnchors} style={{ flex: 1, background: '#059669', color: 'white', border: 'none', borderRadius: '4px', padding: '5px', cursor: 'pointer', fontSize: '12px' }}>
                        {savingAnchors ? '...' : '💾 שמור עיגון'}
                      </button>
                    )}
                    <button onClick={() => { setAnchorMode(false); setPendingAnchor1(null); setPendingAnchor2(null); setAnchorStep(1); }}
                      style={{ background: '#475569', color: 'white', border: 'none', borderRadius: '4px', padding: '5px 10px', cursor: 'pointer', fontSize: '12px' }}>ביטול</button>
                  </div>
                </div>
              )}
            </div>

            {/* Editing existing zone */}
            {editingZone && (
              <div style={{ padding: '14px', borderBottom: '1px solid #1e293b' }}>
                <div style={{ color: '#94a3b8', fontSize: '11px', marginBottom: '8px' }}>עריכת אזור:</div>
                <input value={editingZone.name} onChange={e => setEditingZone(z => z ? { ...z, name: e.target.value } : z)} placeholder="שם אזור"
                  style={{ width: '100%', padding: '7px 10px', borderRadius: '4px', border: '1px solid #475569', background: '#1e293b', color: 'white', fontSize: '13px', boxSizing: 'border-box', marginBottom: '8px' }} />
                <div style={{ display: 'flex', gap: '4px', marginBottom: '10px' }}>
                  {ZONE_COLORS.map(c => (
                    <div key={c} onClick={() => setEditingZone(z => z ? { ...z, color: c } : z)}
                      style={{ width: '22px', height: '22px', borderRadius: '50%', background: c, cursor: 'pointer', border: editingZone.color === c ? '3px solid white' : '2px solid transparent' }} />
                  ))}
                </div>
                <div style={{ display: 'flex', gap: '6px', marginBottom: '12px' }}>
                  <button onClick={saveEdit} disabled={saving} style={{ flex: 1, background: '#059669', color: 'white', border: 'none', borderRadius: '4px', padding: '7px', cursor: 'pointer', fontSize: '12px' }}>
                    {saving ? '...' : '💾 שמור'}
                  </button>
                  <button onClick={() => { deleteZone(editingZone.id); setEditingZone(null); }} style={{ background: '#ef4444', color: 'white', border: 'none', borderRadius: '4px', padding: '7px 10px', cursor: 'pointer', fontSize: '12px' }}>🗑</button>
                  <button onClick={() => setEditingZone(null)} style={{ background: '#334155', color: 'white', border: 'none', borderRadius: '4px', padding: '7px 10px', cursor: 'pointer', fontSize: '12px' }}>✕</button>
                </div>
                <div style={{ borderTop: '1px solid #1e293b', paddingTop: '10px' }}>
                  <div style={{ color: '#7dd3fc', fontSize: '11px', fontWeight: 'bold', marginBottom: '8px' }}>📐 טווחי גובה:</div>
                  {altRangesLoading ? (
                    <div style={{ color: '#64748b', fontSize: '11px' }}>טוען...</div>
                  ) : (
                    <>
                      {altRanges.map(ar => (
                        <div key={ar.id} style={{ display: 'flex', gap: '4px', alignItems: 'center', marginBottom: '5px' }}>
                          <input value={ar.name} onChange={e => setAltRanges(prev => prev.map(x => x.id === ar.id ? { ...x, name: e.target.value } : x))}
                            onBlur={async () => { await fetch(`${API_URL}/zone-altitude-ranges/${ar.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name: ar.name, alt_min: ar.alt_min, alt_max: ar.alt_max, sort_order: ar.sort_order }) }); }}
                            placeholder="שם" style={{ flex: 2, padding: '3px 5px', border: '1px solid #334155', borderRadius: '3px', background: '#1e293b', color: 'white', fontSize: '11px' }} />
                          <input type="number" value={ar.alt_min ?? ''} onChange={e => setAltRanges(prev => prev.map(x => x.id === ar.id ? { ...x, alt_min: e.target.value ? Number(e.target.value) : null } : x))}
                            onBlur={async () => { await fetch(`${API_URL}/zone-altitude-ranges/${ar.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name: ar.name, alt_min: ar.alt_min, alt_max: ar.alt_max, sort_order: ar.sort_order }) }); }}
                            placeholder="מינ'" style={{ width: '50px', padding: '3px 5px', border: '1px solid #334155', borderRadius: '3px', background: '#1e293b', color: 'white', fontSize: '11px' }} />
                          <span style={{ color: '#64748b', fontSize: '10px' }}>—</span>
                          <input type="number" value={ar.alt_max ?? ''} onChange={e => setAltRanges(prev => prev.map(x => x.id === ar.id ? { ...x, alt_max: e.target.value ? Number(e.target.value) : null } : x))}
                            onBlur={async () => { await fetch(`${API_URL}/zone-altitude-ranges/${ar.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name: ar.name, alt_min: ar.alt_min, alt_max: ar.alt_max, sort_order: ar.sort_order }) }); }}
                            placeholder="מקס'" style={{ width: '50px', padding: '3px 5px', border: '1px solid #334155', borderRadius: '3px', background: '#1e293b', color: 'white', fontSize: '11px' }} />
                          <button onClick={async () => { await fetch(`${API_URL}/zone-altitude-ranges/${ar.id}`, { method: 'DELETE' }); setAltRanges(prev => prev.filter(x => x.id !== ar.id)); }}
                            style={{ background: 'transparent', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: '13px', padding: '0 2px' }}>✕</button>
                        </div>
                      ))}
                      <div style={{ display: 'flex', gap: '4px', alignItems: 'center', marginTop: '6px' }}>
                        <input value={newAltRange.name} onChange={e => setNewAltRange(p => ({ ...p, name: e.target.value }))} placeholder="שם חדש"
                          style={{ flex: 2, padding: '3px 5px', border: '1px dashed #475569', borderRadius: '3px', background: '#0f172a', color: 'white', fontSize: '11px' }} />
                        <input type="number" value={newAltRange.alt_min} onChange={e => setNewAltRange(p => ({ ...p, alt_min: e.target.value }))} placeholder="מינ'"
                          style={{ width: '50px', padding: '3px 5px', border: '1px dashed #475569', borderRadius: '3px', background: '#0f172a', color: 'white', fontSize: '11px' }} />
                        <span style={{ color: '#64748b', fontSize: '10px' }}>—</span>
                        <input type="number" value={newAltRange.alt_max} onChange={e => setNewAltRange(p => ({ ...p, alt_max: e.target.value }))} placeholder="מקס'"
                          style={{ width: '50px', padding: '3px 5px', border: '1px dashed #475569', borderRadius: '3px', background: '#0f172a', color: 'white', fontSize: '11px' }} />
                        <button onClick={async () => {
                          if (!newAltRange.name.trim()) return;
                          const res = await fetch(`${API_URL}/zone-altitude-ranges`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ zone_id: editingZone.id, name: newAltRange.name.trim(), alt_min: newAltRange.alt_min ? Number(newAltRange.alt_min) : null, alt_max: newAltRange.alt_max ? Number(newAltRange.alt_max) : null, sort_order: altRanges.length }) });
                          if (res.ok) { const row = await res.json(); setAltRanges(prev => [...prev, row]); setNewAltRange({ name: '', alt_min: '', alt_max: '' }); }
                        }} style={{ background: '#0ea5e9', color: 'white', border: 'none', borderRadius: '4px', padding: '3px 8px', cursor: 'pointer', fontSize: '11px', whiteSpace: 'nowrap' }}>+</button>
                      </div>
                    </>
                  )}
                </div>
              </div>
            )}

            {/* Add new zone */}
            {!editingZone && (
              <div style={{ padding: '14px', borderBottom: '1px solid #1e293b' }}>
                <div style={{ color: '#7dd3fc', fontSize: '12px', fontWeight: 'bold', marginBottom: '8px' }}>➕ אזור חדש</div>
                <div style={{ color: '#64748b', fontSize: '11px', marginBottom: '8px', lineHeight: 1.4 }}>
                  {draftPoints.length === 0 ? 'לחץ על המפה להוסיף נקודות' : `${draftPoints.length} נקודות — לחץ ליד נקודה ראשונה לסגירה`}
                </div>
                <input value={draftName} onChange={e => setDraftName(e.target.value)} placeholder="שם האזור"
                  style={{ width: '100%', padding: '7px 10px', borderRadius: '4px', border: '1px solid #475569', background: '#1e293b', color: 'white', fontSize: '13px', boxSizing: 'border-box', marginBottom: '8px' }} />
                <div style={{ display: 'flex', gap: '4px', marginBottom: '10px' }}>
                  {ZONE_COLORS.map(c => (
                    <div key={c} onClick={() => setDraftColor(c)}
                      style={{ width: '22px', height: '22px', borderRadius: '50%', background: c, cursor: 'pointer', border: draftColor === c ? '3px solid white' : '2px solid transparent' }} />
                  ))}
                </div>
                <div style={{ display: 'flex', gap: '6px' }}>
                  {draftPoints.length >= 3 && (
                    <button onClick={() => { if (!draftName.trim()) { alert('יש להזין שם לאזור'); return; } saveDraft(draftPoints); }}
                      disabled={saving} style={{ flex: 1, background: '#059669', color: 'white', border: 'none', borderRadius: '4px', padding: '7px', cursor: 'pointer', fontSize: '12px' }}>
                      {saving ? '...' : '💾 שמור אזור'}
                    </button>
                  )}
                  {draftPoints.length > 0 && (
                    <button onClick={() => setDraftPoints([])} style={{ background: '#475569', color: 'white', border: 'none', borderRadius: '4px', padding: '7px 10px', cursor: 'pointer', fontSize: '12px' }}>נקה</button>
                  )}
                </div>
              </div>
            )}

            {/* Auto detect zone */}
            <div style={{ padding: '14px', borderBottom: '1px solid #1e293b' }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '8px' }}>
                <div style={{ color: '#a78bfa', fontSize: '12px', fontWeight: 'bold' }}>🤖 זיהוי אוטומטי</div>
                <button
                  onClick={() => { setAutoMode(m => !m); setAutoResults([]); setAutoSelectedId(null); setEditingZone(null); setDraftPoints([]); }}
                  style={{ background: autoMode ? '#7c3aed' : '#334155', color: 'white', border: 'none', borderRadius: '6px', padding: '4px 12px', cursor: 'pointer', fontSize: '11px', fontWeight: autoMode ? 'bold' : 'normal' }}>
                  {autoMode ? '✓ פעיל' : 'הפעל'}
                </button>
              </div>
              {autoMode && (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>

                  {/* Color picker */}
                  <div>
                    <div style={{ color: '#64748b', fontSize: '10px', marginBottom: '5px' }}>בחר צבע האזור לזיהוי:</div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                      <input type="color" value={autoTargetColor} onChange={e => setAutoTargetColor(e.target.value)}
                        style={{ width: '36px', height: '32px', border: 'none', background: 'none', cursor: 'pointer', padding: 0 }} />
                      <div style={{ width: '20px', height: '20px', borderRadius: '4px', background: autoTargetColor, border: '1px solid #475569', flexShrink: 0 }} />
                      <input value={autoTargetColor} onChange={e => { if (/^#[0-9a-fA-F]{0,6}$/.test(e.target.value)) setAutoTargetColor(e.target.value); }}
                        style={{ flex: 1, padding: '4px 7px', borderRadius: '5px', border: '1px solid #334155', background: '#0f172a', color: 'white', fontSize: '12px', fontFamily: 'monospace' }} />
                    </div>
                  </div>

                  {/* Tolerance slider */}
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <span style={{ color: '#94a3b8', fontSize: '11px', flexShrink: 0 }}>סובלנות:</span>
                    <input type="range" min="5" max="80" value={autoTolerance} onChange={e => setAutoTolerance(Number(e.target.value))}
                      style={{ flex: 1, accentColor: '#7c3aed' }} />
                    <span style={{ color: '#e2e8f0', fontSize: '11px', width: '24px', textAlign: 'left' }}>{autoTolerance}</span>
                  </div>

                  {/* Detect button */}
                  <button onClick={detectAllZones} disabled={autoRunning}
                    style={{ background: autoRunning ? '#4c1d95' : '#7c3aed', color: 'white', border: 'none', borderRadius: '7px', padding: '9px', cursor: autoRunning ? 'default' : 'pointer', fontSize: '13px', fontWeight: 'bold', animation: autoRunning ? 'elemBlink 0.8s infinite' : 'none' }}>
                    {autoRunning ? '⏳ מזהה אזורים + OCR...' : '🔍 זהה אזורים'}
                  </button>

                  {/* Results list */}
                  {autoResults.length > 0 && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                      <div style={{ color: '#64748b', fontSize: '10px' }}>נמצאו {autoResults.length} אזורים — לחץ לבחירה ועריכה:</div>
                      {autoResults.map((r, idx) => (
                        <div key={r.id}
                          onClick={() => setAutoSelectedId(id => id === r.id ? null : r.id)}
                          style={{ background: r.id === autoSelectedId ? '#1e1b4b' : '#1e293b', borderRadius: '8px', border: `1px solid ${r.id === autoSelectedId ? r.color : r.color + '55'}`, padding: '8px', cursor: 'pointer', opacity: r.saved ? 0.5 : 1 }}>
                          {/* Row header */}
                          <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                            <div style={{ width: '12px', height: '12px', borderRadius: '3px', background: r.color, flexShrink: 0 }} />
                            <span style={{ color: r.saved ? '#64748b' : '#e2e8f0', fontSize: '12px', flex: 1 }}>
                              {r.name || <span style={{ color: '#475569', fontStyle: 'italic' }}>ללא שם</span>}
                            </span>
                            {r.saved && <span style={{ color: '#22c55e', fontSize: '11px' }}>✓ נשמר</span>}
                            {!r.saved && <span style={{ color: '#64748b', fontSize: '10px' }}>{r.polygon.length} נק'</span>}
                          </div>
                          {/* Expanded editor */}
                          {r.id === autoSelectedId && !r.saved && (
                            <div style={{ marginTop: '8px', display: 'flex', flexDirection: 'column', gap: '6px' }} onClick={e => e.stopPropagation()}>
                              {/* Color */}
                              <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                                <input type="color" value={r.color} onChange={e => setAutoResults(prev => prev.map((x,i) => i===idx ? {...x, color: e.target.value} : x))}
                                  style={{ width: '26px', height: '22px', border: 'none', background: 'none', cursor: 'pointer', padding: 0 }} />
                                <input value={r.color} onChange={e => setAutoResults(prev => prev.map((x,i) => i===idx ? {...x, color: e.target.value} : x))}
                                  style={{ flex: 1, padding: '3px 6px', borderRadius: '4px', border: '1px solid #334155', background: '#0f172a', color: 'white', fontSize: '11px', fontFamily: 'monospace' }} />
                              </div>
                              {/* Name */}
                              <input value={r.name} onChange={e => setAutoResults(prev => prev.map((x,i) => i===idx ? {...x, name: e.target.value} : x))}
                                placeholder="שם האזור"
                                style={{ width: '100%', padding: '5px 8px', borderRadius: '5px', border: '1px solid #334155', background: '#0f172a', color: 'white', fontSize: '12px', boxSizing: 'border-box' }} />
                              {/* Alt ranges */}
                              {r.altRanges.length > 0 && (
                                <div style={{ color: '#64748b', fontSize: '10px', marginBottom: '2px' }}>גבהים:</div>
                              )}
                              {r.altRanges.map((ar, ai) => (
                                <div key={ai} style={{ display: 'flex', gap: '3px', alignItems: 'center' }}>
                                  <input value={ar.name} onChange={e => setAutoResults(prev => prev.map((x,i) => i===idx ? {...x, altRanges: x.altRanges.map((a,j) => j===ai ? {...a, name: e.target.value} : a)} : x))}
                                    placeholder="שם" style={{ flex: 2, padding: '2px 4px', borderRadius: '3px', border: '1px solid #334155', background: '#0f172a', color: 'white', fontSize: '10px' }} />
                                  <input type="number" value={ar.alt_min} onChange={e => setAutoResults(prev => prev.map((x,i) => i===idx ? {...x, altRanges: x.altRanges.map((a,j) => j===ai ? {...a, alt_min: e.target.value} : a)} : x))}
                                    placeholder="מינ'" style={{ width: '42px', padding: '2px 3px', borderRadius: '3px', border: '1px solid #334155', background: '#0f172a', color: 'white', fontSize: '10px' }} />
                                  <span style={{ color: '#475569', fontSize: '9px' }}>—</span>
                                  <input type="number" value={ar.alt_max} onChange={e => setAutoResults(prev => prev.map((x,i) => i===idx ? {...x, altRanges: x.altRanges.map((a,j) => j===ai ? {...a, alt_max: e.target.value} : a)} : x))}
                                    placeholder="מקס'" style={{ width: '42px', padding: '2px 3px', borderRadius: '3px', border: '1px solid #334155', background: '#0f172a', color: 'white', fontSize: '10px' }} />
                                  <button onClick={() => setAutoResults(prev => prev.map((x,i) => i===idx ? {...x, altRanges: x.altRanges.filter((_,j) => j!==ai)} : x))}
                                    style={{ background: 'transparent', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: '11px', padding: '0 2px' }}>✕</button>
                                </div>
                              ))}
                              <button onClick={() => setAutoResults(prev => prev.map((x,i) => i===idx ? {...x, altRanges: [...x.altRanges, {name:'',alt_min:'',alt_max:''}]} : x))}
                                style={{ background: '#1e3a5f', color: '#7dd3fc', border: 'none', borderRadius: '4px', padding: '2px 8px', cursor: 'pointer', fontSize: '10px' }}>+ גובה</button>
                              {/* Actions */}
                              <div style={{ display: 'flex', gap: '5px', marginTop: '2px' }}>
                                <button onClick={() => saveAutoResult(idx)} disabled={r.saving}
                                  style={{ flex: 1, background: '#059669', color: 'white', border: 'none', borderRadius: '5px', padding: '6px', cursor: 'pointer', fontSize: '11px', fontWeight: 'bold' }}>
                                  {r.saving ? '...' : '💾 שמור'}
                                </button>
                                <button onClick={() => setAutoResults(prev => prev.filter((_,i) => i!==idx))}
                                  style={{ background: '#7f1d1d', color: '#fca5a5', border: 'none', borderRadius: '5px', padding: '6px 10px', cursor: 'pointer', fontSize: '11px' }}>🗑</button>
                              </div>
                            </div>
                          )}
                        </div>
                      ))}
                      {autoResults.some(r => !r.saved) && (
                        <button onClick={async () => { for (let i=0; i<autoResults.length; i++) { if (!autoResults[i].saved) await saveAutoResult(i); } }}
                          style={{ background: '#064e3b', color: '#6ee7b7', border: '1px solid #059669', borderRadius: '6px', padding: '7px', cursor: 'pointer', fontSize: '12px', fontWeight: 'bold' }}>
                          💾 שמור הכל ({autoResults.filter(r => !r.saved).length})
                        </button>
                      )}
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* Existing zones list */}
            <div style={{ padding: '14px', flex: 1 }}>
              <div style={{ color: '#64748b', fontSize: '11px', marginBottom: '8px' }}>אזורים שמורים ({zones.length})</div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '5px' }}>
                {zones.map(z => (
                  <div key={z.id} style={{ display: 'flex', alignItems: 'center', gap: '6px', background: editingZone?.id === z.id ? '#1e40af22' : '#1e293b', borderRadius: '6px', padding: '6px 8px', border: `1px solid ${editingZone?.id === z.id ? z.color : z.color + '44'}` }}>
                    <div style={{ width: '12px', height: '12px', borderRadius: '3px', background: z.color, flexShrink: 0 }} />
                    <span style={{ color: '#e2e8f0', fontSize: '12px', flex: 1, cursor: 'default' }}>{z.name}</span>
                    <span style={{ color: '#475569', fontSize: '10px', flexShrink: 0 }}>{z.polygon.length} נק'</span>
                    <button
                      title="עריכה"
                      onClick={() => { setEditingZone(z); setDraftPoints([]); setAltRanges([]); loadAltRanges(z.id); }}
                      style={{ background: editingZone?.id === z.id ? '#1d4ed8' : '#334155', border: 'none', color: '#94a3b8', cursor: 'pointer', borderRadius: '4px', padding: '3px 6px', fontSize: '11px', flexShrink: 0 }}>
                      ✏️
                    </button>
                    <button
                      title="מחיקה"
                      onClick={(e) => { e.stopPropagation(); deleteZone(z.id); if (editingZone?.id === z.id) setEditingZone(null); }}
                      style={{ background: 'transparent', border: 'none', color: '#ef4444', cursor: 'pointer', borderRadius: '4px', padding: '3px 5px', fontSize: '13px', flexShrink: 0 }}>
                      🗑
                    </button>
                  </div>
                ))}
                {zones.length === 0 && <div style={{ color: '#334155', fontSize: '12px', textAlign: 'center', padding: '20px 0' }}>אין אזורים עדיין</div>}
              </div>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
};

// --- ניהול מפות ---
const MapsManager = ({ onClose, onMapsUpdated, isEmbedded = false }: { onClose: () => void; onMapsUpdated: () => void; isEmbedded?: boolean }) => {
  const [maps, setMaps] = useState<{id: number; name: string; created_at: string}[]>([]);
  const [newMapName, setNewMapName] = useState('');
  const [newMapData, setNewMapData] = useState<string | null>(null);
  const [uploading, setUploading] = useState(false);
  const [zoneEditorMapId, setZoneEditorMapId] = useState<number | null>(null);
  const [zoneEditorMapSrc, setZoneEditorMapSrc] = useState<string | null>(null);
  const [zoneEditorMapData, setZoneEditorMapData] = useState<any>(null);

  const loadMaps = async () => {
    try {
      const res = await fetch(`${API_URL}/maps`);
      if (res.ok) setMaps(await res.json());
    } catch (err) {
      console.error('Failed to load maps:', err);
    }
  };

  useEffect(() => {
    loadMaps();
  }, []);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => setNewMapData(ev.target?.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleUpload = async () => {
    if (!newMapName.trim() || !newMapData) return;
    setUploading(true);
    try {
      const res = await fetch(`${API_URL}/maps`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: newMapName.trim(), image_data: newMapData })
      });
      if (res.ok) {
        setNewMapName('');
        setNewMapData(null);
        loadMaps();
        onMapsUpdated();
      }
    } catch (err) {
      console.error('Failed to upload map:', err);
    }
    setUploading(false);
  };

  const handleDelete = async (id: number) => {
    if (!await customConfirm('למחוק את המפה?')) return;
    try {
      await fetch(`${API_URL}/maps/${id}`, { method: 'DELETE' });
      loadMaps();
      onMapsUpdated();
    } catch (err) {
      console.error('Failed to delete map:', err);
    }
  };

  const content = (
    <div style={{ background: isEmbedded ? '#1e293b' : 'white', borderRadius: '12px', padding: '24px', width: isEmbedded ? '100%' : '600px', maxHeight: isEmbedded ? 'none' : '80vh', overflowY: 'auto', direction: 'rtl' }}>
      {!isEmbedded && (
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <h2 style={{ margin: 0, fontSize: '20px', color: '#1e293b' }}>ניהול מפות</h2>
          <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: '24px', cursor: 'pointer', color: '#64748b' }}>&times;</button>
        </div>
      )}
      
      {isEmbedded && <h2 style={{ margin: '0 0 20px 0', fontSize: '18px', color: 'white' }}>ניהול מפות</h2>}

      <div style={{ background: isEmbedded ? '#334155' : '#f1f5f9', padding: '16px', borderRadius: '8px', marginBottom: '20px' }}>
        <h3 style={{ margin: '0 0 12px 0', fontSize: '14px', color: isEmbedded ? '#94a3b8' : '#475569' }}>העלאת מפה חדשה</h3>
        <div style={{ display: 'flex', gap: '10px', alignItems: 'center', flexWrap: 'wrap' }}>
          <input
            type="text"
            value={newMapName}
            onChange={(e) => setNewMapName(e.target.value)}
            placeholder="שם המפה"
            style={{ flex: 1, minWidth: '150px', padding: '8px 12px', border: '1px solid #cbd5e1', borderRadius: '6px', fontSize: '14px', background: 'white' }}
          />
          <label style={{ background: '#475569', color: 'white', padding: '8px 16px', borderRadius: '6px', cursor: 'pointer', fontSize: '14px' }}>
            {newMapData ? 'קובץ נבחר ✓' : 'בחר קובץ JPG'}
            <input type="file" accept="image/*" onChange={handleFileSelect} style={{ display: 'none' }} />
          </label>
          <button
            onClick={handleUpload}
            disabled={!newMapName.trim() || !newMapData || uploading}
            style={{
              background: newMapName.trim() && newMapData ? '#059669' : '#94a3b8',
              color: 'white',
              padding: '8px 20px',
              border: 'none',
              borderRadius: '6px',
              cursor: newMapName.trim() && newMapData ? 'pointer' : 'not-allowed',
              fontSize: '14px'
            }}
          >
            {uploading ? 'מעלה...' : 'העלה'}
          </button>
        </div>
        {newMapData && (
          <div style={{ marginTop: '12px' }}>
            <img src={newMapData} style={{ maxWidth: '200px', maxHeight: '100px', objectFit: 'contain', border: '1px solid #cbd5e1', borderRadius: '4px' }} />
          </div>
        )}
      </div>

      <h3 style={{ margin: '0 0 12px 0', fontSize: '14px', color: isEmbedded ? '#94a3b8' : '#475569' }}>מפות קיימות ({maps.length})</h3>
      {maps.length === 0 ? (
        <div style={{ padding: '20px', textAlign: 'center', color: '#94a3b8' }}>אין מפות עדיין</div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
          {maps.map(map => (
            <div key={map.id}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '12px', background: isEmbedded ? '#475569' : '#f8fafc', border: zoneEditorMapId === map.id ? '1px solid #3b82f6' : '1px solid #e2e8f0', borderRadius: zoneEditorMapId === map.id ? '8px 8px 0 0' : '8px' }}>
                <div>
                  <div style={{ fontWeight: 'bold', color: isEmbedded ? 'white' : '#1e293b' }}>{map.name}</div>
                  <div style={{ fontSize: '12px', color: '#94a3b8' }}>{new Date(map.created_at).toLocaleDateString('he-IL')}</div>
                </div>
                <div style={{ display: 'flex', gap: '8px' }}>
                  <button
                    onClick={async () => {
                      if (zoneEditorMapId === map.id) { setZoneEditorMapId(null); setZoneEditorMapSrc(null); setZoneEditorMapData(null); return; }
                      try {
                        const res = await fetch(`${API_URL}/maps/${map.id}`);
                        if (res.ok) { const data = await res.json(); setZoneEditorMapSrc(data.image_data); setZoneEditorMapId(map.id); setZoneEditorMapData(map); }
                      } catch {}
                    }}
                    style={{ background: zoneEditorMapId === map.id ? '#3b82f6' : (isEmbedded ? '#334155' : '#e2e8f0'), color: zoneEditorMapId === map.id ? 'white' : (isEmbedded ? 'white' : '#1e293b'), padding: '6px 12px', border: 'none', borderRadius: '4px', cursor: 'pointer', fontSize: '12px' }}
                  >
                    🗺 אזורים
                  </button>
                  <button
                    onClick={() => handleDelete(map.id)}
                    style={{ background: '#ef4444', color: 'white', padding: '6px 12px', border: 'none', borderRadius: '4px', cursor: 'pointer', fontSize: '12px' }}
                  >
                    מחק
                  </button>
                </div>
              </div>
              {zoneEditorMapId === map.id && zoneEditorMapSrc && (
                <MapZoneEditor mapId={map.id} mapSrc={zoneEditorMapSrc} onClose={() => { setZoneEditorMapId(null); setZoneEditorMapSrc(null); setZoneEditorMapData(null); }} mapData={zoneEditorMapData ?? map} />
              )}
            </div>
          ))}
        </div>
      )}

      {!isEmbedded && (
        <div style={{ marginTop: '20px', textAlign: 'center' }}>
          <button onClick={onClose} style={{ background: '#1e293b', color: 'white', padding: '10px 30px', border: 'none', borderRadius: '6px', cursor: 'pointer', fontSize: '14px' }}>
            סגור
          </button>
        </div>
      )}
    </div>
  );

  if (isEmbedded) {
    return content;
  }

  return ReactDOM.createPortal(
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      {content}
    </div>,
    document.body
  );
};

// --- רכיב לימוד ספרות ---
const LearnDigitsOverlay = ({ onClose, crewMemberId, crewMemberName }: { onClose: () => void; crewMemberId?: number; crewMemberName?: string }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [currentDigit, setCurrentDigit] = useState(0);
  const [saved, setSaved] = useState(0);
  const [totalCount, setTotalCount] = useState(0);

  const loadCount = async () => {
    const count = await getDigitsCount(crewMemberId);
    setTotalCount(count);
  };

  useEffect(() => {
    loadCount();
  }, [saved, crewMemberId]);

  const getCoords = (e: any) => {
    const rect = canvasRef.current!.getBoundingClientRect();
    if (e.touches && e.touches[0]) {
      return { x: e.touches[0].clientX - rect.left, y: e.touches[0].clientY - rect.top };
    }
    return { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  const startDrawing = (e: any) => {
    e.preventDefault();
    setIsDrawing(true);
    const { x, y } = getCoords(e);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineWidth = 8;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.strokeStyle = '#000';
    }
  };

  const draw = (e: any) => {
    if (!isDrawing) return;
    e.preventDefault();
    const { x, y } = getCoords(e);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx) { 
      ctx.lineTo(x, y); 
      ctx.stroke(); 
    }
  };

  const clearCanvas = () => {
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx && canvasRef.current) {
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
  };

  const saveDigit = async () => {
    if (!canvasRef.current) return;
    const imageData = canvasRef.current.toDataURL('image/png');
    await saveLearnedDigit(currentDigit.toString(), imageData, crewMemberId);
    setSaved(s => s + 1);
    clearCanvas();
  };

  const nextDigit = () => {
    setCurrentDigit((currentDigit + 1) % 10);
    clearCanvas();
  };

  const handleClearAll = async () => {
    await clearLearnedDigits(crewMemberId);
    setSaved(0);
    setTotalCount(0);
  };

  useEffect(() => {
    clearCanvas();
  }, []);

  return createPortal(
    <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999 }}>
      <div style={{ background: 'white', padding: '20px', borderRadius: '12px', direction: 'rtl', minWidth: '300px' }}>
        <h3 style={{ margin: '0 0 15px', color: '#1e293b', textAlign: 'center' }}>לימוד כתב יד {crewMemberName ? `- ${crewMemberName}` : ''}</h3>
        
        <div style={{ textAlign: 'center', marginBottom: '10px' }}>
          <span style={{ fontSize: '14px', color: '#64748b' }}>כתוב את הספרה: </span>
          <span style={{ fontSize: '48px', fontWeight: 'bold', color: '#2563eb' }}>{currentDigit}</span>
        </div>
        
        <canvas 
          ref={canvasRef} 
          width={150} 
          height={150} 
          style={{ background: '#ffffff', border: '2px solid #cbd5e1', borderRadius: '8px', touchAction: 'none', display: 'block', margin: '0 auto' }}
          onMouseDown={startDrawing} 
          onMouseMove={draw} 
          onMouseUp={() => setIsDrawing(false)}
          onMouseLeave={() => setIsDrawing(false)}
          onTouchStart={startDrawing} 
          onTouchMove={draw} 
          onTouchEnd={() => setIsDrawing(false)} 
        />
        
        <div style={{ display: 'flex', gap: '8px', marginTop: '15px' }}>
          <button onClick={clearCanvas} style={{ flex: 1, padding: '8px', background: '#f1f5f9', border: '1px solid #cbd5e1', borderRadius: '6px', cursor: 'pointer' }}>נקה</button>
          <button onClick={saveDigit} style={{ flex: 1, padding: '8px', background: '#10b981', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold' }}>שמור</button>
          <button onClick={nextDigit} style={{ flex: 1, padding: '8px', background: '#3b82f6', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>הבא</button>
        </div>
        
        <div style={{ textAlign: 'center', marginTop: '10px', fontSize: '12px', color: '#64748b' }}>
          נשמרו בסשן: {saved} | סה"כ ב-DB: {totalCount}
        </div>
        
        <div style={{ display: 'flex', gap: '8px', marginTop: '15px' }}>
          <button onClick={handleClearAll} style={{ flex: 1, padding: '8px', background: '#fee2e2', color: '#dc2626', border: '1px solid #fca5a5', borderRadius: '6px', cursor: 'pointer', fontSize: '12px' }}>מחק הכל</button>
          <button onClick={onClose} style={{ flex: 1, padding: '8px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>סיום</button>
        </div>
      </div>
    </div>,
    document.body
  );
};

// --- רכיב כתיבה (OCR) ---
const HandwritingOverlay = ({ onComplete, onCancel, anchorRect }: { onComplete: (val: string) => void; onCancel: () => void; anchorRect?: DOMRect | null }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [loading, setLoading] = useState(false);
  const [recognized, setRecognized] = useState<string | null>(null);
  const timerRef = useRef<any>(null);
  const workerRef = useRef<any>(null);
  const [textInput, setTextInput] = useState('');

  useEffect(() => {
    const initWorker = async () => {
      const worker = await Tesseract.createWorker('eng');
      await worker.setParameters({
        tessedit_char_whitelist: '0123456789',
      });
      workerRef.current = worker;
    };
    initWorker();
    return () => {
      if (workerRef.current) {
        workerRef.current.terminate();
      }
    };
  }, []);

  const getCoords = (e: any) => {
    const rect = canvasRef.current!.getBoundingClientRect();
    if (e.touches && e.touches[0]) {
      return { x: e.touches[0].clientX - rect.left, y: e.touches[0].clientY - rect.top };
    }
    return { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  const startDrawing = (e: any) => {
    e.preventDefault();
    setIsDrawing(true);
    setRecognized(null);
    const { x, y } = getCoords(e);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineWidth = 8;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.strokeStyle = '#000';
    }
  };

  const draw = (e: any) => {
    if (!isDrawing) return;
    e.preventDefault();
    const { x, y } = getCoords(e);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx) { 
      ctx.lineTo(x, y); 
      ctx.stroke(); 
    }
    if (timerRef.current) clearTimeout(timerRef.current);
    timerRef.current = setTimeout(processOCR, 800);
  };

  const stopDrawing = () => {
    setIsDrawing(false);
  };

  const clearCanvas = () => {
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx && canvasRef.current) {
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
    setRecognized(null);
  };

  const preprocessCanvas = () => {
    const canvas = canvasRef.current;
    if (!canvas) return null;
    const ctx = canvas.getContext('2d');
    if (!ctx) return null;

    const tempCanvas = document.createElement('canvas');
    const scale = 3;
    tempCanvas.width = canvas.width * scale;
    tempCanvas.height = canvas.height * scale;
    const tempCtx = tempCanvas.getContext('2d');
    if (!tempCtx) return null;

    tempCtx.fillStyle = '#ffffff';
    tempCtx.fillRect(0, 0, tempCanvas.width, tempCanvas.height);
    tempCtx.drawImage(canvas, 0, 0, tempCanvas.width, tempCanvas.height);

    const imageData = tempCtx.getImageData(0, 0, tempCanvas.width, tempCanvas.height);
    const data = imageData.data;

    for (let i = 0; i < data.length; i += 4) {
      const gray = data[i] * 0.3 + data[i+1] * 0.59 + data[i+2] * 0.11;
      const value = gray < 180 ? 0 : 255;
      data[i] = data[i+1] = data[i+2] = value;
    }

    tempCtx.putImageData(imageData, 0, 0);

    const padding = 40;
    const paddedCanvas = document.createElement('canvas');
    paddedCanvas.width = tempCanvas.width + padding * 2;
    paddedCanvas.height = tempCanvas.height + padding * 2;
    const paddedCtx = paddedCanvas.getContext('2d');
    if (paddedCtx) {
      paddedCtx.fillStyle = '#ffffff';
      paddedCtx.fillRect(0, 0, paddedCanvas.width, paddedCanvas.height);
      paddedCtx.drawImage(tempCanvas, padding, padding);
    }

    return paddedCanvas.toDataURL('image/png');
  };

  const matchWithLearnedDigits = async (): Promise<string | null> => {
    if (!canvasRef.current) return null;
    
    const learnedDigits = await getLearnedDigits();
    if (learnedDigits.length === 0) return null;

    const currentCanvas = canvasRef.current;
    const currentCtx = currentCanvas.getContext('2d');
    if (!currentCtx) return null;

    const normalizeCanvas = document.createElement('canvas');
    normalizeCanvas.width = 50;
    normalizeCanvas.height = 50;
    const normalizeCtx = normalizeCanvas.getContext('2d');
    if (!normalizeCtx) return null;

    normalizeCtx.fillStyle = '#ffffff';
    normalizeCtx.fillRect(0, 0, 50, 50);
    normalizeCtx.drawImage(currentCanvas, 0, 0, 50, 50);
    const currentData = normalizeCtx.getImageData(0, 0, 50, 50);

    let bestMatch = { digit: '', score: 0 };

    for (const learned of learnedDigits) {
      const img = new Image();
      img.crossOrigin = 'anonymous';
      
      await new Promise<void>((resolve) => {
        img.onload = () => {
          normalizeCtx.fillStyle = '#ffffff';
          normalizeCtx.fillRect(0, 0, 50, 50);
          normalizeCtx.drawImage(img, 0, 0, 50, 50);
          const learnedData = normalizeCtx.getImageData(0, 0, 50, 50);
          
          const score = compareImages(currentData, learnedData);
          if (score > bestMatch.score) {
            bestMatch = { digit: learned.digit, score };
          }
          resolve();
        };
        img.onerror = () => resolve();
        img.src = learned.imageData;
      });
    }

    return bestMatch.score > 0.6 ? bestMatch.digit : null;
  };

  const processOCR = async () => {
    if (!canvasRef.current) return;
    setLoading(true);
    
    const learnedResult = await matchWithLearnedDigits();
    
    if (learnedResult) {
      setRecognized(learnedResult);
      setLoading(false);
      return;
    }

    if (!workerRef.current) {
      setLoading(false);
      return;
    }

    const dataUrl = preprocessCanvas();
    if (!dataUrl) {
      setLoading(false);
      return;
    }
    
    try {
      const result = await workerRef.current.recognize(dataUrl);
      const text = result.data.text.replace(/[^0-9]/g, '');
      setRecognized(text || null);
    } catch (err) {
      console.error('OCR error:', err);
    }
    setLoading(false);
  };

  const confirmValue = () => {
    if (recognized) {
      onComplete(recognized);
    }
  };

  useEffect(() => {
    clearCanvas();
  }, []);

  // Calculate position - show to the right of the element, or centered if no anchor
  const getPosition = () => {
    if (anchorRect) {
      let top = anchorRect.top;
      let left = anchorRect.right + 10;
      
      // If would go off right edge, show to the left instead
      if (left + 380 > window.innerWidth) {
        left = anchorRect.left - 390;
      }
      // If would go off left edge, center it
      if (left < 10) {
        left = Math.max(10, (window.innerWidth - 380) / 2);
      }
      // If would go off bottom, move up
      if (top + 380 > window.innerHeight) {
        top = Math.max(10, window.innerHeight - 390);
      }
      return { top, left };
    }
    return { top: '50%', left: '50%', transform: 'translate(-50%, -50%)' };
  };

  const pos = getPosition();

  return createPortal(
    <div style={{ 
      position: 'fixed', 
      top: typeof pos.top === 'number' ? pos.top : pos.top,
      left: typeof pos.left === 'number' ? pos.left : pos.left,
      transform: (pos as any).transform || 'none',
      zIndex: 10001, 
      background: 'white', 
      border: '2px solid #2563eb', 
      padding: '10px', 
      borderRadius: '10px', 
      boxShadow: '0 6px 20px rgba(0,0,0,0.25)', 
      minWidth: '270px',
      maxWidth: '290px',
      direction: 'rtl' 
    }}>
      {/* Title + close */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
        <span style={{ fontSize: '13px', fontWeight: 'bold', color: '#2563eb' }}>עדכון גובה</span>
        <button onClick={onCancel} style={{ background: 'none', border: 'none', color: '#94a3b8', cursor: 'pointer', fontSize: '16px', lineHeight: 1, padding: '0 2px' }}>✕</button>
      </div>

      {/* Text input + VK trigger */}
      <div style={{ display: 'flex', gap: '4px', marginBottom: '8px', alignItems: 'center' }}>
        <input
          type="text"
          value={textInput}
          onChange={e => setTextInput(e.target.value)}
          onKeyDown={e => { if (e.key === 'Enter' && textInput.trim()) { onComplete(textInput.trim()); } }}
          placeholder="הקלד גובה..."
          autoFocus
          style={{ flex: 1, padding: '6px 8px', fontSize: '16px', border: '2px solid #93c5fd', borderRadius: '6px', textAlign: 'center', direction: 'ltr', outline: 'none' }}
        />
        <VKTrigger value={textInput} onChange={v => setTextInput(v)} mode="numeric" label="גובה" size={15} />
        <button
          onPointerDown={e => e.preventDefault()}
          onClick={() => { if (textInput.trim()) onComplete(textInput.trim()); }}
          disabled={!textInput.trim()}
          style={{ padding: '6px 12px', background: textInput.trim() ? '#10b981' : '#d1fae5', color: textInput.trim() ? 'white' : '#6ee7b7', border: 'none', borderRadius: '6px', cursor: textInput.trim() ? 'pointer' : 'default', fontSize: '14px', fontWeight: 'bold', flexShrink: 0 }}
        >✓</button>
      </div>

      {/* Confirm recognized value — ABOVE the canvas */}
      {recognized && (
        <>
          <div style={{ marginBottom: '6px', padding: '6px 8px', background: '#ecfdf5', border: '1px solid #10b981', borderRadius: '6px', textAlign: 'center', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ fontSize: '11px', color: '#065f46' }}>זוהה: <strong style={{ fontSize: '16px' }}>{recognized}</strong></span>
          </div>
          <button onClick={confirmValue} style={{ marginBottom: '6px', width: '100%', padding: '7px', background: '#10b981', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer', fontSize: '13px', fontWeight: 'bold' }}>✓ אישור — {recognized}</button>
        </>
      )}

      {/* Divider + status */}
      <div style={{ textAlign: 'center', fontSize: '10px', color: '#94a3b8', marginBottom: '4px' }}>
        {loading ? '⏳ מזהה...' : '— כתב יד —'}
      </div>
      
      {/* Canvas — smaller */}
      <canvas 
        ref={canvasRef} 
        width={250} 
        height={130} 
        style={{ background: '#ffffff', border: '2px solid #cbd5e1', borderRadius: '6px', touchAction: 'none', display: 'block', width: '250px', height: '130px' }}
        onMouseDown={startDrawing} 
        onMouseMove={draw} 
        onMouseUp={stopDrawing}
        onMouseLeave={stopDrawing}
        onTouchStart={startDrawing} 
        onTouchMove={draw} 
        onTouchEnd={stopDrawing} 
      />
      
      {/* Canvas controls */}
      <div style={{ display: 'flex', gap: '4px', marginTop: '6px' }}>
        <button onClick={clearCanvas} style={{ flex: 1, padding: '5px', background: '#f1f5f9', color: '#475569', border: '1px solid #cbd5e1', borderRadius: '4px', cursor: 'pointer', fontSize: '11px' }}>נקה</button>
        <button onClick={processOCR} disabled={loading} style={{ flex: 1, padding: '5px', background: '#dbeafe', color: '#1d4ed8', border: '1px solid #93c5fd', borderRadius: '4px', cursor: 'pointer', fontSize: '11px' }}>עבד</button>
      </div>
    </div>,
    document.body
  );
};

// --- רכיב עריכת פמם בהעברה ---
const TransferStripEditor = ({ transfer, onAltUpdate, onCancel }: { 
  transfer: any; 
  onAltUpdate: (stripId: string, alt: string) => void;
  onCancel: (transferId: string) => void;
}) => {
  const [edit, setEdit] = useState(false);
  const [anchorRect, setAnchorRect] = useState<DOMRect | null>(null);
  const altRef = useRef<HTMLSpanElement>(null);

  const handleEditClick = () => {
    if (altRef.current) {
      setAnchorRect(altRef.current.getBoundingClientRect());
    }
    setEdit(true);
  };

  return (
    <div style={{ 
      padding: '8px', 
      background: '#fef3c7', 
      border: '2px dashed #f59e0b', 
      borderRadius: '6px', 
      marginBottom: '6px',
      direction: 'rtl'
    }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '6px' }}>
        <div style={{ flex: 1, overflow: 'hidden' }}>
          <div style={{ fontWeight: 'bold', fontSize: '12px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
            {getTransferLabel(transfer)}
          </div>
          {getTransferSq(transfer) && <div style={{ fontSize: '9px', color: '#92400e', marginTop: '1px', opacity: 0.8 }}>{getTransferSq(transfer)}</div>}
        </div>
        <span
          ref={altRef}
          onClick={handleEditClick}
          title="לחץ לעדכון גובה"
          style={{ fontSize: '16px', fontWeight: 'bold', color: '#92400e', background: '#fde68a', padding: '2px 7px', borderRadius: '5px', border: '1px solid #f59e0b', cursor: 'pointer', flexShrink: 0, letterSpacing: '0.5px' }}
        >
          {transfer.alt ? normalizeAlt(transfer.alt) : '—'}
        </span>
      </div>
      <div style={{ fontSize: '10px', color: '#92400e', marginTop: '3px', opacity: 0.75 }}>ממתין לאישור...</div>
      <button 
        onClick={() => onCancel(transfer.id)} 
        style={{ 
          marginTop: '6px', 
          width: '100%', 
          padding: '4px', 
          background: '#dc2626', 
          color: 'white', 
          border: 'none', 
          borderRadius: '4px', 
          fontSize: '10px', 
          cursor: 'pointer' 
        }}
      >
        בטל העברה
      </button>
      {edit && (
        <HandwritingOverlay 
          onCancel={() => setEdit(false)} 
          onComplete={(val: string) => { 
            onAltUpdate(transfer.strip_id, val); 
            setEdit(false); 
          }} 
          anchorRect={anchorRect}
        />
      )}
    </div>
  );
};

// Parse a note value that may be plain text, a data-URL, or combined JSON { text, hw }
const parseNoteValue = (val: string): { text: string; hw: string } => {
  if (!val) return { text: '', hw: '' };
  if (val.startsWith('data:')) return { text: '', hw: val };
  if (val.startsWith('{')) {
    try { const p = JSON.parse(val); return { text: p.text || '', hw: p.hw || '' }; } catch {}
  }
  return { text: val, hw: '' };
};
const serializeNoteValue = (text: string, hw: string): string => {
  const hasText = text.trim().length > 0;
  const hasHw = hw.startsWith('data:');
  if (hasText && hasHw) return JSON.stringify({ text, hw });
  if (hasHw) return hw;
  return text;
};

// --- כרטיס מוסר בסקטור ---
const OutgoingTransferCard = ({ t, isConflict, onCancel, onUpdateStripField, lightMode = false }: {
  t: any;
  isConflict: boolean;
  onCancel: (id: string) => void;
  onUpdateStripField?: (stripId: string, field: string, value: string) => void;
  lightMode?: boolean;
}) => {
  const altRef = useRef<HTMLSpanElement>(null);
  const [anchorRect, setAnchorRect] = useState<DOMRect | null>(null);
  const [showHw, setShowHw] = useState(false);
  const sq = getTransferSq(t);
  return (
    <>
      <div style={{
        padding: '4px 5px', direction: 'rtl', margin: '2px 0', borderRadius: '6px',
        border: isConflict ? '1px solid #ef4444' : (lightMode ? '1px solid #d97706' : '1px solid #78350f'),
        background: isConflict ? (lightMode ? '#fef2f2' : '#450a0a') : (lightMode ? '#fffbeb' : '#0d0800'),
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '4px', marginBottom: '3px' }}>
          <div style={{ flex: 1, overflow: 'hidden' }}>
            <div style={{ fontWeight: 'bold', color: isConflict ? (lightMode ? '#b91c1c' : '#fca5a5') : (lightMode ? '#92400e' : '#fcd34d'), overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', fontSize: '11px' }}>
              {isConflict && '⚠ '}{getTransferLabel(t)}
            </div>
            {sq && <div style={{ fontSize: '9px', color: isConflict ? (lightMode ? '#b91c1c' : '#fca5a5') : '#b45309', marginTop: '1px', opacity: 0.85 }}>{sq}</div>}
          </div>
          <span
            ref={altRef}
            title="לחץ לעדכון גובה"
            onClick={() => { if (altRef.current) setAnchorRect(altRef.current.getBoundingClientRect()); setShowHw(true); }}
            style={{ fontSize: '11px', fontWeight: 'bold', color: isConflict ? (lightMode ? '#b91c1c' : '#fca5a5') : (lightMode ? '#92400e' : '#fcd34d'), background: isConflict ? (lightMode ? '#fee2e2' : '#7f1d1d') : (lightMode ? '#fef3c7' : '#1c0f00'), padding: '1px 6px', borderRadius: '4px', cursor: 'pointer', flexShrink: 0, letterSpacing: '0.5px', border: `1px dashed ${isConflict ? '#ef4444' : '#d97706'}` }}
          >
            {t.alt ? normalizeAlt(t.alt) : '—'}
          </span>
        </div>
        <button
          onClick={(e) => { e.stopPropagation(); onCancel(t.id); }}
          style={{ width: '100%', padding: '1px', background: isConflict ? (lightMode ? '#fee2e2' : '#7f1d1d') : (lightMode ? '#fde68a' : '#7f1d1d'), color: isConflict ? (lightMode ? '#b91c1c' : '#fca5a5') : (lightMode ? '#78350f' : '#fca5a5'), border: `1px solid ${isConflict ? '#dc2626' : (lightMode ? '#d97706' : '#dc2626')}`, borderRadius: '3px', fontSize: '9px', cursor: 'pointer' }}
        >✕ בטל</button>
      </div>
      {showHw && (
        <HandwritingOverlay
          onCancel={() => setShowHw(false)}
          onComplete={(val: string) => { const n = normalizeAlt(val); setShowHw(false); if (onUpdateStripField) onUpdateStripField(String(t.strip_id), 'alt', n); }}
          anchorRect={anchorRect}
        />
      )}
    </>
  );
};

// --- פאנל נקודת העברה עם עמודות העברה/קבלה ---
const DraggableNeighborPanel = ({ 
  neighbor, 
  subSectors,
  onDropOnMap,
  isExpanded,
  onToggle,
  outgoingTransfers,
  incomingTransfers,
  onCancelTransfer,
  onAcceptTransfer,
  onRejectTransfer,
  onAcceptToMap,
  dragStripId,
  onStripDrop,
  conflictAltDelta,
  crossSectorConflictIds,
  onUpdateStripField,
  mapZoom,
  mapPan,
  lightMode = false,
}: { 
  neighbor: any; 
  subSectors: any[];
  onDropOnMap: (sectorId: number, x: number, y: number, subSectorLabel?: string, clientX?: number, clientY?: number) => void;
  isExpanded: boolean;
  onToggle: () => void;
  outgoingTransfers: any[];
  incomingTransfers: any[];
  onCancelTransfer: (id: string) => void;
  onAcceptTransfer: (id: string) => void;
  onRejectTransfer: (id: string) => void;
  onAcceptToMap: (id: string, x: number, y: number) => void;
  dragStripId?: string | null;
  onStripDrop?: (stripId: string, sectorId: number) => void;
  conflictAltDelta?: number;
  crossSectorConflictIds?: Set<string>;
  onUpdateStripField?: (stripId: string, field: string, value: string) => void;
  mapZoom?: number;
  mapPan?: { x: number; y: number };
  lightMode?: boolean;
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isStripDragOver, setIsStripDragOver] = useState(false);
  const [dragPos, setDragPos] = useState({ x: 0, y: 0 });
  const [dragLabel, setDragLabel] = useState<string | null>(null);
  const [neighborContactsOpen, setNeighborContactsOpen] = useState(false);
  const [neighborContactsCache, setNeighborContactsCache] = useState<any[] | null>(null);

  const getNeighborContacts = () => {
    if (!neighborContactsCache) return [];
    const byPreset = new Map<number, { presetName: string; contacts: any[] }>();
    for (const c of neighborContactsCache) {
      let sectors: number[] = [];
      try { sectors = Array.isArray(c.relevant_sectors) ? c.relevant_sectors : (typeof c.relevant_sectors === 'string' ? JSON.parse(c.relevant_sectors) : []); } catch {}
      if (!sectors.map(Number).includes(Number(neighbor.id))) continue;
      if (!byPreset.has(c.preset_id)) byPreset.set(c.preset_id, { presetName: c.preset_name || `עמדה ${c.preset_id}`, contacts: [] });
      byPreset.get(c.preset_id)!.contacts.push(c);
    }
    return Array.from(byPreset.entries()).map(([pid, v]) => ({ presetId: pid, ...v }));
  };
  const toggleNeighborContacts = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (neighborContactsOpen) { setNeighborContactsOpen(false); return; }
    if (!neighborContactsCache) {
      const data = await fetch('/api/workstation-contacts/all').then(r => r.ok ? r.json() : []).catch(() => []);
      setNeighborContactsCache(data);
    }
    setNeighborContactsOpen(true);
  };

  const sectorOutgoing = outgoingTransfers.filter(t => Number(t.to_sector_id) === Number(neighbor.id));
  const sectorIncoming = incomingTransfers.filter(t => Number(t.from_sector_id) === Number(neighbor.id));

  const parseAlt = (alt: string | null | undefined): number | null => {
    if (!alt) return null;
    const m = alt.match(/\d+/);
    return m ? parseInt(m[0]) : null;
  };

  // delta is stored directly in feet; altitudes are in hundreds → multiply diff by 100 for comparison
  const delta = (neighbor as any).conflict_alt_delta ?? conflictAltDelta ?? 0;
  const conflictingTransferIds = new Set<string>();
  if (delta > 0) {
    // Compare outgoing × incoming (cross-direction); skip if same transfer appears in both
    for (const out of sectorOutgoing) {
      const outAlt = parseAlt(out.alt);
      if (outAlt == null) continue;
      for (const inc of sectorIncoming) {
        if (String(inc.id) === String(out.id)) continue; // same record in both arrays → skip
        const incAlt = parseAlt(inc.alt);
        if (incAlt == null) continue;
        if (Math.abs(outAlt - incAlt) * 100 <= delta) {
          conflictingTransferIds.add(String(out.id));
          conflictingTransferIds.add(String(inc.id));
        }
      }
    }
    // Compare outgoing × outgoing (same-direction — two strips going to same sector at similar altitude)
    // Skip if they go via DIFFERENT sub-sector transfer points (different corridors, no shared airspace)
    for (let i = 0; i < sectorOutgoing.length; i++) {
      const altA = parseAlt(sectorOutgoing[i].alt);
      if (altA == null) continue;
      for (let j = i + 1; j < sectorOutgoing.length; j++) {
        const lblI = sectorOutgoing[i].sub_sector_label || '';
        const lblJ = sectorOutgoing[j].sub_sector_label || '';
        if (lblI && lblJ && lblI !== lblJ) continue; // different transfer points → skip
        const altB = parseAlt(sectorOutgoing[j].alt);
        if (altB == null) continue;
        if (Math.abs(altA - altB) * 100 <= delta) {
          conflictingTransferIds.add(String(sectorOutgoing[i].id));
          conflictingTransferIds.add(String(sectorOutgoing[j].id));
        }
      }
    }
    // Compare incoming × incoming (same-direction)
    // Skip if they arrive via DIFFERENT sub-sector transfer points
    for (let i = 0; i < sectorIncoming.length; i++) {
      const altA = parseAlt(sectorIncoming[i].alt);
      if (altA == null) continue;
      for (let j = i + 1; j < sectorIncoming.length; j++) {
        const lblI = sectorIncoming[i].sub_sector_label || '';
        const lblJ = sectorIncoming[j].sub_sector_label || '';
        if (lblI && lblJ && lblI !== lblJ) continue; // different transfer points → skip
        const altB = parseAlt(sectorIncoming[j].alt);
        if (altB == null) continue;
        if (Math.abs(altA - altB) * 100 <= delta) {
          conflictingTransferIds.add(String(sectorIncoming[i].id));
          conflictingTransferIds.add(String(sectorIncoming[j].id));
        }
      }
    }
  }
  // Merge explicit conflicts from parent if any
  if (crossSectorConflictIds) {
    const sectorTransferIds = new Set([...sectorOutgoing, ...sectorIncoming].map(t => String(t.id)));
    crossSectorConflictIds.forEach(id => {
      if (sectorTransferIds.has(id)) conflictingTransferIds.add(id);
    });
  }
  const hasConflict = conflictingTransferIds.size > 0;

  const handlePointerDown = (e: React.PointerEvent, subLabel?: string) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
    setDragPos({ x: e.clientX - 50, y: e.clientY - 20 });
    setDragLabel(subLabel || null);
  };

  useEffect(() => {
    if (!isDragging) return;

    let lastClientX = 0;
    let lastClientY = 0;

    const handleMove = (e: PointerEvent) => {
      lastClientX = e.clientX;
      lastClientY = e.clientY;
      setDragPos({ x: e.clientX - 50, y: e.clientY - 20 });
    };

    const dropAt = (clientX: number, clientY: number) => {
      setIsDragging(false);
      const mapArea = document.getElementById('map-area');
      if (mapArea) {
        const rect = mapArea.getBoundingClientRect();
        if (clientX >= rect.left && clientX <= rect.right &&
            clientY >= rect.top && clientY <= rect.bottom) {
          const cx = rect.left + rect.width / 2;
          const cy = rect.top + rect.height / 2;
          const z = mapZoom || 1;
          const px = mapPan?.x ?? 0;
          const py = mapPan?.y ?? 0;
          const rawX = (clientX - cx - px) / z + rect.width / 2;
          const rawY = (clientY - cy - py) / z + rect.height / 2;
          const x = Math.max(100, Math.min(rect.width - 100, rawX));
          const y = Math.max(40, Math.min(rect.height - 50, rawY));
          onDropOnMap(neighbor.id, x, y, dragLabel || undefined, clientX, clientY);
        }
      }
      setDragLabel(null);
    };

    const handleUp = (e: PointerEvent) => dropAt(e.clientX, e.clientY);
    const handleCancel = () => dropAt(lastClientX, lastClientY);

    window.addEventListener('pointermove', handleMove);
    window.addEventListener('pointerup', handleUp);
    window.addEventListener('pointercancel', handleCancel);
    return () => {
      window.removeEventListener('pointermove', handleMove);
      window.removeEventListener('pointerup', handleUp);
      window.removeEventListener('pointercancel', handleCancel);
    };
  }, [isDragging, neighbor.id, onDropOnMap, dragLabel, mapZoom, mapPan]);

  const neighborSubSectors = subSectors.filter(ss => ss.neighbor_id === neighbor.id);
  const hasSubSectors = neighborSubSectors.length > 0;
  const hasTransfers = sectorOutgoing.length > 0 || sectorIncoming.length > 0;

  return (
    <>
      {/* Card container */}
      <div
        onDragOver={e => { e.preventDefault(); setIsStripDragOver(true); }}
        onDragLeave={e => { if (!e.currentTarget.contains(e.relatedTarget as Node)) setIsStripDragOver(false); }}
        onDrop={e => { e.preventDefault(); e.stopPropagation(); setIsStripDragOver(false); const sid = dragStripId || e.dataTransfer.getData('text/strip-id-for-transfer') || (() => { try { const d = JSON.parse(e.dataTransfer.getData('text/plain')); return d.stripId ? String(d.stripId) : null; } catch { return null; } })(); if (sid && onStripDrop) onStripDrop(String(sid), neighbor.id); }}
        style={{
        margin: '6px 6px',
        borderRadius: '10px',
        border: isStripDragOver ? '2px solid #22c55e' : (hasConflict ? '2px solid #ef4444' : (lightMode ? '1px solid #cbd5e1' : '1px solid #2d4060')),
        background: isStripDragOver ? (lightMode ? '#f0fdf4' : '#0a2218') : (dragStripId ? (lightMode ? '#eff6ff' : '#0e1e2e') : (lightMode ? '#f8fafc' : '#0f1923')),
        overflow: 'hidden',
        boxShadow: lightMode ? '0 2px 8px rgba(0,0,0,0.12)' : '0 2px 10px rgba(0,0,0,0.5)',
        transition: 'border-color 0.15s, background 0.15s',
      }}>

        {/* Header — drag zone */}
        <div
          className="neighbor-drop-zone"
          data-sector-id={neighbor.id}
          onPointerDown={(e) => { if (dragStripId) { e.preventDefault(); e.stopPropagation(); } else { handlePointerDown(e); } }}
          onPointerEnter={() => { if (dragStripId) setIsStripDragOver(true); }}
          onPointerLeave={() => { if (dragStripId) setIsStripDragOver(false); }}
          onDragOver={(e => { e.preventDefault(); e.stopPropagation(); setIsStripDragOver(true); })}
          onDragLeave={(() => setIsStripDragOver(false))}
          onDrop={(e => { e.preventDefault(); e.stopPropagation(); setIsStripDragOver(false); const sid = dragStripId || e.dataTransfer.getData('text/strip-id-for-transfer') || (() => { try { const d = JSON.parse(e.dataTransfer.getData('text/plain')); return d.stripId ? String(d.stripId) : null; } catch { return null; } })(); if (sid && onStripDrop) onStripDrop(String(sid), neighbor.id); })}
          style={{
            padding: '7px 10px',
            background: lightMode ? 'rgba(0,0,0,0.04)' : 'rgba(255,255,255,0.05)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            gap: '6px',
            cursor: dragStripId ? 'copy' : 'grab',
            userSelect: 'none',
            direction: 'rtl',
            borderBottom: `1px solid ${lightMode ? '#e2e8f0' : '#1e2d3d'}`,
          }}
        >
          {/* Sector name — center */}
          <div style={{ flex: 1, textAlign: 'center', direction: 'rtl', userSelect: 'none' }}>
            <div style={{ fontSize: '12px', fontWeight: 'bold', color: lightMode ? '#1e293b' : '#e2e8f0', letterSpacing: '0.01em', lineHeight: 1.4 }}>
              {neighbor.label_he || neighbor.name}
            </div>
            {neighbor.notes && (
              <div style={{ fontSize: '9px', color: lightMode ? '#92400e' : '#fbbf24', fontStyle: 'italic', marginTop: '1px' }}>{neighbor.notes}</div>
            )}
            {hasConflict && (
              <span style={{ fontSize: '10px', background: lightMode ? '#fee2e2' : '#450a0a', color: lightMode ? '#b91c1c' : '#fca5a5', borderRadius: '4px', padding: '1px 5px', fontWeight: 'bold', display: 'inline-block', marginTop: '2px' }}>⚠ קונפליקט גובה</span>
            )}
          </div>

          {/* קשר button */}
          <button
            onClick={toggleNeighborContacts}
            onPointerDown={e => e.stopPropagation()}
            title="הצג קשרי עמדות לנקודה זו"
            style={{
              padding: '3px 9px',
              fontSize: '11px',
              fontWeight: 'bold',
              background: neighborContactsOpen ? '#0c3547' : '#0a1e2e',
              color: neighborContactsOpen ? '#67e8f9' : '#38bdf8',
              border: `1px solid ${neighborContactsOpen ? '#0e7490' : '#1e4a6a'}`,
              borderRadius: '6px',
              cursor: 'pointer',
              flexShrink: 0,
              lineHeight: 1.5,
              transition: 'all 0.15s',
            }}>
            קשר
          </button>

          {/* Sub-sector toggle (only if sub-sectors exist) */}
          {hasSubSectors && (
            <span
              onClick={(e) => { e.stopPropagation(); onToggle(); }}
              style={{ fontSize: '11px', color: '#64748b', cursor: 'pointer', flexShrink: 0, padding: '2px 4px' }}
            >{isExpanded ? '▲' : '▼'}</span>
          )}
        </div>

        {/* Sub-sectors (collapsible) */}
        {isExpanded && hasSubSectors && neighborSubSectors.map(ss => (
          <div
            key={ss.id}
            onPointerDown={(e) => handlePointerDown(e, ss.label)}
            style={{ padding: '5px 12px', fontSize: '11px', color: lightMode ? '#64748b' : '#94a3b8', borderBottom: `1px solid ${lightMode ? '#e2e8f0' : '#1e2d3d'}`, cursor: 'grab', userSelect: 'none', direction: 'rtl', background: lightMode ? '#f1f5f9' : '#080f18' }}
          >
            ↳ {ss.label}
          </div>
        ))}

        {/* Two-column transfers — always visible */}
        <div style={{ display: 'flex', direction: 'rtl' }}>

          {/* מוסר — outgoing (right in RTL = left visually) */}
          <div style={{ flex: 1, borderInlineEnd: `1px solid ${lightMode ? '#e2e8f0' : '#1e2d3d'}` }}>
            <div style={{ padding: '4px 6px', fontSize: '10px', fontWeight: 'bold', color: lightMode ? '#92400e' : '#f59e0b', background: lightMode ? '#fffbeb' : '#130a00', textAlign: 'center', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '3px' }}>
              <span>🔥</span><span>מוסר</span><span style={{ fontWeight: 'normal', opacity: 0.75 }}>({sectorOutgoing.length})</span>
            </div>
            <div style={{ padding: '3px', minHeight: '24px' }}>
              {sectorOutgoing.map(t => (
                <OutgoingTransferCard
                  key={t.id}
                  t={t}
                  isConflict={conflictingTransferIds.has(String(t.id))}
                  onCancel={onCancelTransfer}
                  onUpdateStripField={onUpdateStripField}
                  lightMode={lightMode}
                />
              ))}
              {sectorOutgoing.length === 0 && (
                <div style={{ padding: '6px 4px', fontSize: '10px', color: lightMode ? '#94a3b8' : '#334155', textAlign: 'center' }}>—</div>
              )}
            </div>
          </div>

          {/* מקבל — incoming */}
          <div style={{ flex: 1 }}>
            <div style={{ padding: '4px 6px', fontSize: '10px', fontWeight: 'bold', color: lightMode ? '#15803d' : '#22c55e', background: lightMode ? '#f0fdf4' : '#020d04', textAlign: 'center', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '3px' }}>
              <span>📥</span><span>מקבל</span><span style={{ fontWeight: 'normal', opacity: 0.75 }}>({sectorIncoming.length})</span>
            </div>
            <div style={{ padding: '3px', minHeight: '24px' }}>
              {sectorIncoming.map(t => (
                <DraggableIncomingTransferMini
                  key={t.id}
                  transfer={t}
                  onAccept={onAcceptTransfer}
                  onReject={onRejectTransfer}
                  onAcceptToMap={onAcceptToMap}
                  isConflict={conflictingTransferIds.has(String(t.id))}
                  onUpdateStripField={onUpdateStripField}
                  zoom={mapZoom}
                  pan={mapPan}
                />
              ))}
              {sectorIncoming.length === 0 && (
                <div style={{ padding: '6px 4px', fontSize: '10px', color: lightMode ? '#94a3b8' : '#334155', textAlign: 'center' }}>—</div>
              )}
            </div>
          </div>
        </div>

        {/* Contacts panel */}
        {neighborContactsOpen && neighborContactsCache !== null && (() => {
          const groups = getNeighborContacts();
          return (
            <div style={{ borderTop: `1px solid ${lightMode ? '#e2e8f0' : '#1e3a5f'}`, background: lightMode ? '#f8fafc' : '#060f1e', padding: '6px 8px', fontSize: '11px', direction: 'rtl', borderRadius: '0 0 10px 10px' }}>
              {groups.length === 0 ? (
                <div style={{ color: '#64748b', fontStyle: 'italic', textAlign: 'center', padding: '4px 0' }}>אין קשרים מוגדרים לסקטור זה</div>
              ) : groups.map(g => (
                <div key={g.presetId} style={{ marginBottom: '6px' }}>
                  <div style={{ fontWeight: 'bold', color: lightMode ? '#0369a1' : '#7dd3fc', fontSize: '10px', marginBottom: '3px', paddingBottom: '2px', borderBottom: `1px solid ${lightMode ? '#e2e8f0' : '#1e3a5f'}` }}>📍 {g.presetName}</div>
                  {g.contacts.map((c: any) => (
                    <div key={c.id} style={{ display: 'flex', gap: '5px', padding: '2px 4px', borderRadius: '3px', background: lightMode ? '#f1f5f9' : '#0a1e35', marginBottom: '2px', alignItems: 'center', flexWrap: 'wrap' }}>
                      {c.device_type && <span style={{ color: lightMode ? '#b45309' : '#f59e0b', fontWeight: 'bold', fontSize: '9px', minWidth: '24px', flexShrink: 0 }}>{c.device_type}</span>}
                      {c.mahut && <span style={{ color: lightMode ? '#475569' : '#94a3b8', flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', fontSize: '10px' }}>{c.mahut}</span>}
                      {c.oketz && <span style={{ color: lightMode ? '#2563eb' : '#60a5fa', fontWeight: 'bold', fontSize: '10px', flexShrink: 0 }}>{c.oketz}</span>}
                      {c.frequency && <span style={{ color: lightMode ? '#16a34a' : '#22c55e', fontFamily: 'monospace', fontSize: '10px', flexShrink: 0 }}>{c.frequency}</span>}
                    </div>
                  ))}
                </div>
              ))}
            </div>
          );
        })()}
      </div>

      {isDragging && createPortal(
        <div style={{
          position: 'fixed',
          left: dragPos.x,
          top: dragPos.y,
          background: '#2563eb',
          color: 'white',
          padding: '10px 20px',
          borderRadius: '8px',
          fontSize: '14px',
          fontWeight: 'bold',
          boxShadow: '0 8px 20px rgba(0,0,0,0.4)',
          zIndex: 9999,
          pointerEvents: 'none',
          direction: 'rtl'
        }}>
          {dragLabel ? `${neighbor.label_he || neighbor.name} - ${dragLabel}` : (neighbor.label_he || neighbor.name)}
          <div style={{ fontSize: '10px', marginTop: '4px', opacity: 0.8 }}>שחרר על המפה</div>
        </div>,
        document.body
      )}
    </>
  );
};

// Mini version of incoming transfer for sector panel
const DraggableIncomingTransferMini = ({
  transfer,
  onAccept,
  onReject,
  onAcceptToMap,
  isConflict = false,
  onUpdateStripField,
  zoom = 1,
  pan,
}: {
  transfer: any;
  onAccept: (id: string) => void;
  onReject: (id: string) => void;
  onAcceptToMap: (id: string, x: number, y: number) => void;
  isConflict?: boolean;
  onUpdateStripField?: (stripId: string, field: string, value: string) => void;
  zoom?: number;
  pan?: { x: number; y: number };
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [dragPos, setDragPos] = useState({ x: 0, y: 0 });
  const [editingAlt, setEditingAlt] = useState(false);
  const [anchorRect, setAnchorRect] = useState<DOMRect | null>(null);
  const altRef = useRef<HTMLSpanElement>(null);

  const handlePointerDown = (e: React.PointerEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
    setDragPos({ x: e.clientX - 40, y: e.clientY - 20 });
  };

  useEffect(() => {
    if (!isDragging) return;

    let lastClientX = 0;
    let lastClientY = 0;

    const handleMove = (e: PointerEvent) => {
      lastClientX = e.clientX;
      lastClientY = e.clientY;
      setDragPos({ x: e.clientX - 40, y: e.clientY - 20 });
    };

    const screenToMapCoords = (clientX: number, clientY: number, rect: DOMRect) => {
      const cx = rect.left + rect.width / 2;
      const cy = rect.top + rect.height / 2;
      const z = zoom || 1;
      const px = pan?.x ?? 0;
      const py = pan?.y ?? 0;
      const rawX = (clientX - cx - px) / z + rect.width / 2;
      const rawY = (clientY - cy - py) / z + rect.height / 2;
      return { rawX, rawY };
    };

    const dropAt = (clientX: number, clientY: number) => {
      setIsDragging(false);
      const sidebarArea = document.getElementById('sidebar-area');
      if (sidebarArea) {
        const sidebarRect = sidebarArea.getBoundingClientRect();
        if (clientX >= sidebarRect.left && clientX <= sidebarRect.right &&
            clientY >= sidebarRect.top && clientY <= sidebarRect.bottom) {
          onAccept(transfer.id);
          return;
        }
      }
      const mapArea = document.getElementById('map-area');
      if (mapArea) {
        const rect = mapArea.getBoundingClientRect();
        if (clientX >= rect.left && clientX <= rect.right &&
            clientY >= rect.top && clientY <= rect.bottom) {
          const { rawX, rawY } = screenToMapCoords(clientX, clientY, rect);
          const x = Math.max(100, Math.min(rect.width - 100, rawX));
          const y = Math.max(40, Math.min(rect.height - 50, rawY));
          onAcceptToMap(transfer.id, x, y);
        }
      }
    };

    const handleUp = (e: PointerEvent) => dropAt(e.clientX, e.clientY);
    const handleCancel = () => dropAt(lastClientX, lastClientY);

    window.addEventListener('pointermove', handleMove);
    window.addEventListener('pointerup', handleUp);
    window.addEventListener('pointercancel', handleCancel);
    return () => {
      window.removeEventListener('pointermove', handleMove);
      window.removeEventListener('pointerup', handleUp);
      window.removeEventListener('pointercancel', handleCancel);
    };
  }, [isDragging, transfer.id, onAcceptToMap, zoom, pan]);

  return (
    <>
      <div 
        onPointerDown={handlePointerDown}
        style={{ 
          background: isConflict ? '#450a0a' : '#dcfce7', 
          border: isConflict ? '2px solid #ef4444' : '1px solid #22c55e',
          borderRadius: '4px',
          padding: '5px',
          marginBottom: '4px',
          fontSize: '9px',
          cursor: 'grab',
          direction: 'rtl'
        }}
      >
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '4px', marginBottom: '4px' }}>
          <div style={{ flex: 1, overflow: 'hidden' }}>
            <div style={{ fontWeight: 'bold', color: isConflict ? '#fca5a5' : '#166534', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', fontSize: '11px' }}>
              {isConflict && '⚠️ '}{getTransferLabel(transfer)}
            </div>
            {getTransferSq(transfer) && <div style={{ fontSize: '9px', color: isConflict ? '#fca5a5' : '#15803d', marginTop: '1px', opacity: 0.85 }}>{getTransferSq(transfer)}</div>}
          </div>
          <span
            ref={altRef}
            title={onUpdateStripField ? 'לחץ לעדכון גובה' : undefined}
            onPointerDown={e => { if (onUpdateStripField) { e.stopPropagation(); if (altRef.current) setAnchorRect(altRef.current.getBoundingClientRect()); setEditingAlt(true); } }}
            style={{ fontSize: '11px', fontWeight: 'bold', color: isConflict ? '#fca5a5' : '#166534', background: isConflict ? '#7f1d1d' : '#bbf7d0', padding: '1px 6px', borderRadius: '4px', cursor: onUpdateStripField ? 'pointer' : 'default', flexShrink: 0, letterSpacing: '0.5px', border: onUpdateStripField ? `1px dashed ${isConflict ? '#ef4444' : '#22c55e'}` : 'none' }}
          >
            {transfer.alt ? normalizeAlt(transfer.alt) : '—'}
          </span>
        </div>
        <div style={{ display: 'flex', gap: '2px' }}>
          <button
            onClick={(e) => { e.stopPropagation(); onAccept(transfer.id); }}
            style={{
              flex: 1,
              padding: '2px',
              background: '#22c55e',
              color: 'white',
              border: 'none',
              borderRadius: '3px',
              fontSize: '8px',
              cursor: 'pointer'
            }}
          >
            קבל
          </button>
          <button
            onClick={(e) => { e.stopPropagation(); onReject(transfer.id); }}
            style={{
              flex: 1,
              padding: '2px',
              background: '#ef4444',
              color: 'white',
              border: 'none',
              borderRadius: '3px',
              fontSize: '8px',
              cursor: 'pointer'
            }}
          >
            דחה
          </button>
        </div>
      </div>
      
      {isDragging && createPortal(
        <div style={{
          position: 'fixed',
          left: dragPos.x,
          top: dragPos.y,
          background: '#22c55e',
          color: 'white',
          padding: '8px 16px',
          borderRadius: '8px',
          fontSize: '12px',
          fontWeight: 'bold',
          boxShadow: '0 8px 20px rgba(0,0,0,0.4)',
          zIndex: 9999,
          pointerEvents: 'none',
          direction: 'rtl'
        }}>
          {getFormationDisplayName(transfer)}
          <div style={{ fontSize: '9px', opacity: 0.8 }}>גרור למפה או לפ"מ פעילים</div>
        </div>,
        document.body
      )}
      {editingAlt && (
        <HandwritingOverlay
          onCancel={() => setEditingAlt(false)}
          onComplete={(val: string) => { const n = normalizeAlt(val); setEditingAlt(false); if (onUpdateStripField) onUpdateStripField(String(transfer.strip_id), 'alt', n); }}
          anchorRect={anchorRect}
        />
      )}
    </>
  );
};

// --- תפריט קליק ימני ---
const ContextMenu = ({ x, y, neighbors, onSelect, onClose, extraActions = [] }: { 
  x: number; 
  y: number; 
  neighbors: any[]; 
  onSelect: (sectorId: number) => void; 
  onClose: () => void;
  extraActions?: { label: string; onClick: () => void }[];
}) => {
  useEffect(() => {
    const handleClick = () => onClose();
    window.addEventListener('click', handleClick);
    return () => window.removeEventListener('click', handleClick);
  }, [onClose]);

  return createPortal(
    <div 
      style={{
        position: 'fixed',
        left: x,
        top: y > window.innerHeight - 300 ? 'auto' : y,
        bottom: y > window.innerHeight - 300 ? (window.innerHeight - y) : 'auto',
        background: 'white',
        border: '1px solid #cbd5e1',
        borderRadius: '8px',
        boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
        zIndex: 10000,
        minWidth: '150px',
        direction: 'rtl',
        overflow: 'hidden'
      }}
      onClick={(e) => e.stopPropagation()}
    >
      <div style={{ padding: '8px 12px', background: '#f1f5f9', borderBottom: '1px solid #e2e8f0', fontSize: '12px', fontWeight: 'bold', color: '#475569' }}>
        העבר לנקודת העברה:
      </div>
      {neighbors.length === 0 ? (
        <div style={{ padding: '10px 12px', fontSize: '12px', color: '#94a3b8' }}>אין נקודות העברה נוספות</div>
      ) : (
        neighbors.map(n => (
          <button
            key={n.id}
            onClick={() => onSelect(n.id)}
            style={{
              width: '100%',
              padding: '10px 12px',
              border: 'none',
              background: 'white',
              cursor: 'pointer',
              textAlign: 'right',
              fontSize: '13px',
              borderBottom: '1px solid #f1f5f9'
            }}
            onMouseEnter={(e) => e.currentTarget.style.background = '#dbeafe'}
            onMouseLeave={(e) => e.currentTarget.style.background = 'white'}
          >
            {n.label_he || n.name}
          </button>
        ))
      )}
      {extraActions.length > 0 && (
        <>
          <div style={{ padding: '6px 12px', background: '#f1f5f9', borderTop: '1px solid #e2e8f0', fontSize: '11px', fontWeight: 'bold', color: '#475569' }}>
            ספרורים:
          </div>
          {extraActions.map((action, i) => (
            <button
              key={i}
              onClick={() => { action.onClick(); onClose(); }}
              style={{ width: '100%', padding: '9px 12px', border: 'none', background: 'white', cursor: 'pointer', textAlign: 'right', fontSize: '12px', borderBottom: '1px solid #f1f5f9', color: '#dc2626' }}
              onMouseEnter={(e) => e.currentTarget.style.background = '#fee2e2'}
              onMouseLeave={(e) => e.currentTarget.style.background = 'white'}
            >
              {action.label}
            </button>
          ))}
        </>
      )}
    </div>,
    document.body
  );
};

// --- Draggable Map Marker component ---
const DraggableMapMarker = ({ 
  marker, 
  onMove, 
  onRemove, 
  onRename,
  strips,
  onTransfer,
  outgoingTransfers,
  incomingTransfers,
  onCancelTransfer,
  onAcceptTransfer,
  onRejectTransfer,
  onAcceptToMap,
  notes,
  onUpdateNotes,
  zoom = 1,
  pan,
  conflictAltDelta = 0,
  crossSectorConflictIds,
  onUpdateStripField,
  lightMode = false,
}: { 
  marker: { sectorId: number; x: number; y: number; subLabel?: string; label: string };
  onMove: (x: number, y: number) => void;
  onRemove: () => void;
  onRename: (newLabel: string) => void;
  strips: any[];
  onTransfer: (stripId: string, sectorId: number, x: number, y: number, subLabel?: string) => void;
  outgoingTransfers: any[];
  incomingTransfers: any[];
  onCancelTransfer: (transferId: string) => void;
  onAcceptTransfer: (transferId: string) => void;
  onRejectTransfer: (transferId: string) => void;
  onAcceptToMap: (transferId: string, x: number, y: number) => void;
  notes?: string;
  onUpdateNotes?: (sectorId: number, notes: string) => void;
  zoom?: number;
  pan?: { x: number; y: number };
  conflictAltDelta?: number;
  crossSectorConflictIds?: Set<string>;
  onUpdateStripField?: (stripId: string, field: string, value: string) => void;
  lightMode?: boolean;
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [dragPos, setDragPos] = useState({ x: marker.x, y: marker.y });
  const [showMenu, setShowMenu] = useState(false);
  const [editingName, setEditingName] = useState(false);
  const [editingNotes, setEditingNotes] = useState(false);
  const [tempName, setTempName] = useState(marker.subLabel || '');
  const [tempNotes, setTempNotes] = useState(notes || '');
  const [editingAltId, setEditingAltId] = useState<string | null>(null);
  const [editingAltVal, setEditingAltVal] = useState('');
  const [editingAltAnchor, setEditingAltAnchor] = useState<DOMRect | null>(null);
  const [isTransferMode, setIsTransferMode] = useState(false);
  const startPosRef = useRef({ x: 0, y: 0 });
  const dragStartClientRef = useRef({ x: 0, y: 0 });

  // Sync tempNotes when notes prop changes
  useEffect(() => {
    setTempNotes(notes || '');
  }, [notes]);

  const handlePointerDown = (e: React.PointerEvent) => {
    if ((e.target as HTMLElement).tagName === 'BUTTON') return;
    e.preventDefault();
    e.stopPropagation();
    dragStartClientRef.current = { x: e.clientX, y: e.clientY };
    startPosRef.current = { x: e.clientX - marker.x, y: e.clientY - marker.y };
    setDragPos({ x: marker.x, y: marker.y });
    setIsDragging(true);
  };

  useEffect(() => {
    if (!isDragging) return;

    const lastPos = { x: marker.x, y: marker.y };
    let hasDragged = false;

    const screenToMap = (clientX: number, clientY: number, rect: DOMRect) => {
      const cx = rect.left + rect.width / 2;
      const cy = rect.top + rect.height / 2;
      const px = (pan?.x ?? 0);
      const py = (pan?.y ?? 0);
      const z = zoom || 1;
      const rawX = (clientX - cx - px) / z + rect.width / 2;
      const rawY = (clientY - cy - py) / z + rect.height / 2;
      return { rawX, rawY };
    };

    const handleMoveEvent = (e: PointerEvent) => {
      const dx = e.clientX - dragStartClientRef.current.x;
      const dy = e.clientY - dragStartClientRef.current.y;
      if (Math.abs(dx) > 6 || Math.abs(dy) > 6) hasDragged = true;
      const mapArea = document.getElementById('map-area');
      if (mapArea) {
        const rect = mapArea.getBoundingClientRect();
        const { rawX, rawY } = screenToMap(e.clientX, e.clientY, rect);
        lastPos.x = rawX;
        lastPos.y = rawY;
        setDragPos({ x: rawX, y: rawY });
      }
    };

    const drop = (clientX: number, clientY: number) => {
      setIsDragging(false);
      const mapArea = document.getElementById('map-area');
      if (mapArea) {
        const rect = mapArea.getBoundingClientRect();
        const { rawX, rawY } = screenToMap(clientX, clientY, rect);
        const x = Math.max(100, Math.min(rect.width - 100, rawX));
        const y = Math.max(40, Math.min(rect.height - 50, rawY));
        onMove(x, y);
      }
    };

    const handleUp = (e: PointerEvent) => {
      if (!hasDragged) {
        // Tap on header → toggle transfer mode
        setIsDragging(false);
        setIsTransferMode(v => !v);
        window.removeEventListener('pointermove', handleMoveEvent);
        window.removeEventListener('pointerup', handleUp);
        window.removeEventListener('pointercancel', handleCancel);
        return;
      }
      drop(e.clientX, e.clientY);
    };
    const handleCancel = () => {
      setIsDragging(false);
      if (!hasDragged) return;
      const mapArea = document.getElementById('map-area');
      if (mapArea) {
        const rect = mapArea.getBoundingClientRect();
        const x = Math.max(100, Math.min(rect.width - 100, lastPos.x));
        const y = Math.max(40, Math.min(rect.height - 50, lastPos.y));
        onMove(x, y);
      }
    };

    window.addEventListener('pointermove', handleMoveEvent);
    window.addEventListener('pointerup', handleUp);
    window.addEventListener('pointercancel', handleCancel);
    return () => {
      window.removeEventListener('pointermove', handleMoveEvent);
      window.removeEventListener('pointerup', handleUp);
      window.removeEventListener('pointercancel', handleCancel);
    };
  }, [isDragging, onMove]);

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    setTempName(marker.subLabel || marker.label);
    setEditingName(true);
  };

  const handleSaveName = () => {
    onRename(tempName);
    setEditingName(false);
  };

  const availableStrips = strips.filter((s: any) => !s.onMap && s.status !== 'pending_transfer');
  
  // Filter outgoing transfers for this marker (outgoing: to_sector_id = neighbor sector)
  const markerOutgoing = (outgoingTransfers || []).filter((t: any) => 
    Number(t.to_sector_id) === Number(marker.sectorId) && 
    (marker.subLabel ? t.sub_sector_label === marker.subLabel : !t.sub_sector_label)
  );
  
  // Filter incoming transfers for this marker (incoming: from_sector_id = neighbor sector)
  const markerIncoming = (incomingTransfers || []).filter((t: any) => 
    Number(t.from_sector_id) === Number(marker.sectorId) && 
    (marker.subLabel ? t.sub_sector_label === marker.subLabel : !t.sub_sector_label)
  );
  
  const hasTransfers = markerOutgoing.length > 0 || markerIncoming.length > 0;

  // Altitude conflict detection
  const parseAlt = (alt: string | null | undefined): number | null => {
    if (!alt) return null;
    const m = alt.match(/\d+/);
    return m ? parseInt(m[0]) : null;
  };
  const markerConflictIds = new Set<string>();
  // conflictAltDelta is in feet; altitudes are in hundreds → multiply diff by 100
  if (conflictAltDelta > 0) {
    // Compare outgoing × incoming (cross-direction); skip if same transfer appears in both
    for (const out of markerOutgoing) {
      const outAlt = parseAlt(out.alt);
      if (outAlt == null) continue;
      for (const inc of markerIncoming) {
        if (String(inc.id) === String(out.id)) continue; // same record in both arrays → skip
        const incAlt = parseAlt(inc.alt);
        if (incAlt == null) continue;
        if (Math.abs(outAlt - incAlt) * 100 <= conflictAltDelta) {
          markerConflictIds.add(String(out.id));
          markerConflictIds.add(String(inc.id));
        }
      }
    }
    // Compare outgoing × outgoing (same-direction — two strips going to same marker at similar altitude)
    for (let i = 0; i < markerOutgoing.length; i++) {
      const altA = parseAlt(markerOutgoing[i].alt);
      if (altA == null) continue;
      for (let j = i + 1; j < markerOutgoing.length; j++) {
        const altB = parseAlt(markerOutgoing[j].alt);
        if (altB == null) continue;
        if (Math.abs(altA - altB) * 100 <= conflictAltDelta) {
          markerConflictIds.add(String(markerOutgoing[i].id));
          markerConflictIds.add(String(markerOutgoing[j].id));
        }
      }
    }
    // Compare incoming × incoming (same-direction)
    for (let i = 0; i < markerIncoming.length; i++) {
      const altA = parseAlt(markerIncoming[i].alt);
      if (altA == null) continue;
      for (let j = i + 1; j < markerIncoming.length; j++) {
        const altB = parseAlt(markerIncoming[j].alt);
        if (altB == null) continue;
        if (Math.abs(altA - altB) * 100 <= conflictAltDelta) {
          markerConflictIds.add(String(markerIncoming[i].id));
          markerConflictIds.add(String(markerIncoming[j].id));
        }
      }
    }
  }
  // Merge explicit conflicts from parent if any
  if (crossSectorConflictIds) {
    const markerTransferIds = new Set([...markerOutgoing, ...markerIncoming].map((t: any) => String(t.id)));
    crossSectorConflictIds.forEach(id => {
      if (markerTransferIds.has(id)) markerConflictIds.add(id);
    });
  }
  const markerHasConflict = markerConflictIds.size > 0;

  return (
    <div
      className="marker-drop-zone"
      data-marker-sector={marker.sectorId}
      data-marker-sublabel={marker.subLabel || ''}
      style={{
        position: 'absolute',
        left: (isDragging ? dragPos.x : marker.x) - 100,
        top: (isDragging ? dragPos.y : marker.y) - 40,
        width: '200px',
        background: '#3b82f6',
        borderRadius: '8px',
        boxShadow: markerHasConflict ? '0 0 0 2px #ef4444, 0 4px 12px rgba(0,0,0,0.4)' : '0 4px 12px rgba(0,0,0,0.3)',
        zIndex: 50,
        userSelect: 'none',
        direction: 'rtl',
        overflow: 'hidden',
        transform: `scale(${1/zoom})`,
        transformOrigin: 'center center'
      }}
      onContextMenu={handleContextMenu}
    >
      <div 
        onPointerDown={handlePointerDown}
        title={isTransferMode ? 'מוד מעבר פעיל — לחץ לביטול' : 'לחץ לפתיחת מוד מעבר / גרור להזזה'}
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          padding: '6px 8px',
          background: isTransferMode ? '#065f46' : markerHasConflict ? '#7f1d1d' : '#2563eb',
          cursor: isDragging ? 'grabbing' : 'grab',
          borderBottom: isTransferMode ? '2px solid #10b981' : undefined,
        }}
      >
        <span style={{ color: 'white', fontSize: '12px', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '4px' }}>
          {isTransferMode && <span style={{ fontSize: '10px', background: '#10b981', borderRadius: '3px', padding: '1px 4px' }}>↔ מעבר</span>}
          {marker.label}
          {marker.subLabel && <span style={{ fontSize: '10px', opacity: 0.8 }}> ({marker.subLabel})</span>}
          {markerHasConflict && <span style={{ fontSize: '9px', background: '#ef4444', borderRadius: '3px', padding: '1px 4px', whiteSpace: 'nowrap' }}>⚠️ קונפליקט גובה</span>}
        </span>
        <div style={{ display: 'flex', gap: '4px' }}>
          <button
            onClick={(e) => { e.stopPropagation(); setShowMenu(!showMenu); }}
            onPointerDown={(e) => e.stopPropagation()}
            style={{
              background: '#1d4ed8',
              border: 'none',
              color: 'white',
              width: '20px',
              height: '20px',
              borderRadius: '50%',
              cursor: 'pointer',
              fontSize: '14px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}
          >
            +
          </button>
          <button
            onClick={(e) => { e.stopPropagation(); onRemove(); }}
            onPointerDown={(e) => e.stopPropagation()}
            style={{
              background: '#dc2626',
              border: 'none',
              color: 'white',
              width: '20px',
              height: '20px',
              borderRadius: '50%',
              cursor: 'pointer',
              fontSize: '14px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}
          >
            ×
          </button>
        </div>
      </div>
      
      {/* Two-column layout for העברה/קבלה - with drop zone for strip transfers */}
      <div 
        className="marker-drop-zone"
        data-marker-sector={marker.sectorId}
        data-marker-sublabel={marker.subLabel || ''}
        style={{ display: 'flex', background: lightMode ? '#f1f5f9' : '#0f172a', borderTop: `1px solid ${lightMode ? '#cbd5e1' : '#334155'}` }}
      >
        {/* העברה - Outgoing */}
        <div style={{ flex: 1, borderLeft: `1px solid ${lightMode ? '#cbd5e1' : '#334155'}`, padding: '6px', minHeight: '60px' }}>
          <div style={{ fontSize: '10px', color: lightMode ? '#b45309' : '#f59e0b', fontWeight: 'bold', marginBottom: '4px', textAlign: 'center' }}>
            העברה: ({markerOutgoing.length})
          </div>
          {markerOutgoing.map((t: any) => (
            <OutgoingTransferCard
              key={t.id}
              t={t}
              isConflict={markerConflictIds.has(String(t.id))}
              onCancel={onCancelTransfer}
              onUpdateStripField={onUpdateStripField}
              lightMode={lightMode}
            />
          ))}
        </div>
        
        {/* קבלה - Incoming */}
        <div style={{ flex: 1, padding: '6px', minHeight: '60px' }}>
          <div style={{ fontSize: '10px', color: lightMode ? '#15803d' : '#22c55e', fontWeight: 'bold', marginBottom: '4px', textAlign: 'center' }}>
            קבלה ({markerIncoming.length})
          </div>
          {markerIncoming.map((t: any) => {
            const isConflict = markerConflictIds.has(String(t.id));
            const sq = getTransferSq(t);
            return (
            <div key={t.id} className={isConflict ? 'alt-conflict-flash' : ''} style={{ 
              background: isConflict ? '#7f1d1d' : '#dcfce7', 
              border: `1px solid ${isConflict ? '#ef4444' : '#22c55e'}`,
              borderRadius: '4px',
              padding: '5px',
              marginBottom: '4px',
              direction: 'rtl'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '4px', marginBottom: '3px' }}>
                <div style={{ flex: 1, overflow: 'hidden' }}>
                  <div style={{ fontWeight: 'bold', color: isConflict ? '#fca5a5' : '#166534', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', fontSize: '11px' }}>
                    {isConflict && '⚠ '}{getTransferLabel(t)}
                  </div>
                  {sq && <div style={{ fontSize: '9px', color: isConflict ? '#fca5a5' : '#15803d', marginTop: '1px', opacity: 0.85 }}>{sq}</div>}
                </div>
                <span
                  title={onUpdateStripField ? 'לחץ לעדכון גובה' : undefined}
                  onPointerDown={e => { if (onUpdateStripField) { e.stopPropagation(); setEditingAltVal(t.alt || ''); setEditingAltId(String(t.id)); setEditingAltAnchor(e.currentTarget.getBoundingClientRect()); } }}
                  style={{ fontSize: '14px', fontWeight: 'bold', color: isConflict ? '#fca5a5' : '#166534', background: isConflict ? '#450a0a' : '#bbf7d0', padding: '1px 6px', borderRadius: '4px', cursor: onUpdateStripField ? 'pointer' : 'default', flexShrink: 0, letterSpacing: '0.5px', border: onUpdateStripField ? `1px dashed ${isConflict ? '#ef4444' : '#22c55e'}` : 'none' }}
                >
                  {t.alt ? normalizeAlt(t.alt) : '—'}
                </span>
              </div>
              <div style={{ display: 'flex', gap: '2px' }}>
                <button
                  onClick={(e) => { e.stopPropagation(); onAcceptTransfer(t.id); }}
                  style={{ flex: 1, padding: '2px', background: '#22c55e', color: 'white', border: 'none', borderRadius: '2px', fontSize: '8px', cursor: 'pointer' }}
                >קבל</button>
                <button
                  onClick={(e) => { e.stopPropagation(); onRejectTransfer(t.id); }}
                  style={{ flex: 1, padding: '2px', background: '#dc2626', color: 'white', border: 'none', borderRadius: '2px', fontSize: '8px', cursor: 'pointer' }}
                >דחה</button>
              </div>
            </div>
          ); })}
        </div>
      </div>
      
      {/* Notes section */}
      {(notes || editingNotes) && (
        <div style={{ background: lightMode ? '#e2e8f0' : '#1e293b', padding: '6px', borderTop: `1px solid ${lightMode ? '#cbd5e1' : '#334155'}` }}>
          {editingNotes ? (
            <div onClick={(e) => e.stopPropagation()} onPointerDown={(e) => e.stopPropagation()}>
              <div style={{ display: 'flex', alignItems: 'flex-start', gap: '4px' }}>
                <textarea
                  value={tempNotes}
                  onChange={(e) => setTempNotes(e.target.value)}
                  style={{ flex: 1, padding: '4px', border: `1px solid ${lightMode ? '#94a3b8' : '#475569'}`, borderRadius: '4px', background: lightMode ? 'white' : '#0f172a', color: lightMode ? '#1e293b' : 'white', fontSize: '10px', resize: 'none', boxSizing: 'border-box' }}
                  rows={2}
                  autoFocus
                />
                <VKTrigger value={tempNotes} onChange={v => setTempNotes(v)} mode="full" label="הערה" size={14} />
              </div>
              <div style={{ display: 'flex', gap: '4px', marginTop: '4px' }}>
                <button 
                  onClick={() => { 
                    if (onUpdateNotes) onUpdateNotes(marker.sectorId, tempNotes);
                    setEditingNotes(false);
                  }} 
                  style={{ flex: 1, padding: '3px', background: '#10b981', color: 'white', border: 'none', borderRadius: '3px', fontSize: '9px', cursor: 'pointer' }}
                >
                  שמור
                </button>
                <button 
                  onClick={() => { setTempNotes(notes || ''); setEditingNotes(false); }} 
                  style={{ flex: 1, padding: '3px', background: '#64748b', color: 'white', border: 'none', borderRadius: '3px', fontSize: '9px', cursor: 'pointer' }}
                >
                  ביטול
                </button>
              </div>
            </div>
          ) : (
            <div 
              onClick={(e) => { e.stopPropagation(); setEditingNotes(true); }}
              style={{ fontSize: '9px', color: lightMode ? '#334155' : '#94a3b8', cursor: 'pointer', fontWeight: lightMode ? 'bold' : undefined }}
              title="לחץ לעריכה"
            >
              {(() => { const np = parseNoteValue(notes || ''); return (<>
                {np.text && <span>📝 {np.text}</span>}
                {np.hw && <img src={np.hw} alt="כתב יד" style={{ maxHeight: '28px', display: 'block', marginTop: '2px', maxWidth: '100%' }} />}
              </>); })()}
            </div>
          )}
        </div>
      )}
      
      {/* Add notes button if no notes */}
      {!notes && !editingNotes && onUpdateNotes && (
        <div style={{ background: lightMode ? '#e2e8f0' : '#1e293b', padding: '4px', borderTop: `1px solid ${lightMode ? '#cbd5e1' : '#334155'}`, textAlign: 'center' }}>
          <button
            onClick={(e) => { e.stopPropagation(); setEditingNotes(true); }}
            onPointerDown={(e) => e.stopPropagation()}
            style={{ background: 'transparent', border: 'none', color: lightMode ? '#475569' : '#64748b', fontSize: '9px', cursor: 'pointer', fontWeight: 'bold' }}
          >
            + הוסף הערה
          </button>
        </div>
      )}

      {showMenu && availableStrips.length > 0 && (
        <div
          onClick={(e) => e.stopPropagation()}
          onPointerDown={(e) => e.stopPropagation()}
          style={{
            position: 'absolute',
            top: '100%',
            right: 0,
            background: 'white',
            border: '1px solid #e2e8f0',
            borderRadius: '4px',
            boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
            padding: '4px',
            minWidth: '120px',
            zIndex: 100
          }}
        >
          <div style={{ fontSize: '10px', color: '#64748b', padding: '4px', borderBottom: '1px solid #e2e8f0' }}>
            בחר פמם להעברה:
          </div>
          {availableStrips.map((s: any) => (
            <button
              key={s.id}
              onClick={() => {
                onTransfer(s.id, marker.sectorId, marker.x, marker.y, marker.subLabel);
                setShowMenu(false);
              }}
              style={{
                display: 'block',
                width: '100%',
                padding: '6px 8px',
                background: 'transparent',
                border: 'none',
                textAlign: 'right',
                cursor: 'pointer',
                fontSize: '11px',
                color: '#1e293b'
              }}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span>{s.callsign}</span>
                <span style={{ background: '#3b82f6', color: 'white', padding: '1px 4px', borderRadius: '3px', fontSize: '9px' }}>{s.sq}</span>
              </div>
              <div style={{ fontSize: '9px', color: '#64748b' }}>גובה: {normalizeAlt(s.alt || '')}</div>
            </button>
          ))}
        </div>
      )}

      {editingName && (
        <div
          onClick={(e) => e.stopPropagation()}
          onPointerDown={(e) => e.stopPropagation()}
          style={{
            position: 'absolute',
            top: '100%',
            right: 0,
            background: 'white',
            border: '1px solid #e2e8f0',
            borderRadius: '4px',
            boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
            padding: '8px',
            zIndex: 100
          }}
        >
          <input
            type="text"
            value={tempName}
            onChange={(e) => setTempName(e.target.value)}
            style={{ padding: '4px', border: '1px solid #cbd5e1', borderRadius: '4px', width: '100px', fontSize: '11px' }}
            autoFocus
          />
          <div style={{ display: 'flex', gap: '4px', marginTop: '6px' }}>
            <button onClick={handleSaveName} style={{ flex: 1, padding: '4px', background: '#10b981', color: 'white', border: 'none', borderRadius: '4px', fontSize: '10px', cursor: 'pointer' }}>
              שמור
            </button>
            <button onClick={() => setEditingName(false)} style={{ flex: 1, padding: '4px', background: '#64748b', color: 'white', border: 'none', borderRadius: '4px', fontSize: '10px', cursor: 'pointer' }}>
              ביטול
            </button>
          </div>
        </div>
      )}
      {editingAltId !== null && (
        <HandwritingOverlay
          onCancel={() => setEditingAltId(null)}
          onComplete={(val: string) => { const n = normalizeAlt(val); setEditingAltId(null); if (onUpdateStripField) onUpdateStripField(editingAltId, 'alt', n); }}
          anchorRect={editingAltAnchor}
        />
      )}
    </div>
  );
};

// --- רכיב העברה נכנסת ניתנת לגרירה ---
const DraggableIncomingTransfer = ({ transfer, onAccept, onReject, onAcceptToMap }: { 
  transfer: any; 
  onAccept: (id: string) => void; 
  onReject: (id: string) => void;
  onAcceptToMap: (id: string, x: number, y: number) => void;
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [dragPos, setDragPos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const startPosRef = useRef({ x: 0, y: 0 });

  const handlePointerDown = (e: React.PointerEvent) => {
    e.preventDefault();
    e.stopPropagation();
    (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
    const rect = containerRef.current?.getBoundingClientRect();
    if (rect) {
      startPosRef.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
      setDragPos({ x: e.clientX - startPosRef.current.x, y: e.clientY - startPosRef.current.y });
      setIsDragging(true);
    }
  };

  useEffect(() => {
    if (!isDragging) return;

    const handlePointerMove = (e: PointerEvent) => {
      setDragPos({ 
        x: e.clientX - startPosRef.current.x, 
        y: e.clientY - startPosRef.current.y 
      });
    };

    const handlePointerUp = (e: PointerEvent) => {
      setIsDragging(false);
      const mapArea = document.getElementById('map-area');
      const sidebar = document.getElementById('sidebar-area');
      
      if (mapArea && sidebar) {
        const mapRect = mapArea.getBoundingClientRect();
        const sidebarRect = sidebar.getBoundingClientRect();
        const dropX = e.clientX;
        const dropY = e.clientY;

        if (dropX >= sidebarRect.left && dropX <= sidebarRect.right &&
            dropY >= sidebarRect.top && dropY <= sidebarRect.bottom) {
          onAccept(transfer.id);
        }
        else if (dropX >= mapRect.left && dropX <= mapRect.right &&
            dropY >= mapRect.top && dropY <= mapRect.bottom) {
          const x = dropX - mapRect.left;
          const y = dropY - mapRect.top;
          onAcceptToMap(transfer.id, x, y);
        }
      }
    };

    window.addEventListener('pointermove', handlePointerMove);
    window.addEventListener('pointerup', handlePointerUp);
    return () => {
      window.removeEventListener('pointermove', handlePointerMove);
      window.removeEventListener('pointerup', handlePointerUp);
    };
  }, [isDragging, transfer.id, onAccept, onAcceptToMap]);

  const content = (
    <>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <span style={{ fontWeight: 'bold', fontSize: '12px' }}>{getFormationDisplayName(transfer)}</span>
        <span style={{ fontSize: '10px', background: '#3b82f6', padding: '2px 6px', borderRadius: '4px' }}>{transfer.sq}</span>
      </div>
      {(!transfer.sq && transfer.squadron) && <div style={{ fontSize: '10px', color: '#a78bfa', marginTop: '2px' }}>טייסת: {transfer.squadron}</div>}
      <div style={{ display: 'flex', gap: '8px', fontSize: '10px', color: '#94a3b8', marginTop: '4px' }}>
        <span>גובה: {transfer.alt}</span>
      </div>
      <div style={{ fontSize: '10px', color: '#94a3b8', marginTop: '4px' }}>
        מ: {transfer.from_sector_label}
        {transfer.sub_sector_label && <span style={{ color: '#60a5fa' }}> ({transfer.sub_sector_label})</span>}
      </div>
    </>
  );

  const baseStyle: React.CSSProperties = {
    background: '#334155', 
    padding: '8px', 
    borderRadius: '4px', 
    marginBottom: '8px',
    cursor: 'grab',
    touchAction: 'none'
  };

  if (isDragging) {
    return (
      <>
        <div ref={containerRef} style={{ ...baseStyle, opacity: 0.3 }}>{content}</div>
        {createPortal(
          <div style={{ 
            ...baseStyle, 
            position: 'fixed', 
            left: dragPos.x, 
            top: dragPos.y, 
            zIndex: 9999,
            pointerEvents: 'none',
            boxShadow: '0 8px 20px rgba(0,0,0,0.3)',
            transform: 'rotate(2deg)',
            width: 180
          }}>
            {content}
            <div style={{ fontSize: '9px', color: '#10b981', marginTop: '6px', textAlign: 'center' }}>
              גרור למפה או לממתינים
            </div>
          </div>,
          document.body
        )}
      </>
    );
  }

  return (
    <div ref={containerRef} style={baseStyle} onPointerDown={handlePointerDown}>
      {content}
      <div style={{ fontSize: '9px', color: '#64748b', marginTop: '4px', textAlign: 'center' }}>
        גרור למפה או לממתינים להצבה
      </div>
      <div style={{ display: 'flex', gap: '4px', marginTop: '6px' }}>
        <button onClick={(e) => { e.stopPropagation(); onAccept(transfer.id); }} style={{ flex: 1, padding: '4px', background: '#10b981', color: 'white', border: 'none', borderRadius: '4px', fontSize: '10px', cursor: 'pointer' }}>
          לממתינים
        </button>
        <button onClick={(e) => { e.stopPropagation(); onReject(transfer.id); }} style={{ flex: 1, padding: '4px', background: '#ef4444', color: 'white', border: 'none', borderRadius: '4px', fontSize: '10px', cursor: 'pointer' }}>
          דחה
        </button>
      </div>
    </div>
  );
};

// Singleton — only one strip details popup open at a time
let _activeStripDetailsCloser: (() => void) | null = null;

// --- רכיב פ"מ (Strip) ---
const Strip = ({ s, onMove, onUpdate, neighbors, onTransfer, onToggleAirborne, onUpdateNotes, onUpdateDetails, zoom = 1, pan = null, serials = [], serialSelections = [], onSerialSelect, onSerialDismiss, onSerialRemove, allBlockSpaces = [], allBlocks = [], allBlockTables = [], allWorkstationPresets = [], activeBlockTableId = null, mapConflictIds = null, viewerPresetId = null, lightMode = false }: any) => {
  const controls = useDragControls();
  const [edit, setEdit] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [dragPos, setDragPos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const altRef = useRef<HTMLDivElement>(null);
  const startPosRef = useRef({ x: 0, y: 0 });
  const bodyTouchRef = useRef<{ startX: number; startY: number; cleanup: () => void } | null>(null);
  const bodyDragReadyRef = useRef(false);
  const [bodyDragReady, setBodyDragReady] = useState(false);
  const [contextMenu, setContextMenu] = useState<{x: number; y: number} | null>(null);
  const [serialRowMenu, setSerialRowMenu] = useState<{x: number; y: number; station: string; latestSerialId: number; specificSerialId?: number} | null>(null);
  const [expandedStationHistory, setExpandedStationHistory] = useState<string | null>(null);
  const [serialViewPopup, setSerialViewPopup] = useState<{x: number; y: number; station: string} | null>(null);
  const [anchorRect, setAnchorRect] = useState<DOMRect | null>(null);
  const [editingNotes, setEditingNotes] = useState(false);
  const [tempNotes, setTempNotes] = useState(s.notes || '');
  const [showDetails, setShowDetails] = useState(false);
  const [detailsPos, setDetailsPos] = useState<{left: number; top: number}>({ left: 0, top: 0 });
  const [detailsData, setDetailsData] = useState({
    weapons: (s.weapons || []) as {type: string; quantity: string}[],
    targets: (s.targets || []) as {name: string; aim_point: string}[],
    systems: (s.systems || []) as {name: string}[],
    shkadia: s.shkadia || ''
  });
  const [localTakeoffTime, setLocalTakeoffTime] = useState<string>(() => {
    if (!s.takeoff_time) return '';
    const d = new Date(s.takeoff_time);
    if (isNaN(d.getTime())) return '';
    const pad = (n: number) => n.toString().padStart(2, '0');
    return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
  });
  const [localErka, setLocalErka] = useState(s.erka || '');
  const [localKoteret, setLocalKoteret] = useState(s.koteret || '');
  const [localMivtza, setLocalMivtza] = useState(s.mivtza || '');
  const [localBlockSpaceId, setLocalBlockSpaceId] = useState(s.block_space_id ? String(s.block_space_id) : '');
  const blockSpaceSavingRef = React.useRef(false);
  const [blockDeviation, setBlockDeviation] = useState(s.block_deviation || false);

  useEffect(() => {
    if (!blockSpaceSavingRef.current) {
      setLocalBlockSpaceId(s.block_space_id ? String(s.block_space_id) : '');
    }
  }, [s.block_space_id]);

  useEffect(() => {
    setDetailsData({
      weapons: s.weapons || [],
      targets: s.targets || [],
      systems: s.systems || [],
      shkadia: s.shkadia || ''
    });
  }, [s.weapons, s.targets, s.systems, s.shkadia]);

  useEffect(() => {
    if (s.takeoff_time) {
      const d = new Date(s.takeoff_time);
      if (!isNaN(d.getTime())) {
        const pad = (n: number) => n.toString().padStart(2, '0');
        setLocalTakeoffTime(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`);
      }
    }
  }, [s.takeoff_time]);

  const saveDetails = (updated: typeof detailsData) => {
    setDetailsData(updated);
    if (onUpdateDetails) onUpdateDetails(s.id, updated);
  };

  const hasDetails = (s.weapons && s.weapons.length > 0) || (s.targets && s.targets.length > 0) || (s.systems && s.systems.length > 0) || s.shkadia;

  // Block deviation detection (uses shared helper)
  const isBlockDeviation = React.useMemo(() => computeBlockDeviation(s, allBlocks, allBlockTables, activeBlockTableId, viewerPresetId),
    [s.alt, s.workstation_preset_id, allBlocks, activeBlockTableId]);

  // Altitude conflict with another map strip
  const isAltConflict = mapConflictIds != null && mapConflictIds.has(String(s.id));

  // Sync local blockDeviation state when prop changes (e.g. after polling)
  useEffect(() => {
    setBlockDeviation(s.block_deviation || false);
  }, [s.block_deviation]);

  // Auto-clear acknowledged deviation when altitude is fixed (no more deviation).
  // Guard: only runs when blocks are actually loaded — prevents premature clear during page refresh
  // when allBlocks hasn't populated yet and computeBlockDeviation temporarily returns false.
  useEffect(() => {
    if (!isBlockDeviation && blockDeviation && (allBlocks.length > 0 || allBlockTables.length > 0)) {
      setBlockDeviation(false);
      fetch(`${API_URL}/strips/${s.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ block_deviation: false }) }).catch(() => {});
    }
  }, [isBlockDeviation, blockDeviation, allBlocks.length, allBlockTables.length]);

  // Sync tempNotes when notes prop changes
  useEffect(() => {
    setTempNotes(s.notes || '');
  }, [s.notes]);

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    setContextMenu({ x: e.clientX, y: e.clientY });
  };

  const handleEditClick = () => {
    if (altRef.current) {
      setAnchorRect(altRef.current.getBoundingClientRect());
    }
    setEdit(true);
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    e.preventDefault();
    e.stopPropagation();
    // Do NOT call setPointerCapture: it redirects elementsFromPoint inside CSS-transformed
    // containers (contain:paint + scale) and can cause pointercancel on re-render.
    // Instead, attach listeners immediately on window — no race with useEffect.
    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return;
    startPosRef.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
    const pointerStartX = e.clientX;
    const pointerStartY = e.clientY;
    let dragActivated = false;

    // Use getBoundingClientRect for both markers and neighbor panels — reliable through CSS transforms.
    // elementsFromPoint can be unreliable inside contain:paint contexts and CSS-scaled containers.
    const findMarker = (cx: number, cy: number): Element | null => {
      for (const el of Array.from(document.querySelectorAll('.marker-drop-zone[data-marker-sector]'))) {
        const r = el.getBoundingClientRect();
        if (cx >= r.left && cx <= r.right && cy >= r.top && cy <= r.bottom) return el;
      }
      return null;
    };
    const findNeighborPanel = (cx: number, cy: number): Element | null => {
      for (const el of Array.from(document.querySelectorAll('.neighbor-drop-zone[data-sector-id]'))) {
        const r = el.getBoundingClientRect();
        if (cx >= r.left && cx <= r.right && cy >= r.top && cy <= r.bottom) return el;
      }
      return null;
    };
    const clearHighlights = () => {
      document.querySelectorAll('.marker-drop-zone.strip-drag-active, .neighbor-drop-zone.strip-drag-active').forEach(el => el.classList.remove('strip-drag-active'));
    };

    // Helper: convert viewport coords to map-container coords (accounts for zoom + pan with center origin)
    // pan is passed as prop: { x, y } translation applied to the map container before scale.
    const viewportToMapCoords = (vx: number, vy: number, mapRect: DOMRect): { x: number; y: number } => {
      const z = zoom || 1;
      const px = pan?.x ?? 0;
      const py = pan?.y ?? 0;
      const cw = mapRect.width;
      const ch = mapRect.height;
      return {
        x: (vx - mapRect.left - cw / 2 - px) / z + cw / 2,
        y: (vy - mapRect.top  - ch / 2 - py) / z + ch / 2,
      };
    };

    // Track last pointer position — used in handleDragCancel fallback (tablet pointercancel)
    let lastCx = e.clientX;
    let lastCy = e.clientY;

    const handleDragMove = (ev: PointerEvent) => {
      lastCx = ev.clientX;
      lastCy = ev.clientY;
      if (!dragActivated) {
        if (Math.abs(ev.clientX - pointerStartX) < 5 && Math.abs(ev.clientY - pointerStartY) < 5) return;
        dragActivated = true;
        setIsDragging(true);
      }
      setDragPos({ x: ev.clientX - startPosRef.current.x, y: ev.clientY - startPosRef.current.y });
      clearHighlights();
      const m = findMarker(ev.clientX, ev.clientY);
      if (m) { m.classList.add('strip-drag-active'); return; }
      const n = findNeighborPanel(ev.clientX, ev.clientY);
      if (n) n.classList.add('strip-drag-active');
    };

    const performDrop = (cx: number, cy: number) => {
      const mapArea = document.getElementById('map-area');
      const sidebar = document.getElementById('sidebar-area');

      // 1. נקודת העברה (neighbor panel) — getBoundingClientRect, אמין דרך כל CSS transforms
      const topNeighbor = findNeighborPanel(cx, cy);
      if (topNeighbor) {
        const sectorId = parseInt(topNeighbor.getAttribute('data-sector-id') || '0');
        if (sectorId && onTransfer) { onTransfer(s.id, sectorId); return; }
      }

      // 2. סמן מפה — getBoundingClientRect אמין דרך CSS transforms
      const topMarker = findMarker(cx, cy);
      if (topMarker && mapArea) {
        const sectorId = parseInt(topMarker.getAttribute('data-marker-sector') || '0');
        const subLabel = topMarker.getAttribute('data-marker-sublabel') || undefined;
        if (sectorId && onTransfer) {
          const mapRect = mapArea.getBoundingClientRect();
          const mc = viewportToMapCoords(cx, cy, mapRect);
          onTransfer(s.id, sectorId, mc.x, mc.y, subLabel || undefined);
          return;
        }
      }

      if (mapArea) {
        const mapRect = mapArea.getBoundingClientRect();

        // 3. החזרה לרשימה (drop על סרגל הצד)
        if (sidebar) {
          const sr = sidebar.getBoundingClientRect();
          if (cx >= sr.left && cx <= sr.right && cy >= sr.top && cy <= sr.bottom) {
            onMove(s.id, 0, 0, false);
            return;
          }
        }

        // 4. מיקום על המפה — ממיר לקואורדינטות map-container (מתחשב בזום/פאן)
        if (cx >= mapRect.left && cx <= mapRect.right &&
            cy >= mapRect.top  && cy <= mapRect.bottom) {
          // stripLeft/Top: viewport position of the strip's top-left corner at release
          const stripLeft = cx - startPosRef.current.x;
          const stripTop  = cy - startPosRef.current.y;
          const mcStrip = viewportToMapCoords(stripLeft, stripTop, mapRect);
          onMove(s.id, mcStrip.x, mcStrip.y, true);
        }
      }
    };

    const handleDragUp = (ev: PointerEvent) => {
      clearHighlights();
      setIsDragging(false);
      window.removeEventListener('pointermove', handleDragMove);
      window.removeEventListener('pointerup', handleDragUp);
      window.removeEventListener('pointercancel', handleDragCancel);
      if (dragActivated) performDrop(ev.clientX, ev.clientY);
    };

    const handleDragCancel = () => {
      clearHighlights();
      setIsDragging(false);
      window.removeEventListener('pointermove', handleDragMove);
      window.removeEventListener('pointerup', handleDragUp);
      window.removeEventListener('pointercancel', handleDragCancel);
      if (!dragActivated) return;
      // Tablet fallback: attempt transfer at last known position (neighbor panel / marker only).
      // Does NOT reposition on map to avoid accidental moves on system-cancelled gestures.
      const topNeighbor = findNeighborPanel(lastCx, lastCy);
      if (topNeighbor) {
        const sectorId = parseInt(topNeighbor.getAttribute('data-sector-id') || '0');
        if (sectorId && onTransfer) { onTransfer(s.id, sectorId); return; }
      }
      const topMarker = findMarker(lastCx, lastCy);
      const mapArea = document.getElementById('map-area');
      if (topMarker && mapArea) {
        const sectorId = parseInt(topMarker.getAttribute('data-marker-sector') || '0');
        const subLabel = topMarker.getAttribute('data-marker-sublabel') || undefined;
        if (sectorId && onTransfer) {
          const mapRect = mapArea.getBoundingClientRect();
          const mc = viewportToMapCoords(lastCx, lastCy, mapRect);
          onTransfer(s.id, sectorId, mc.x, mc.y, subLabel || undefined);
        }
      }
    };

    window.addEventListener('pointermove', handleDragMove);
    window.addEventListener('pointerup', handleDragUp);
    window.addEventListener('pointercancel', handleDragCancel);
  };

  const handleBodyPointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
    if (e.pointerType !== 'touch') return;
    if (!s.onMap) return;
    if (isDragging) return;
    if ((e.target as HTMLElement).closest('button, input, textarea, select')) return;
    const startX = e.clientX;
    const startY = e.clientY;
    bodyDragReadyRef.current = false;

    const longPressTimer = setTimeout(() => {
      if (!bodyTouchRef.current) return;
      bodyDragReadyRef.current = true;
      setBodyDragReady(true);
      if (navigator.vibrate) navigator.vibrate(60);
    }, 2000);

    const onMove = (me: PointerEvent) => {
      if (!bodyTouchRef.current) return;
      if (bodyDragReadyRef.current) {
        cleanup();
        handlePointerDown({ clientX: startX, clientY: startY, preventDefault: () => {}, stopPropagation: () => {} } as any);
        return;
      }
      if (Math.abs(me.clientX - startX) > 10 || Math.abs(me.clientY - startY) > 10) {
        cleanup();
      }
    };
    const cleanup = () => {
      clearTimeout(longPressTimer);
      bodyDragReadyRef.current = false;
      setBodyDragReady(false);
      window.removeEventListener('pointermove', onMove);
      window.removeEventListener('pointerup', onUp);
      window.removeEventListener('pointercancel', onUp);
      if (bodyTouchRef.current) bodyTouchRef.current = null;
    };
    const onUp = cleanup;
    bodyTouchRef.current = { startX, startY, cleanup };
    window.addEventListener('pointermove', onMove);
    window.addEventListener('pointerup', onUp);
    window.addEventListener('pointercancel', onUp);
  };

  useEffect(() => {
    return () => {
      document.querySelectorAll('.marker-drop-zone.strip-drag-active, .neighbor-drop-zone.strip-drag-active').forEach(el => el.classList.remove('strip-drag-active'));
    };
  }, []);

  // רכיב הפ"מ הבסיסי
  const stripContent = (style: React.CSSProperties) => (
    <div data-strip-id={s.id} ref={!isDragging ? containerRef : undefined} className={`bt-strip${isBlockDeviation && !blockDeviation ? ' block-deviation-flash' : ''}${isAltConflict ? ' alt-conflict-flash' : ''}`} style={{ ...style, outline: bodyDragReady ? '3px solid #22c55e' : undefined, transition: 'outline 0.15s' }} onContextMenu={handleContextMenu} onPointerDown={s.onMap ? handleBodyPointerDown : undefined}>
      <div style={{ width: 22, background: '#1e293b', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'space-between', padding: '2px 0', userSelect: 'none', touchAction: 'none', WebkitUserSelect: 'none', flexShrink: 0 }}>
        <div
          onPointerDown={e => {
            e.preventDefault();
            e.stopPropagation();
            handlePointerDown(e);
          }}
          title="גרור להזזה"
          style={{ cursor: 'grab', color: 'white', fontSize: '13px', lineHeight: 1, flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', borderRadius: '2px', width: '100%' }}
        >⋮</div>
        <button
          onClick={(e) => { e.stopPropagation(); if (showDetails) { _activeStripDetailsCloser = null; setShowDetails(false); } else { if (_activeStripDetailsCloser) _activeStripDetailsCloser(); const rect = containerRef.current?.getBoundingClientRect(); if (rect) { const pw=230,ph=420; let left=rect.right+8; if(left+pw>window.innerWidth-8) left=rect.left-pw-8; if(left<8) left=8; let top=rect.top; if(top+ph>window.innerHeight-8) top=window.innerHeight-ph-8; if(top<8) top=8; setDetailsPos({left,top}); } _activeStripDetailsCloser=()=>setShowDetails(false); setShowDetails(true); } }}
          title={showDetails ? 'סגור פרטים' : 'פתח פרטים'}
          style={{ background: 'transparent', border: 'none', color: hasDetails ? '#60a5fa' : '#94a3b8', fontSize: '9px', cursor: 'pointer', padding: '1px 0', lineHeight: 1 }}
        >{showDetails ? '▴' : '▾'}</button>
      </div>
      <div onDoubleClick={(e) => { e.stopPropagation(); if (showDetails) { _activeStripDetailsCloser = null; setShowDetails(false); } else { if (_activeStripDetailsCloser) _activeStripDetailsCloser(); const rect = containerRef.current?.getBoundingClientRect(); if (rect) { const pw=230,ph=420; let left=rect.right+8; if(left+pw>window.innerWidth-8) left=rect.left-pw-8; if(left<8) left=8; let top=rect.top; if(top+ph>window.innerHeight-8) top=window.innerHeight-ph-8; if(top<8) top=8; setDetailsPos({left,top}); } _activeStripDetailsCloser=()=>setShowDetails(false); setShowDetails(true); } }} style={{ padding: '2px 4px', flex: 1, direction: 'rtl', textAlign: 'right', minWidth: 0, overflowX: 'hidden' }}>
        {/* שורה 1: או"ק + טייסת + משימה */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '3px', flexWrap: 'nowrap', overflow: 'hidden' }}>
          <div style={{
            fontWeight: 'bold',
            fontSize: '11px',
            whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', flexShrink: 1,
            ...(s.airborne ? { background: '#1d4ed8', color: 'white', border: '1px solid #3b82f6', borderRadius: '3px', padding: '0 3px' } : {})
          }}>{getFormationDisplayName(s)}{s.numberOfFormation && !s.aircraft_indices ? ` / ${s.numberOfFormation}` : ''}{s.aircraft_indices ? <span style={{ fontSize: '8px', color: '#fb923c', fontWeight: 'normal', marginRight: '3px' }}>⬡חלקי</span> : null}</div>
          {(s.sq || s.squadron) && <div style={{ fontSize: '8px', color: '#7c3aed', fontWeight: 'bold', flexShrink: 0 }}>{s.sq || s.squadron}</div>}
          {s.task && <div style={{ fontSize: '9px', color: '#475569', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', flexShrink: 1 }}>{s.task}</div>}
        </div>
        {/* שורה 2: גובה + הערה */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '4px', overflow: 'hidden' }}>
          <div ref={altRef} onClick={handleEditClick}
            style={{ fontSize: '11px', fontWeight: 'bold', color: (isBlockDeviation || blockDeviation) ? '#f97316' : isAltConflict ? '#ef4444' : '#374151', cursor: 'pointer', whiteSpace: 'nowrap', flexShrink: 0 }}>
            {s.alt ? `גובה: ${normalizeAlt(s.alt)}` : ''}
          </div>
          {isAltConflict && (
            <span title="קונפליקט גובה עם פ״מ אחר במפה" style={{ display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: '14px', height: '14px', borderRadius: '50%', background: '#ef4444', color: 'white', fontSize: '10px', fontWeight: 'bold', flexShrink: 0, lineHeight: 1, userSelect: 'none' }}>!</span>
          )}
          {isBlockDeviation && !blockDeviation && (
            <span
              onClick={async (e) => { e.stopPropagation(); setBlockDeviation(true); try { await fetch(`${API_URL}/strips/${s.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ block_deviation: true }) }); } catch {} }}
              title="אישור חריגה מבלוק"
              style={{ display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: '14px', height: '14px', borderRadius: '50%', background: '#f97316', color: 'white', fontSize: '10px', fontWeight: 'bold', flexShrink: 0, cursor: 'pointer', lineHeight: 1, userSelect: 'none' }}
            >!</span>
          )}
          {blockDeviation && (
            <span
              onClick={async (e) => { e.stopPropagation(); setBlockDeviation(false); try { await fetch(`${API_URL}/strips/${s.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ block_deviation: false }) }); } catch {} }}
              title="חריגה מאושרת — לחץ לביטול אישור"
              style={{ display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: '14px', height: '14px', borderRadius: '50%', background: '#22c55e', color: 'white', fontSize: '10px', fontWeight: 'bold', flexShrink: 0, cursor: 'pointer', lineHeight: 1, userSelect: 'none' }}
            >!</span>
          )}
          {!editingNotes && s.notes && (() => { const np = parseNoteValue(s.notes || ''); return (
            <div onClick={(e) => { e.stopPropagation(); setEditingNotes(true); }} style={{ fontSize: '8px', color: '#64748b', cursor: 'pointer', flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }} title="לחץ לעריכה">
              {np.text && <span>📝 {np.text}</span>}
              {np.hw && <img src={np.hw} alt="כתב יד" style={{ maxHeight: '14px', borderRadius: '2px', verticalAlign: 'middle' }} />}
            </div>
          ); })()}
          {!editingNotes && !s.notes && onUpdateNotes && (
            <button onClick={(e) => { e.stopPropagation(); setEditingNotes(true); }} style={{ background: 'transparent', border: 'none', color: '#94a3b8', fontSize: '8px', cursor: 'pointer', flexShrink: 0, padding: 0 }}>+ הערה</button>
          )}
        </div>
        {/* עריכת הערה — נפתח בלחיצה מהשורה השנייה */}
        {editingNotes && (
          <div onClick={(e) => e.stopPropagation()}>
            <div style={{ display: 'flex', alignItems: 'flex-start', gap: '2px' }}>
              <textarea
                value={tempNotes}
                onChange={(e) => setTempNotes(e.target.value)}
                style={{ flex: 1, padding: '2px', border: '1px solid #cbd5e1', borderRadius: '2px', fontSize: '8px', resize: 'none', boxSizing: 'border-box' }}
                rows={2}
                autoFocus
              />
              <VKTrigger value={tempNotes} onChange={v => setTempNotes(v)} mode="full" label="הערה" size={14} />
            </div>
            <div style={{ display: 'flex', gap: '2px', marginTop: '2px' }}>
              <button
                onClick={() => { if (onUpdateNotes) onUpdateNotes(s.id, tempNotes); setEditingNotes(false); }}
                style={{ flex: 1, padding: '1px', background: '#10b981', color: 'white', border: 'none', borderRadius: '2px', fontSize: '8px', cursor: 'pointer' }}
              >שמור</button>
              <button
                onClick={() => { setTempNotes(s.notes || ''); setEditingNotes(false); }}
                style={{ flex: 1, padding: '1px', background: '#64748b', color: 'white', border: 'none', borderRadius: '2px', fontSize: '8px', cursor: 'pointer' }}
              >ביטול</button>
            </div>
          </div>
        )}

        {/* Expandable Details Panel — floating portal */}
        {showDetails && createPortal(
          <>
            <div onClick={() => { _activeStripDetailsCloser = null; setShowDetails(false); }} style={{ position: 'fixed', inset: 0, zIndex: 9990 }} />
            <div onClick={(e) => e.stopPropagation()} style={{ position: 'fixed', left: detailsPos.left, top: detailsPos.top, zIndex: 9991, background: '#f8fafc', border: '1px solid #cbd5e1', borderRadius: '6px', boxShadow: '0 8px 28px rgba(0,0,0,0.28)', width: '230px', maxHeight: '80vh', overflowY: 'auto', direction: 'rtl' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '4px 8px', borderBottom: '1px solid #e2e8f0', background: '#dde5f0', borderRadius: '6px 6px 0 0', position: 'sticky', top: 0, zIndex: 1 }}>
                <span style={{ fontWeight: 'bold', fontSize: '10px', color: '#1e293b' }}>📋 {s.callSign || s.callsign || 'פרטים'}</span>
                <button onClick={() => { _activeStripDetailsCloser = null; setShowDetails(false); }} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#475569', fontSize: '13px', lineHeight: 1, padding: '0 2px' }}>✕</button>
              </div>
              <div style={{ padding: '6px', fontSize: '9px' }}>

            {/* זמן המראה */}
            <div style={{ marginBottom: '8px', display: 'flex', alignItems: 'center', gap: '6px' }}>
              <span style={{ color: '#475569', fontWeight: 'bold', whiteSpace: 'nowrap' }}>זמן המראה:</span>
              <input
                type="datetime-local"
                value={localTakeoffTime}
                onChange={e => setLocalTakeoffTime(e.target.value)}
                onBlur={async e => {
                  const val = e.target.value;
                  if (!val) return;
                  try {
                    await fetch(`${API_URL}/strips/${s.id}`, {
                      method: 'PUT',
                      headers: { 'Content-Type': 'application/json' },
                      body: JSON.stringify({ takeoff_time: new Date(val).toISOString() })
                    });
                  } catch {}
                }}
                style={{ flex: 1, padding: '2px 4px', border: '1px solid #cbd5e1', borderRadius: '3px', fontSize: '9px', background: 'white', minWidth: 0 }}
              />
              {localTakeoffTime && (
                <button
                  onClick={async () => {
                    setLocalTakeoffTime('');
                    try {
                      await fetch(`${API_URL}/strips/${s.id}`, {
                        method: 'PUT',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ takeoff_time: null })
                      });
                    } catch {}
                  }}
                  style={{ background: '#ef4444', color: 'white', border: 'none', borderRadius: '3px', padding: '1px 5px', fontSize: '9px', cursor: 'pointer' }}
                >✕</button>
              )}
            </div>

            {/* חימושים */}
            <div style={{ marginBottom: '6px' }}>
              <div style={{ fontWeight: 'bold', color: '#1e293b', marginBottom: '3px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span>חימושים</span>
                <button onClick={() => saveDetails({ ...detailsData, weapons: [...detailsData.weapons, { type: '', quantity: '' }] })}
                  style={{ background: '#3b82f6', color: 'white', border: 'none', borderRadius: '3px', padding: '1px 5px', fontSize: '9px', cursor: 'pointer' }}>+</button>
              </div>
              {detailsData.weapons.map((w, i) => (
                <div key={i} style={{ display: 'flex', gap: '3px', marginBottom: '2px', alignItems: 'center' }}>
                  <input value={w.type} placeholder="סוג" onChange={(e) => {
                    const updated = detailsData.weapons.map((item, idx) => idx === i ? { ...item, type: e.target.value } : item);
                    saveDetails({ ...detailsData, weapons: updated });
                  }} style={{ flex: 2, padding: '2px 4px', border: '1px solid #cbd5e1', borderRadius: '3px', fontSize: '9px', minWidth: 0 }} />
                  <input value={w.quantity} placeholder="כמות" onChange={(e) => {
                    const updated = detailsData.weapons.map((item, idx) => idx === i ? { ...item, quantity: e.target.value } : item);
                    saveDetails({ ...detailsData, weapons: updated });
                  }} style={{ flex: 1, padding: '2px 4px', border: '1px solid #cbd5e1', borderRadius: '3px', fontSize: '9px', minWidth: 0 }} />
                  <button onClick={() => saveDetails({ ...detailsData, weapons: detailsData.weapons.filter((_, idx) => idx !== i) })}
                    style={{ background: '#ef4444', color: 'white', border: 'none', borderRadius: '3px', padding: '1px 4px', fontSize: '9px', cursor: 'pointer', flexShrink: 0 }}>✕</button>
                </div>
              ))}
              {detailsData.weapons.length === 0 && <div style={{ color: '#94a3b8', fontSize: '8px' }}>לחץ + להוספה</div>}
            </div>

            {/* מטרות */}
            <div style={{ marginBottom: '6px' }}>
              <div style={{ fontWeight: 'bold', color: '#1e293b', marginBottom: '3px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span>מטרות</span>
                <button onClick={() => saveDetails({ ...detailsData, targets: [...detailsData.targets, { name: '', aim_point: '' }] })}
                  style={{ background: '#3b82f6', color: 'white', border: 'none', borderRadius: '3px', padding: '1px 5px', fontSize: '9px', cursor: 'pointer' }}>+</button>
              </div>
              {detailsData.targets.map((t, i) => (
                <div key={i} style={{ display: 'flex', gap: '3px', marginBottom: '2px', alignItems: 'center' }}>
                  <input value={t.name} placeholder="שם מטרה" onChange={(e) => {
                    const updated = detailsData.targets.map((item, idx) => idx === i ? { ...item, name: e.target.value } : item);
                    saveDetails({ ...detailsData, targets: updated });
                  }} style={{ flex: 2, padding: '2px 4px', border: '1px solid #cbd5e1', borderRadius: '3px', fontSize: '9px', minWidth: 0 }} />
                  <input value={t.aim_point} placeholder="נ. מכוון" onChange={(e) => {
                    const updated = detailsData.targets.map((item, idx) => idx === i ? { ...item, aim_point: e.target.value } : item);
                    saveDetails({ ...detailsData, targets: updated });
                  }} style={{ flex: 1, padding: '2px 4px', border: '1px solid #cbd5e1', borderRadius: '3px', fontSize: '9px', minWidth: 0 }} />
                  <button onClick={() => saveDetails({ ...detailsData, targets: detailsData.targets.filter((_, idx) => idx !== i) })}
                    style={{ background: '#ef4444', color: 'white', border: 'none', borderRadius: '3px', padding: '1px 4px', fontSize: '9px', cursor: 'pointer', flexShrink: 0 }}>✕</button>
                </div>
              ))}
              {detailsData.targets.length === 0 && <div style={{ color: '#94a3b8', fontSize: '8px' }}>לחץ + להוספה</div>}
            </div>

            {/* מערכות */}
            <div style={{ marginBottom: '6px' }}>
              <div style={{ fontWeight: 'bold', color: '#1e293b', marginBottom: '3px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span>מערכות</span>
                <button onClick={() => saveDetails({ ...detailsData, systems: [...detailsData.systems, { name: '' }] })}
                  style={{ background: '#3b82f6', color: 'white', border: 'none', borderRadius: '3px', padding: '1px 5px', fontSize: '9px', cursor: 'pointer' }}>+</button>
              </div>
              {detailsData.systems.map((sys, i) => (
                <div key={i} style={{ display: 'flex', gap: '3px', marginBottom: '2px', alignItems: 'center' }}>
                  <input value={sys.name} placeholder="שם מערכת" onChange={(e) => {
                    const updated = detailsData.systems.map((item, idx) => idx === i ? { name: e.target.value } : item);
                    saveDetails({ ...detailsData, systems: updated });
                  }} style={{ flex: 1, padding: '2px 4px', border: '1px solid #cbd5e1', borderRadius: '3px', fontSize: '9px', minWidth: 0 }} />
                  <button onClick={() => saveDetails({ ...detailsData, systems: detailsData.systems.filter((_, idx) => idx !== i) })}
                    style={{ background: '#ef4444', color: 'white', border: 'none', borderRadius: '3px', padding: '1px 4px', fontSize: '9px', cursor: 'pointer', flexShrink: 0 }}>✕</button>
                </div>
              ))}
              {detailsData.systems.length === 0 && <div style={{ color: '#94a3b8', fontSize: '8px' }}>לחץ + להוספה</div>}
            </div>

            {/* שקדיה */}
            <div>
              <div style={{ fontWeight: 'bold', color: '#1e293b', marginBottom: '3px' }}>שקדיה</div>
              <input
                value={detailsData.shkadia}
                placeholder="מי מפסר המבנה יש שקדיה"
                onChange={(e) => saveDetails({ ...detailsData, shkadia: e.target.value })}
                style={{ width: '100%', padding: '3px 5px', border: '1px solid #cbd5e1', borderRadius: '3px', fontSize: '9px', boxSizing: 'border-box' }}
              />
            </div>

            {/* כותרת / ערכה / מבצע */}
            <div style={{ marginTop: '6px', display: 'flex', flexDirection: 'column', gap: '4px' }}>
              <input
                value={localKoteret}
                placeholder="כותרת"
                onChange={e => setLocalKoteret(e.target.value)}
                onBlur={async e => {
                  const val = e.target.value;
                  try { await fetch(`${API_URL}/strips/${s.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ koteret: val }) }); } catch {}
                }}
                style={{ width: '100%', padding: '3px 5px', border: '1px solid #cbd5e1', borderRadius: '3px', fontSize: '9px', boxSizing: 'border-box' }}
              />
              <div style={{ display: 'flex', gap: '4px' }}>
                <input
                  value={localErka}
                  placeholder="ערכה"
                  onChange={e => setLocalErka(e.target.value)}
                  onBlur={async e => {
                    const val = e.target.value;
                    try { await fetch(`${API_URL}/strips/${s.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ erka: val }) }); } catch {}
                  }}
                  style={{ flex: 1, padding: '3px 5px', border: '1px solid #cbd5e1', borderRadius: '3px', fontSize: '9px', minWidth: 0 }}
                />
                <input
                  value={localMivtza}
                  placeholder="מבצע"
                  onChange={e => setLocalMivtza(e.target.value)}
                  onBlur={async e => {
                    const val = e.target.value;
                    try { await fetch(`${API_URL}/strips/${s.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ mivtza: val }) }); } catch {}
                  }}
                  style={{ flex: 1, padding: '3px 5px', border: '1px solid #cbd5e1', borderRadius: '3px', fontSize: '9px', minWidth: 0 }}
                />
              </div>
            </div>
            {allBlockSpaces.length > 0 && (
              <div style={{ marginTop: '4px' }}>
                <div style={{ fontSize: '9px', color: '#94a3b8', marginBottom: '2px' }}>מרחב בלוקים</div>
                <select
                  value={localBlockSpaceId}
                  onChange={async e => {
                    const val = e.target.value;
                    setLocalBlockSpaceId(val);
                    blockSpaceSavingRef.current = true;
                    try {
                      await fetch(`${API_URL}/strips/${s.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ block_space_id: val || null }) });
                      const bsName = val ? (allBlockSpaces.find((b: any) => String(b.id) === val)?.name || val) : null;
                      fetch(`${API_URL}/activity-log`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ event_type: 'block_assigned', severity: 'normal', strip_id: String(s.id), strip_callsign: s.callsign || s.callSign || '', details: { blockSpaceName: bsName, blockSpaceId: val || null } }) }).catch(() => {});
                    } catch {}
                    setTimeout(() => { blockSpaceSavingRef.current = false; }, 5000);
                  }}
                  style={{ width: '100%', padding: '3px 5px', border: '1px solid #cbd5e1', borderRadius: '3px', fontSize: '9px', background: 'white', color: '#1e293b' }}
                >
                  <option value="">ללא מרחב בלוקים</option>
                  {allBlockSpaces.map((bs: any) => <option key={bs.id} value={String(bs.id)}>{bs.name}</option>)}
                </select>
              </div>
            )}
              </div>
            </div>
          </>,
          document.body
        )}
      </div>
      {edit && (
        <HandwritingOverlay 
          onCancel={() => setEdit(false)} 
          onComplete={(val: string) => { onUpdate(s.id, val); setEdit(false); }} 
          anchorRect={anchorRect}
        />
      )}
      {serialRowMenu && (
        <>
          <div onClick={() => setSerialRowMenu(null)} style={{ position: 'fixed', inset: 0, zIndex: 9998 }}/>
          <div style={{ position: 'fixed', left: clampMenuPos(serialRowMenu.x, serialRowMenu.y, 190, 150).left, top: clampMenuPos(serialRowMenu.x, serialRowMenu.y, 190, 150).top, zIndex: 9999, background: '#1e293b', border: '1px solid #334155', borderRadius: '6px', boxShadow: '0 4px 16px rgba(0,0,0,0.5)', minWidth: '170px', overflow: 'hidden', direction: 'rtl' }}>
            <div style={{ padding: '4px 0' }}>
              <button
                onClick={() => { onSerialSelect && onSerialSelect(s.id, serialRowMenu.station, serialRowMenu.specificSerialId ?? serialRowMenu.latestSerialId, false); setSerialRowMenu(null); }}
                style={{ width: '100%', background: 'none', border: 'none', color: '#e2e8f0', padding: '8px 14px', cursor: 'pointer', textAlign: 'right', fontSize: '13px', display: 'block' }}
                onMouseEnter={e => (e.currentTarget.style.background = '#2563eb')}
                onMouseLeave={e => (e.currentTarget.style.background = 'none')}
              >✅ קבל ספרור</button>
              <button
                onClick={() => { onSerialDismiss && onSerialDismiss(s.id, serialRowMenu.station); setSerialRowMenu(null); }}
                style={{ width: '100%', background: 'none', border: 'none', color: '#fca5a5', padding: '8px 14px', cursor: 'pointer', textAlign: 'right', fontSize: '13px', display: 'block' }}
                onMouseEnter={e => (e.currentTarget.style.background = '#7f1d1d')}
                onMouseLeave={e => (e.currentTarget.style.background = 'none')}
              >🚫 ספרור לא רלוונטי</button>
              <div style={{ borderTop: '1px solid #334155', margin: '2px 0' }}/>
              <button
                onClick={() => { setSerialViewPopup({ x: serialRowMenu.x, y: serialRowMenu.y, station: serialRowMenu.station }); setSerialRowMenu(null); }}
                style={{ width: '100%', background: 'none', border: 'none', color: '#93c5fd', padding: '8px 14px', cursor: 'pointer', textAlign: 'right', fontSize: '13px', display: 'block' }}
                onMouseEnter={e => (e.currentTarget.style.background = '#1e3a5f')}
                onMouseLeave={e => (e.currentTarget.style.background = 'none')}
              >📋 הצג ספרור</button>
            </div>
          </div>
        </>
      )}
      {serialViewPopup && (() => {
        const station = serialViewPopup.station;
        const allStationSerials = [...serials].filter((sr: any) => sr.control_station === station).sort((a: any, b: any) => b.serial_number - a.serial_number);
        const latestSerial = allStationSerials[0];
        const mySelection = serialSelections.find((sel: any) => sel.strip_id === s.id && sel.control_station === station);
        const mySerial = mySelection?.serial_id ? serials.find((sr: any) => sr.id === mySelection.serial_id) : null;
        const threeHoursAgo = Date.now() - 3 * 60 * 60 * 1000;
        const recentSerials = allStationSerials.filter((sr: any) => {
          const t = sr.created_at ? new Date(sr.created_at).getTime() : 0;
          return t >= threeHoursAgo;
        });
        const fmt = (dt: string) => dt ? new Date(dt).toLocaleString('he-IL', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' }) : '—';
        const { left: popLeft, top: popTop } = clampMenuPos(serialViewPopup.x, serialViewPopup.y, 330, 440);
        return (
          <>
            <div onClick={() => setSerialViewPopup(null)} style={{ position: 'fixed', inset: 0, zIndex: 9998 }}/>
            <div style={{ position: 'fixed', left: popLeft, top: popTop, zIndex: 9999, background: '#0f172a', border: '1px solid #1d4ed8', borderRadius: '8px', boxShadow: '0 8px 32px rgba(0,0,0,0.7)', width: '320px', direction: 'rtl', overflow: 'hidden', maxHeight: '80vh', display: 'flex', flexDirection: 'column' }}>
              {/* כותרת */}
              <div style={{ background: '#1e3a5f', padding: '8px 12px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexShrink: 0 }}>
                <span style={{ color: '#93c5fd', fontWeight: 'bold', fontSize: '13px' }}>📡 ספרור — {station}</span>
                <button onClick={() => setSerialViewPopup(null)} style={{ background: 'none', border: 'none', color: '#94a3b8', cursor: 'pointer', fontSize: '16px', lineHeight: 1 }}>✕</button>
              </div>
              <div style={{ overflowY: 'auto', flex: 1 }}>
                {/* הספרור הנוכחי של הפ"מ */}
                <div style={{ padding: '10px 12px', borderBottom: '1px solid #1e3a5f', background: '#0c1a2e' }}>
                  <div style={{ color: '#60a5fa', fontSize: '10px', marginBottom: '6px', fontWeight: 'bold', textTransform: 'uppercase', letterSpacing: '0.5px' }}>ספרור נוכחי של הפ"מ</div>
                  {mySerial && !mySelection?.dismissed ? (
                    <div style={{ background: '#14432a', border: '1px solid #166534', borderRadius: '6px', padding: '8px 10px' }}>
                      <div style={{ color: '#4ade80', fontSize: '16px', fontWeight: 'bold', marginBottom: '3px' }}>#{mySerial.serial_number}</div>
                      {mySerial.essence && <div style={{ color: '#bbf7d0', fontSize: '11px', marginBottom: '2px' }}>מהות: {mySerial.essence}</div>}
                      {mySerial.relevant_to && <div style={{ color: '#86efac', fontSize: '10px', marginBottom: '2px' }}>רלוונטי ל: {mySerial.relevant_to}</div>}
                      <div style={{ color: '#4ade80', fontSize: '9px', opacity: 0.7 }}>נוצר: {fmt(mySerial.created_at)}</div>
                      {latestSerial && latestSerial.id !== mySerial.id && (
                        <div style={{ marginTop: '6px', padding: '4px 8px', background: '#dc2626', borderRadius: '4px', color: 'white', fontSize: '10px', fontWeight: 'bold' }}>
                          ⚠️ קיים ספרור חדש יותר: #{latestSerial.serial_number}
                          <button
                            onClick={e => { e.stopPropagation(); onSerialSelect && onSerialSelect(s.id, station, latestSerial.id, false); setSerialViewPopup(null); }}
                            style={{ marginRight: '8px', background: 'white', color: '#dc2626', border: 'none', borderRadius: '3px', padding: '1px 6px', cursor: 'pointer', fontSize: '9px', fontWeight: 'bold' }}
                          >עדכן</button>
                        </div>
                      )}
                    </div>
                  ) : mySelection?.dismissed ? (
                    <div style={{ color: '#f87171', fontSize: '12px', padding: '4px 0' }}>🚫 סומן כ"לא רלוונטי"</div>
                  ) : (
                    <div style={{ color: '#64748b', fontSize: '12px', padding: '4px 0' }}>— לא משויך ספרור לפ"מ זה</div>
                  )}
                </div>
                {/* ספרורים מ-3 שעות האחרונות */}
                <div style={{ padding: '8px 12px 6px' }}>
                  <div style={{ color: '#64748b', fontSize: '10px', marginBottom: '6px', fontWeight: 'bold' }}>ספרורים מ-3 השעות האחרונות</div>
                  {recentSerials.length === 0 ? (
                    <div style={{ color: '#475569', fontSize: '11px', padding: '6px 0', textAlign: 'center' }}>אין ספרורים מ-3 השעות האחרונות</div>
                  ) : (
                    recentSerials.map((sr: any) => {
                      const isCurrent = mySelection?.serial_id === sr.id && !mySelection?.dismissed;
                      const isLatest = latestSerial?.id === sr.id;
                      return (
                        <div key={sr.id} style={{ display: 'flex', alignItems: 'center', gap: '6px', padding: '5px 8px', borderRadius: '5px', marginBottom: '3px', background: isCurrent ? '#14432a' : isLatest ? '#1e3a5f' : '#0f172a', border: `1px solid ${isCurrent ? '#166534' : isLatest ? '#1d4ed8' : '#1e293b'}` }}>
                          <div style={{ flex: 1, minWidth: 0 }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                              <span style={{ color: isCurrent ? '#4ade80' : isLatest ? '#93c5fd' : '#e2e8f0', fontWeight: 'bold', fontSize: '12px' }}>#{sr.serial_number}</span>
                              {isLatest && <span style={{ background: '#1d4ed8', color: 'white', fontSize: '8px', borderRadius: '3px', padding: '0 4px' }}>חדש ביותר</span>}
                              {isCurrent && <span style={{ background: '#166534', color: '#4ade80', fontSize: '8px', borderRadius: '3px', padding: '0 4px' }}>✓ נוכחי</span>}
                            </div>
                            {sr.essence && <div style={{ color: '#64748b', fontSize: '10px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{sr.essence}</div>}
                            <div style={{ color: '#475569', fontSize: '9px' }}>{fmt(sr.created_at)}</div>
                          </div>
                          {!isCurrent && (
                            <button
                              onClick={e => { e.stopPropagation(); onSerialSelect && onSerialSelect(s.id, station, sr.id, false); setSerialViewPopup(null); }}
                              style={{ background: '#1d4ed8', color: 'white', border: 'none', borderRadius: '3px', padding: '3px 7px', cursor: 'pointer', fontSize: '9px', fontWeight: 'bold', flexShrink: 0 }}
                            >קבל</button>
                          )}
                        </div>
                      );
                    })
                  )}
                </div>
              </div>
              {/* כפתורי פעולה */}
              <div style={{ display: 'flex', gap: '6px', padding: '8px 12px', borderTop: '1px solid #1e3a5f', flexShrink: 0 }}>
                {latestSerial && mySerial?.id !== latestSerial.id && !mySelection?.dismissed && (
                  <button
                    onClick={() => { onSerialSelect && onSerialSelect(s.id, station, latestSerial.id, false); setSerialViewPopup(null); }}
                    style={{ flex: 1, background: '#1d4ed8', border: 'none', borderRadius: '4px', color: 'white', padding: '6px', cursor: 'pointer', fontSize: '11px', fontWeight: 'bold' }}
                  >✅ קבל ספרור עדכני</button>
                )}
                <button
                  onClick={() => { onSerialDismiss && onSerialDismiss(s.id, station); setSerialViewPopup(null); }}
                  style={{ flex: 1, background: '#7f1d1d', border: 'none', borderRadius: '4px', color: '#fca5a5', padding: '6px', cursor: 'pointer', fontSize: '11px' }}
                >🚫 לא רלוונטי</button>
              </div>
            </div>
          </>
        );
      })()}
      {contextMenu && (
        <ContextMenu 
          x={contextMenu.x} 
          y={contextMenu.y} 
          neighbors={neighbors || []} 
          onSelect={(sectorId) => {
            if (onTransfer) onTransfer(s.id, sectorId);
            setContextMenu(null);
          }}
          onClose={() => setContextMenu(null)}
          extraActions={(() => {
            const mySelections = serialSelections.filter((sel: any) => sel.strip_id === s.id && !sel.dismissed);
            const alertSelections = mySelections.filter((sel: any) => {
              const latestForStation = [...serials].filter((sr: any) => sr.control_station === sel.control_station).sort((a: any, b: any) => b.serial_number - a.serial_number)[0];
              return sel.serial_id && latestForStation && latestForStation.id !== sel.serial_id;
            });
            const actions = [];
            if (mySelections.length > 0) {
              actions.push({ label: 'ספרור לא רלוונטי לפ"מ', onClick: () => mySelections.forEach((sel: any) => onSerialDismiss && onSerialDismiss(s.id, sel.control_station)) });
            }
            if (alertSelections.length > 0) {
              actions.push({ label: 'פ"מ עודכן בספרור', onClick: () => alertSelections.forEach((sel: any) => {
                const latest = [...serials].filter((sr: any) => sr.control_station === sel.control_station).sort((a: any, b: any) => b.serial_number - a.serial_number)[0];
                if (latest && onSerialSelect) onSerialSelect(s.id, sel.control_station, latest.id, false);
              })});
            }
            if (isBlockDeviation && !blockDeviation) {
              actions.push({ label: '⚠️ אשר חריגה מבלוק', onClick: async () => {
                setBlockDeviation(true);
                try { await fetch(`${API_URL}/strips/${s.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ block_deviation: true }) }); } catch {}
                setContextMenu(null);
              }});
            }
            if (blockDeviation && !isBlockDeviation) {
              actions.push({ label: 'נקה סטייה ממרחב בלוקים', onClick: async () => {
                setBlockDeviation(false);
                try { await fetch(`${API_URL}/strips/${s.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ block_deviation: false }) }); } catch {}
                setContextMenu(null);
              }});
            }
            return actions;
          })()}
        />
      )}
    </div>
  );

  const baseStyle: React.CSSProperties = {
    width: 130,
    background: (isBlockDeviation && !blockDeviation)
      ? undefined
      : blockDeviation
        ? (lightMode ? 'white' : 'rgba(234, 88, 12, 0.15)')
        : isAltConflict
          ? (lightMode ? 'white' : 'rgba(127, 29, 29, 0.15)')
          : s.airborne ? '#dbeafe' : 'white',
    border: (isBlockDeviation || blockDeviation)
      ? (lightMode ? '2px solid black' : '2px solid #f97316')
      : isAltConflict
        ? '2px solid #ef4444'
        : s.airborne ? '2px solid #3b82f6' : '2px solid black',
    display: 'flex', flexDirection: 'row-reverse',
    marginBottom: '6px', touchAction: 'none'
  };

  // אם בגרירה, מציג בפורטל שיעקוב אחרי העכבר
  if (isDragging) {
    return (
      <>
        {/* Placeholder במקום המקורי — call stripContent directly to avoid double-positioning */}
        {stripContent({ ...baseStyle, opacity: 0.3, position: s.onMap ? 'absolute' : 'relative', left: s.onMap ? s.x : 0, top: s.onMap ? s.y : 0, transform: s.onMap ? `scale(${1/zoom})` : undefined, transformOrigin: 'top left' })}
        {/* רכיב גרירה שעוקב אחרי העכבר */}
        {createPortal(
          <div style={{ 
            ...baseStyle, 
            position: 'fixed', 
            left: dragPos.x, 
            top: dragPos.y, 
            zIndex: 9999,
            pointerEvents: 'none',
            boxShadow: '0 8px 20px rgba(0,0,0,0.3)',
            transform: 'rotate(2deg)'
          }}>
            <div style={{ width: 35, background: '#1e293b', color: 'white', display: 'flex', justifyContent: 'center', alignItems: 'center', fontSize: '20px' }}>⋮</div>
            <div style={{ padding: '8px', flex: 1, direction: 'rtl', textAlign: 'right' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div style={{ fontWeight: 'bold', fontSize: '13px' }}>{getFormationDisplayName(s)}{s.numberOfFormation && !s.aircraft_indices ? ` / ${s.numberOfFormation}` : ''}</div>
                <div style={{ fontSize: '11px', background: '#3b82f6', color: 'white', padding: '1px 6px', borderRadius: '3px' }}>{s.sq}</div>
              </div>
              {(!s.sq && s.squadron) && <div style={{ fontSize: '10px', color: '#7c3aed', fontWeight: 'bold', marginTop: '2px' }}>{s.squadron}</div>}
              <div style={{ display: 'flex', gap: '5px', marginTop: '4px' }}>
                <div style={{ fontSize: '10px', border: '1px solid #e2e8f0', flex: 1, padding: '2px', background: '#f1f5f9' }}>גובה: {normalizeAlt(s.alt || '')}</div>
                <div style={{ fontSize: '10px', flex: 1, color: '#64748b' }}>{s.task}</div>
              </div>
            </div>
          </div>,
          document.body
        )}
      </>
    );
  }

  return stripContent({
    ...baseStyle,
    position: s.onMap ? 'absolute' : 'relative',
    left: s.onMap ? s.x : 0, 
    top: s.onMap ? s.y : 0,
    zIndex: 50,
    transform: s.onMap ? `scale(${1/zoom})` : undefined,
    transformOrigin: 'top left'
  });
};

// --- מקלדת על-מסך ---
const OSK_LAYOUTS: Record<string, string[][]> = {
  he: [
    ['1','2','3','4','5','6','7','8','9','0','-','='],
    ['/','\'','א','ר','ט','ו','ן','ם','פ','[',']'],
    ['ש','ד','ג','כ','ע','י','ח','ל','ך','ף',';'],
    ['ז','ס','ב','ה','נ','מ','צ','ת','ץ','.'],
  ],
  en: [
    ['q','w','e','r','t','y','u','i','o','p'],
    ['a','s','d','f','g','h','j','k','l'],
    ['z','x','c','v','b','n','m',',','.'],
  ],
  EN: [
    ['Q','W','E','R','T','Y','U','I','O','P'],
    ['A','S','D','F','G','H','J','K','L'],
    ['Z','X','C','V','B','N','M','<','>'],
  ],
  sym: [
    ['!','@','#','$','%','^','&','*','(',')'],
    ['+','=','_','-','|','\\',':',';','"','\''],
    ['<','>','?','/','~','`','{','}','[',']'],
    ['°','±','×','÷','€','£','¥','©','®','™'],
  ],
};
const OnScreenKeyboard = ({ onType, onBackspace, onEnter, onClose }: {
  onType: (c: string) => void;
  onBackspace: () => void;
  onEnter: () => void;
  onClose: () => void;
}) => {
  const [lang, setLang] = useState<'he'|'en'|'EN'|'sym'>('he');
  const [pos, setPos] = useState({ x: Math.max(0, (window.innerWidth - 560) / 2), y: window.innerHeight - 280 });
  const dragRef = useRef<{ sx: number; sy: number; ox: number; oy: number } | null>(null);
  const rows = OSK_LAYOUTS[lang];
  const key: React.CSSProperties = {
    minWidth: 34, height: 38, background: '#334155', color: 'white',
    border: '1px solid #475569', borderRadius: '5px', cursor: 'pointer',
    fontSize: '14px', fontFamily: 'inherit', padding: '0 4px', flexShrink: 0,
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    WebkitUserSelect: 'none', userSelect: 'none',
  };
  const langBtn = (l: typeof lang, label: string) => (
    <button key={l} onPointerDown={e => { e.preventDefault(); setLang(l); }}
      style={{ ...key as any, minWidth: 50, background: lang === l ? '#2563eb' : '#1e3a5f', border: lang === l ? '1px solid #3b82f6' : '1px solid #1e40af', fontSize: '12px', fontWeight: 'bold' }}
    >{label}</button>
  );
  const onDragStart = (e: React.PointerEvent) => {
    e.preventDefault();
    dragRef.current = { sx: e.clientX, sy: e.clientY, ox: pos.x, oy: pos.y };
    const onMove = (me: PointerEvent) => {
      if (!dragRef.current) return;
      setPos({ x: dragRef.current.ox + me.clientX - dragRef.current.sx, y: dragRef.current.oy + me.clientY - dragRef.current.sy });
    };
    const onUp = () => { dragRef.current = null; window.removeEventListener('pointermove', onMove); window.removeEventListener('pointerup', onUp); };
    window.addEventListener('pointermove', onMove);
    window.addEventListener('pointerup', onUp);
  };
  return createPortal(
    <div style={{ position: 'fixed', left: pos.x, top: pos.y, zIndex: 99999, background: '#0f172a', border: '2px solid #3b82f6', borderRadius: '10px', boxShadow: '0 8px 32px rgba(0,0,0,0.7)', userSelect: 'none', direction: 'ltr', display: 'flex', flexDirection: 'column', gap: '4px', padding: '6px' }}>
      {/* Drag handle + close */}
      <div onPointerDown={onDragStart} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'grab', background: '#1e293b', borderRadius: '6px', padding: '4px 8px', marginBottom: '2px' }}>
        <span style={{ color: '#94a3b8', fontSize: '11px' }}>⌨ מקלדת וירטואלית — גרור להזזה</span>
        <button onPointerDown={e => { e.stopPropagation(); onClose(); }} style={{ background: '#ef4444', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer', padding: '2px 8px', fontSize: '13px', fontWeight: 'bold' }}>✕</button>
      </div>
      {/* Language row */}
      <div style={{ display: 'flex', gap: '4px', justifyContent: 'center' }}>
        {langBtn('he', 'עברית')}{langBtn('en', 'EN')}{langBtn('EN', 'CAPS')}{langBtn('sym', '!@#')}
      </div>
      {/* Key rows */}
      {rows.map((row, ri) => (
        <div key={ri} style={{ display: 'flex', gap: '4px', justifyContent: 'center' }}>
          {row.map(k => (
            <button key={k} style={key as any} onPointerDown={e => { e.preventDefault(); onType(k); }}>{k}</button>
          ))}
          {ri === 0 && (
            <button style={{ ...key as any, minWidth: 52, background: '#7f1d1d', border: '1px solid #991b1b', fontSize: '16px' }}
              onPointerDown={e => { e.preventDefault(); onBackspace(); }}>⌫</button>
          )}
        </div>
      ))}
      {/* Bottom row */}
      <div style={{ display: 'flex', gap: '4px', justifyContent: 'center' }}>
        <button style={{ ...key as any, minWidth: 200, fontSize: '12px', color: '#94a3b8' }} onPointerDown={e => { e.preventDefault(); onType(' '); }}>space / מרווח</button>
        <button style={{ ...key as any, minWidth: 60, background: '#1d4ed8', border: '1px solid #2563eb', fontSize: '13px' }} onPointerDown={e => { e.preventDefault(); onEnter(); }}>↵</button>
      </div>
    </div>,
    document.body
  );
};
// --- קנבס כתב יד לטבלה ---
const TableHandwritingCanvas = ({ existing, onConfirm, onCancel, showText = true }: { existing: string; onConfirm: (note: string) => void; onCancel: () => void; showText?: boolean }) => {
  const parsed = parseNoteValue(existing);
  const [textValue, setTextValue] = useState(parsed.text);
  const [showOSK, setShowOSK] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const hwRef = useRef<HTMLCanvasElement>(null);
  const isDrawingRef = useRef(false);
  const lastRef = useRef<{x:number;y:number}|null>(null);
  const insertAtCursor = (char: string) => {
    const el = textareaRef.current;
    if (!el) { setTextValue(v => v + char); return; }
    const s = el.selectionStart ?? el.value.length;
    const e2 = el.selectionEnd ?? s;
    const next = el.value.slice(0, s) + char + el.value.slice(e2);
    setTextValue(next);
    requestAnimationFrame(() => { el.focus(); el.setSelectionRange(s + char.length, s + char.length); });
  };
  const oskBackspace = () => {
    const el = textareaRef.current;
    if (!el) { setTextValue(v => v.slice(0, -1)); return; }
    const s = el.selectionStart ?? el.value.length;
    const e2 = el.selectionEnd ?? s;
    const next = s === e2 ? el.value.slice(0, Math.max(0, s - 1)) + el.value.slice(e2) : el.value.slice(0, s) + el.value.slice(e2);
    const ns = s === e2 ? Math.max(0, s - 1) : s;
    setTextValue(next);
    requestAnimationFrame(() => { el.focus(); el.setSelectionRange(ns, ns); });
  };

  // Load existing handwriting onto canvas
  useEffect(() => {
    const canvas = hwRef.current;
    const ctx = canvas?.getContext('2d');
    if (!ctx || !canvas) return;
    ctx.fillStyle = '#fff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    if (parsed.hw) {
      const img = new Image();
      img.onload = () => ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
      img.src = parsed.hw;
    }
  }, []);

  const getXY = (e: any) => {
    const canvas = hwRef.current!;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const src = e.touches ? e.touches[0] : e;
    return { x: (src.clientX - rect.left) * scaleX, y: (src.clientY - rect.top) * scaleY };
  };
  const onDown = (e: any) => {
    e.preventDefault();
    e.stopPropagation();
    isDrawingRef.current = true;
    const {x,y} = getXY(e);
    lastRef.current = {x,y};
  };
  const onMove = (e: any) => {
    if (!isDrawingRef.current || !lastRef.current) return;
    e.preventDefault();
    const {x,y} = getXY(e);
    const ctx = hwRef.current?.getContext('2d');
    if (ctx) {
      ctx.lineWidth = 3;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.strokeStyle = '#1e293b';
      ctx.beginPath();
      ctx.moveTo(lastRef.current.x, lastRef.current.y);
      ctx.lineTo(x, y);
      ctx.stroke();
    }
    lastRef.current = {x,y};
  };
  const onUp = () => { isDrawingRef.current = false; lastRef.current = null; };
  const clearHw = () => {
    const canvas = hwRef.current;
    const ctx = canvas?.getContext('2d');
    if (ctx && canvas) { ctx.fillStyle='#fff'; ctx.fillRect(0,0,canvas.width,canvas.height); }
  };
  const confirm = () => {
    const hwData = hwRef.current?.toDataURL('image/png') || '';
    // Check if canvas has actual drawing (not just white fill) by comparing to a blank canvas
    const blank = document.createElement('canvas');
    blank.width = hwRef.current?.width || 480;
    blank.height = hwRef.current?.height || 200;
    const bctx = blank.getContext('2d');
    if (bctx) { bctx.fillStyle = '#fff'; bctx.fillRect(0,0,blank.width,blank.height); }
    const hasDrawing = hwData !== blank.toDataURL('image/png');
    onConfirm(serializeNoteValue(textValue, hasDrawing ? hwData : ''));
  };

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.7)', zIndex:9999, display:'flex', alignItems:'center', justifyContent:'center' }} onClick={e => e.stopPropagation()}>
      <div style={{ background:'white', borderRadius:'12px', padding:'16px', display:'flex', flexDirection:'column', gap:'10px', width:'min(92vw, 520px)', maxHeight:'90vh', overflowY:'auto' }}>
        <div style={{ fontWeight:'bold', fontSize:'16px', direction:'rtl', textAlign:'center' }}>עריכת הערה</div>

        {/* Text input — shown only when showText is true */}
        {showText && (
          <div style={{ direction:'rtl' }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'4px' }}>
              <span style={{ fontSize:'12px', color:'#64748b', fontWeight:'600' }}>⌨️ טקסט</span>
              <button
                onPointerDown={e => { e.preventDefault(); setShowOSK(v => !v); }}
                style={{ padding:'4px 10px', background: showOSK ? '#2563eb' : '#475569', color:'white', border:'none', borderRadius:'5px', cursor:'pointer', fontSize:'12px', fontWeight:'bold' }}
              >⌨ מקלדת וירטואלית</button>
            </div>
            <textarea
              ref={textareaRef}
              value={textValue}
              onChange={e => setTextValue(e.target.value)}
              dir="rtl"
              rows={3}
              style={{ width:'100%', padding:'10px', fontSize:'16px', border:'2px solid #cbd5e1', borderRadius:'8px', resize:'vertical', fontFamily:'inherit', boxSizing:'border-box', outline:'none' }}
              placeholder="כתוב כאן..."
              autoFocus
              onFocus={e => e.currentTarget.setSelectionRange(e.currentTarget.value.length, e.currentTarget.value.length)}
            />
            {showOSK && (
              <OnScreenKeyboard
                onType={insertAtCursor}
                onBackspace={oskBackspace}
                onEnter={() => insertAtCursor('\n')}
                onClose={() => setShowOSK(false)}
              />
            )}
          </div>
        )}

        {/* Handwriting canvas — always visible */}
        <div style={{ direction:'rtl' }}>
          <div style={{ fontSize:'12px', color:'#64748b', marginBottom:'4px', fontWeight:'600' }}>🖊️ כתב יד</div>
          <canvas
            ref={hwRef}
            width={480}
            height={200}
            style={{ border:'2px solid #cbd5e1', borderRadius:'8px', cursor:'crosshair', touchAction:'none', background:'#fff', display:'block', width:'100%' }}
            onPointerDown={onDown} onPointerMove={onMove} onPointerUp={onUp} onPointerLeave={onUp} onPointerCancel={onUp}
            onTouchStart={onDown} onTouchMove={onMove} onTouchEnd={onUp}
          />
        </div>

        {/* Action buttons */}
        <div style={{ display:'flex', gap:'8px', direction:'rtl', flexWrap:'wrap', justifyContent:'center' }}>
          <button onClick={confirm} style={{ padding:'9px 24px', background:'#2563eb', color:'white', border:'none', borderRadius:'6px', cursor:'pointer', fontWeight:'bold', fontSize:'15px' }}>קבל</button>
          <button onClick={clearHw} style={{ padding:'9px 16px', background:'#64748b', color:'white', border:'none', borderRadius:'6px', cursor:'pointer', fontSize:'14px' }}>נקה ציור</button>
          <button onClick={onCancel} style={{ padding:'9px 16px', background:'#ef4444', color:'white', border:'none', borderRadius:'6px', cursor:'pointer', fontSize:'14px' }}>ביטול</button>
        </div>
      </div>
    </div>
  );
};

// --- BlockMiniView: narrow side-panel block+altitude view ---
const BlockMiniView = ({ relevantBlocks, strips, lightMode, onUpdateStripAlt }: {
  relevantBlocks: any[]; strips: any[]; lightMode: boolean;
  onUpdateStripAlt?: (stripId: string, newAlt: string) => void;
}) => {
  const containerRef = React.useRef<HTMLDivElement>(null);
  const [containerH, setContainerH] = React.useState(400);
  const dragRef = React.useRef<{ stripId: string; startY: number; startAltFt: number } | null>(null);
  const [dragAlt, setDragAlt] = React.useState<{ id: string; altFt: number } | null>(null);

  React.useEffect(() => {
    const el = containerRef.current; if (!el) return;
    const ro = new ResizeObserver(ents => { for (const e of ents) setContainerH(e.contentRect.height); });
    ro.observe(el); return () => ro.disconnect();
  }, []);

  const minAltFt = relevantBlocks.length ? Math.min(...relevantBlocks.map((b: any) => b.alt_from)) * 100 : 10000;
  const maxAltFt = relevantBlocks.length ? Math.max(...relevantBlocks.map((b: any) => b.alt_to)) * 100 : 60000;
  const pad = 5000;
  const altMin = minAltFt - pad;
  const altMax = maxAltFt + pad;
  const altRange = altMax - altMin || 1;

  const toY = (ft: number) => ((altMax - ft) / altRange) * containerH;
  const fromY = (y: number) => altMax - (y / containerH) * altRange;

  React.useEffect(() => {
    if (!dragRef.current) return;
    const onMove = (e: PointerEvent) => {
      if (!dragRef.current || !containerRef.current) return;
      const rect = containerRef.current.getBoundingClientRect();
      const relY = e.clientY - rect.top;
      const newAltFt = Math.round(fromY(relY) / 500) * 500;
      setDragAlt({ id: dragRef.current.stripId, altFt: newAltFt });
    };
    const onUp = (e: PointerEvent) => {
      if (!dragRef.current || !containerRef.current) return;
      const rect = containerRef.current.getBoundingClientRect();
      const relY = e.clientY - rect.top;
      const newAltFt = Math.round(fromY(relY) / 500) * 500;
      const fl = Math.round(newAltFt / 100);
      if (onUpdateStripAlt) onUpdateStripAlt(dragRef.current.stripId, String(fl));
      dragRef.current = null;
      setDragAlt(null);
    };
    window.addEventListener('pointermove', onMove);
    window.addEventListener('pointerup', onUp);
    return () => { window.removeEventListener('pointermove', onMove); window.removeEventListener('pointerup', onUp); };
  }, [dragRef.current !== null, altMin, altMax, containerH]);

  const TICK_STEP = 5000;
  const ticks: number[] = [];
  for (let a = Math.ceil(altMin / TICK_STEP) * TICK_STEP; a <= altMax; a += TICK_STEP) ticks.push(a);

  const CHIP_H = 28;
  const placedStrips = strips.map((s: any) => {
    const ft = parseAltToFeet(String(s.alt || ''));
    return { ...s, altFt: ft };
  }).filter((s: any) => s.altFt !== null && s.altFt >= altMin - 1000 && s.altFt <= altMax + 1000);

  return (
    <div ref={containerRef} style={{ width: '100%', height: '100%', position: 'relative', overflow: 'hidden', cursor: dragRef.current ? 'ns-resize' : 'default' }}>
      {/* Block bands */}
      {relevantBlocks.map((b: any) => {
        const y1 = toY(b.alt_to * 100);
        const y2 = toY(b.alt_from * 100);
        if (y2 <= 0 && y1 <= 0) return null;
        if (y1 >= containerH && y2 >= containerH) return null;
        return (
          <div key={b.id} style={{
            position: 'absolute', left: 0, right: 0,
            top: Math.max(0, y1), height: Math.max(2, Math.min(containerH, y2) - Math.max(0, y1)),
            background: (b.color || '#6366f1') + '33',
            borderTop: `2px solid ${b.color || '#6366f1'}cc`,
            borderBottom: `2px solid ${b.color || '#6366f1'}cc`,
            pointerEvents: 'none',
          }}>
            {b.mission && (
              <span style={{ position: 'absolute', top: 2, right: 2, fontSize: '7px', color: b.color || '#a5b4fc', fontWeight: 'bold', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', maxWidth: '80%' }}>{b.mission}</span>
            )}
          </div>
        );
      })}
      {/* Altitude ticks */}
      {ticks.map(a => {
        const y = toY(a);
        if (y < 0 || y > containerH) return null;
        return (
          <div key={a} style={{ position: 'absolute', left: 0, right: 0, top: y, height: 1, background: lightMode ? '#e2e8f0' : '#334155', pointerEvents: 'none' }}>
            <span style={{ position: 'absolute', right: 2, top: -8, fontSize: '7px', color: lightMode ? '#94a3b8' : '#475569', whiteSpace: 'nowrap' }}>FL{a / 100}</span>
          </div>
        );
      })}
      {/* Strip chips — draggable */}
      {placedStrips.map((s: any) => {
        const isDragging = dragAlt?.id === s.id;
        const displayAltFt = isDragging ? dragAlt!.altFt : s.altFt!;
        const y = toY(displayAltFt);
        const fl = Math.round(displayAltFt / 100);
        return (
          <div
            key={s.id}
            onPointerDown={onUpdateStripAlt ? (e) => {
              e.preventDefault(); e.stopPropagation();
              (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
              dragRef.current = { stripId: s.id, startY: e.clientY, startAltFt: s.altFt! };
              setDragAlt({ id: s.id, altFt: s.altFt! });
            } : undefined}
            style={{
              position: 'absolute', left: 2, right: 2,
              top: y - CHIP_H / 2, height: CHIP_H,
              borderRadius: '3px',
              background: isDragging ? (lightMode ? '#1d4ed8' : '#3b82f6') : (lightMode ? '#1e293b' : '#334155'),
              border: `1px solid ${isDragging ? '#60a5fa' : (lightMode ? '#475569' : '#64748b')}`,
              display: 'flex', flexDirection: 'column', alignItems: 'stretch', justifyContent: 'center',
              color: lightMode ? '#f8fafc' : '#f1f5f9',
              overflow: 'hidden',
              cursor: onUpdateStripAlt ? 'ns-resize' : 'default',
              zIndex: isDragging ? 10 : 2,
              userSelect: 'none', touchAction: 'none',
              padding: '1px 3px',
              opacity: isDragging ? 0.85 : 1,
            }}
            title={`${s.callSign || ''} | FL${fl}${s.plane_type ? ' | ' + s.plane_type : ''}`}
          >
            <div style={{ fontSize: '9px', fontWeight: 'bold', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', lineHeight: 1.2 }}>
              {s.callSign || '—'}
            </div>
            <div style={{ fontSize: '8px', color: lightMode ? '#93c5fd' : '#94a3b8', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', lineHeight: 1.2 }}>
              FL{fl}{s.plane_type ? ` · ${s.plane_type}` : ''}
            </div>
          </div>
        );
      })}
    </div>
  );
};

// --- תצוגת מגרש (GROUND) ---
const AIR_DEFENSE_STATUSES: { label: string; color: string }[] = [
  { label: 'ראייה',              color: '#22c55e' },
  { label: 'התראה',              color: '#eab308' },
  { label: 'מכשירים',            color: '#f97316' },
  { label: 'מכשירים להקפה',     color: '#f97316' },
  { label: 'סגור',               color: '#ef4444' },
  { label: 'פתוח להזנקות',      color: '#ef4444' },
];

const GROUND_STATUSES = [
  { key: 'none',    label: 'Pre-Call — טרם קרא',      color: '#64748b', bg: '#0f172a', dot: '#475569', flash: false },
  { key: 'taxi',    label: 'Taxi — קרא להסעה',        color: '#86efac', bg: '#14532d', dot: '#22c55e', flash: false },
  { key: 'lineup',  label: 'Line-up — להתיישרות',    color: '#60a5fa', bg: '#1e3a5f', dot: '#3b82f6', flash: false },
  { key: 'takeoff', label: 'Take-off — המראה',        color: '#fca5a5', bg: '#450a0a', dot: '#ef4444', flash: true  },
] as const;

type GroundStatusKey = 'none' | 'taxi' | 'lineup' | 'takeoff';

const GROUND_POINT_MARKERS = [
  { key: 'circle',   label: '⬤ עיגול' },
  { key: 'square',   label: '■ ריבוע' },
  { key: 'diamond',  label: '◆ מעוין' },
  { key: 'triangle', label: '▲ משולש' },
  { key: 'cross',    label: '✚ צלב' },
  { key: 'star',     label: '★ כוכב' },
  { key: 'runway',   label: '▬ מסלול' },
  { key: 'parking',  label: 'P חניה' },
  { key: 'hangar',   label: '⌂ אנגר' },
] as const;

type GroundMarkerKey = typeof GROUND_POINT_MARKERS[number]['key'];

const GroundMarkerSVG = ({ marker, color, size = 16, opacity = 1 }: { marker: string; color: string; size?: number; opacity?: number }) => {
  const s = size;
  const h = s / 2;
  const style: React.CSSProperties = { display: 'block', opacity };
  switch (marker) {
    case 'square':
      return <svg width={s} height={s} style={style}><rect x={1} y={1} width={s-2} height={s-2} fill={color} rx={2} /></svg>;
    case 'diamond':
      return <svg width={s} height={s} style={style}><polygon points={`${h},1 ${s-1},${h} ${h},${s-1} 1,${h}`} fill={color} /></svg>;
    case 'triangle':
      return <svg width={s} height={s} style={style}><polygon points={`${h},1 ${s-1},${s-1} 1,${s-1}`} fill={color} /></svg>;
    case 'cross':
      return <svg width={s} height={s} style={style}><rect x={h-2} y={1} width={4} height={s-2} fill={color} rx={1} /><rect x={1} y={h-2} width={s-2} height={4} fill={color} rx={1} /></svg>;
    case 'star':
      return <svg width={s} height={s} style={style}><text x={h} y={s-2} textAnchor="middle" fontSize={s-2} fill={color}>★</text></svg>;
    case 'runway':
      return <svg width={s} height={s} style={style}><rect x={1} y={h-2} width={s-2} height={4} fill={color} rx={2} /></svg>;
    case 'parking':
      return <svg width={s} height={s} style={style}><rect x={1} y={1} width={s-2} height={s-2} fill={color} rx={3} /><text x={h} y={s-3} textAnchor="middle" fontSize={s-5} fill="white" fontWeight="bold">P</text></svg>;
    case 'hangar':
      return <svg width={s} height={s} style={style}><text x={h} y={s-2} textAnchor="middle" fontSize={s-2} fill={color}>⌂</text></svg>;
    default: // circle
      return <svg width={s} height={s} style={style}><circle cx={h} cy={h} r={h-1} fill={color} /></svg>;
  }
};

